render_brand_logo_asset_override()

components.html(
    """
    <script>
    const parentDoc = window.parent && window.parent.document;
    if (parentDoc && !parentDoc.__errorsweepGridScrollBlur) {
      parentDoc.__errorsweepGridScrollBlur = true;
      const isGridOverlay = (el) => {
        if (!el) return false;
        const tag = (el.tagName || "").toLowerCase();
        if (tag !== "textarea" && tag !== "input") return false;
        const cls = String(el.className || "");
        const aria = String(el.getAttribute("aria-label") || "");
        return cls.includes("gdg") || cls.includes("dvn") || aria.includes("cell") ||
          !!el.closest('[data-testid="stDataFrame"],[data-testid="stDataEditor"]');
      };
      const overlaySelector = [
        'textarea.gdg-input', 'input.gdg-input',
        'textarea[class*="gdg"]', 'input[class*="gdg"]',
        'textarea[class*="dvn"]', 'input[class*="dvn"]',
        '[data-testid="stDataFrame"] textarea', '[data-testid="stDataFrame"] input',
        '[data-testid="stDataEditor"] textarea', '[data-testid="stDataEditor"] input'
      ].join(',');
      const rectsOverlap = (a, b) => {
        return a.right > b.left + 2 && a.left < b.right - 2 && a.bottom > b.top + 2 && a.top < b.bottom - 2;
      };
      const overlayInsideGrid = (el) => {
        const rect = el.getBoundingClientRect();
        if (!rect || rect.width < 2 || rect.height < 2) return true;
        const grids = Array.from(parentDoc.querySelectorAll('[data-testid="stDataFrame"],[data-testid="stDataEditor"]'));
        return grids.some((grid) => rectsOverlap(rect, grid.getBoundingClientRect()));
      };
      const cleanupEscapedGridOverlays = () => {
        parentDoc.querySelectorAll(overlaySelector).forEach((el) => {
          if (!isGridOverlay(el)) return;
          if (!overlayInsideGrid(el)) {
            el.classList.add("es-grid-overlay-escaped");
            if (parentDoc.activeElement === el) el.blur();
          } else if (!parentDoc.body.classList.contains("es-grid-scroll-active")) {
            el.classList.remove("es-grid-overlay-escaped");
          }
        });
      };
      const focusGridOverlayAtPoint = (x, y) => {
        const overlays = Array.from(parentDoc.querySelectorAll(overlaySelector))
          .filter((el) => isGridOverlay(el) && overlayInsideGrid(el));
        const containing = overlays.find((el) => {
          const rect = el.getBoundingClientRect();
          return x >= rect.left - 2 && x <= rect.right + 2 && y >= rect.top - 2 && y <= rect.bottom + 2;
        });
        const target = containing || overlays.find((el) => {
          const rect = el.getBoundingClientRect();
          return rect.width > 8 && rect.height > 8;
        });
        if (!target) return;
        target.classList.remove("es-grid-overlay-escaped");
        target.style.opacity = "1";
        target.style.pointerEvents = "auto";
        target.focus({ preventScroll: true });
        if (typeof target.setSelectionRange === "function") {
          const end = String(target.value || "").length;
          target.setSelectionRange(end, end);
        }
      };
      let scrollTimer = null;
      const hideGridOverlayDuringScroll = () => {
        parentDoc.body.classList.add("es-grid-scroll-active");
        const el = parentDoc.activeElement;
        if (isGridOverlay(el)) el.blur();
        cleanupEscapedGridOverlays();
        window.clearTimeout(scrollTimer);
        scrollTimer = window.setTimeout(() => {
          parentDoc.body.classList.remove("es-grid-scroll-active");
          cleanupEscapedGridOverlays();
        }, 220);
      };
      parentDoc.addEventListener("scroll", hideGridOverlayDuringScroll, true);
      parentDoc.addEventListener("wheel", hideGridOverlayDuringScroll, true);
      parentDoc.addEventListener("touchmove", hideGridOverlayDuringScroll, true);
      window.setInterval(cleanupEscapedGridOverlays, 350);
      parentDoc.addEventListener("click", (event) => {
        if (parentDoc.__errorsweepSyntheticGridEdit) return;
        const target = event.target;
        if (!target || !target.closest || !target.closest('[data-testid="stDataEditor"]')) return;
        if (target.closest('input, textarea, button, select, [role="button"]')) return;
        const now = Date.now();
        if (parentDoc.__errorsweepLastGridClick && now - parentDoc.__errorsweepLastGridClick < 180) return;
        parentDoc.__errorsweepLastGridClick = now;
        window.setTimeout(() => {
          if (parentDoc.body.classList.contains("es-grid-scroll-active")) return;
          const editTarget = parentDoc.elementFromPoint(event.clientX, event.clientY) || target;
          parentDoc.__errorsweepSyntheticGridEdit = true;
          const fire = (type, detail) => {
            editTarget.dispatchEvent(new MouseEvent(type, {
              bubbles: true,
              cancelable: true,
              view: parentDoc.defaultView || window,
              clientX: event.clientX,
              clientY: event.clientY,
              screenX: event.screenX,
              screenY: event.screenY,
              button: event.button,
              buttons: event.buttons,
              ctrlKey: event.ctrlKey,
              shiftKey: event.shiftKey,
              altKey: event.altKey,
              metaKey: event.metaKey,
              detail: detail
            }));
          };
          fire("mousedown", 2);
          fire("mouseup", 2);
          fire("click", 2);
          const dbl = new MouseEvent("dblclick", {
            bubbles: true,
            cancelable: true,
            view: parentDoc.defaultView || window,
            clientX: event.clientX,
            clientY: event.clientY,
            screenX: event.screenX,
            screenY: event.screenY,
            button: event.button,
            buttons: event.buttons,
            ctrlKey: event.ctrlKey,
            shiftKey: event.shiftKey,
            altKey: event.altKey,
            metaKey: event.metaKey,
            detail: 2
          });
          editTarget.dispatchEvent(dbl);
          window.setTimeout(() => focusGridOverlayAtPoint(event.clientX, event.clientY), 35);
          window.setTimeout(() => { parentDoc.__errorsweepSyntheticGridEdit = false; }, 100);
        }, 45);
      }, true);
    }
    </script>
    """,
    height=0,
)


# ==========================================================
# Session and config helpers
# ==========================================================

def secret(name: str, default: str = "") -> str:
    value = runtime_env(name, "")
    if value:
        return value
    try:
        value = st.secrets.get(name)
        if value:
            return value
        alias = cognisweep_env_alias(name)
        if alias:
            value = st.secrets.get(alias)
            if value:
                return value
    except Exception as exc:
        LOGGER.debug("Unable to read secret %s: %s", name, exc)
    return default


def is_production_mode() -> bool:
    mode = secret("ERRORSWEEP_ENV", secret("ENVIRONMENT", secret("APP_ENV", ""))).strip().lower()
    return mode in {"prod", "production"}


FEATURE_FLAG_META = {
    "main_api_translation": ("AI draft translation", "Allow Pro/QA workflows to call customer BYO AI translation routes."),
    "pro_human_review": ("Translation Studio Human Review", "Allow Translation Studio runs to open the Human Review workspace."),
    "scorecards": ("Scorecards", "Allow translator/reviewer scorecard generation workflows."),
    "subtitle_editor": ("Subtitle / Transcription Editor", "Allow subtitle and transcription workspace tools."),
    "public_registration": ("Public registration", "Allow unauthenticated users to create a trial workspace."),
    "demo_access": ("Demo access", "Allow unauthenticated demo workspace sign-in on local builds."),
    "billing_collection": ("Billing collection", "Allow checkout/mandate intents from the Billing page."),
}


def feature_flag_defaults() -> Dict[str, bool]:
    local_mode = not is_production_mode()
    return {
        "main_api_translation": True,
        "pro_human_review": True,
        "scorecards": True,
        "subtitle_editor": True,
        "public_registration": True,
        "demo_access": local_mode,
        "billing_collection": local_mode,
    }


def parse_bool_flag(value: Any, default: bool = False) -> bool:
    if value in (None, ""):
        return default
    if isinstance(value, bool):
        return value
    return safe_text(value).lower() in {"1", "true", "yes", "on", "enabled"}


def feature_flag(key: str, default: Optional[bool] = None) -> bool:
    defaults = feature_flag_defaults()
    fallback = defaults.get(key, bool(default))
    env_key = f"ERRORSWEEP_FEATURE_{key.upper()}"
    configured = secret(env_key, "")
    if configured != "":
        return parse_bool_flag(configured, fallback)
    flags = st.session_state.setdefault("feature_flags", defaults.copy())
    if key not in flags:
        flags[key] = fallback
    return parse_bool_flag(flags.get(key), fallback)


def set_feature_flags(updates: Dict[str, bool]) -> List[str]:
    flags = st.session_state.setdefault("feature_flags", feature_flag_defaults().copy())
    changed: List[str] = []
    for key, value in updates.items():
        normalized = bool(value)
        if bool(flags.get(key, feature_flag_defaults().get(key, False))) != normalized:
            flags[key] = normalized
            changed.append(key)
    if changed:
        try:
            upsert_platform_setting(
                "feature_flags",
                {key: bool(flags.get(key, feature_flag_defaults().get(key, False))) for key in FEATURE_FLAG_META},
                metadata={"changed": changed, "source": "Platform Settings"},
            )
        except Exception as exc:
            LOGGER.warning("Unable to persist feature flags: %s", exc)
        add_audit(
            "Feature flags updated",
            ", ".join(f"{FEATURE_FLAG_META.get(key, (key, ''))[0]}={flags.get(key)}" for key in changed),
        )
    return changed


def retention_policy_defaults() -> Dict[str, int]:
    return dict(RETENTION_POLICY_DEFAULTS)


def session_secret() -> str:
    value = secret("ERRORSWEEP_SESSION_SECRET", DEFAULT_SESSION_SECRET)
    if is_production_mode() and value == DEFAULT_SESSION_SECRET:
        raise RuntimeError("ERRORSWEEP_SESSION_SECRET must be configured in production.")
    return value


def b64url(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).decode("utf-8").rstrip("=")


def hash_password(password: str, salt: Optional[str] = None, iterations: int = PASSWORD_HASH_ITERATIONS) -> str:
    salt = salt or b64url(os.urandom(16))
    digest = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt.encode("utf-8"), iterations)
    return f"pbkdf2_sha256${iterations}${salt}${b64url(digest)}"


def verify_password(password: str, stored_hash: str) -> bool:
    parts = str(stored_hash or "").split("$")
    if len(parts) != 4 or parts[0] != "pbkdf2_sha256":
        return False
    try:
        iterations = int(parts[1])
        digest = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), parts[2].encode("utf-8"), iterations)
        return hmac.compare_digest(b64url(digest), parts[3])
    except Exception as exc:
        LOGGER.warning("Password hash verification failed: %s", exc)
        return False


def verify_login_password(password: str, hash_secret_name: str, legacy_secret_name: str) -> bool:
    stored_hash = secret(hash_secret_name, "")
    if stored_hash:
        return verify_password(password, stored_hash)

    legacy_password = secret(legacy_secret_name, "")
    if not legacy_password:
        return False
    if is_production_mode():
        LOGGER.error("%s is plaintext and is not accepted in production. Configure %s.", legacy_secret_name, hash_secret_name)
        return False
    LOGGER.warning("%s is plaintext and should be replaced with %s.", legacy_secret_name, hash_secret_name)
    return hmac.compare_digest(password, legacy_password)


def early_safe_text(value: Any) -> str:
    if value is None:
        return ""
    try:
        return str(value).replace("\u00A0", " ").strip()
    except Exception:
        return ""


def configured_owner_username(local_default: bool = False) -> str:
    default = "owner@cognisweep.local" if local_default and not is_production_mode() else ""
    return early_safe_text(secret("ERRORSWEEP_OWNER_USERNAME", default)).lower()


def configured_owner_password_hash() -> str:
    return early_safe_text(secret("ERRORSWEEP_OWNER_PASSWORD_HASH", ""))


def unlimited_access_email() -> str:
    return early_safe_text(secret(UNLIMITED_ACCESS_EMAIL_SECRET, configured_owner_username())).lower()


def unlimited_access_password_hash() -> str:
    return early_safe_text(secret(UNLIMITED_ACCESS_PASSWORD_HASH_SECRET, configured_owner_password_hash()))


def unlimited_access_configured() -> bool:
    return bool(unlimited_access_email() and unlimited_access_password_hash().startswith("pbkdf2_sha256$"))


def password_configured(hash_secret_name: str, legacy_secret_name: str) -> bool:
    return bool(secret(hash_secret_name, "") or secret(legacy_secret_name, ""))


def trim_session_list(key: str, limit: int = SESSION_HISTORY_LIMIT) -> None:
    items = st.session_state.get(key)
    if isinstance(items, list) and len(items) > limit:
        del items[limit:]


def trim_session_collections() -> None:
    for key, limit in SESSION_COLLECTION_LIMITS.items():
        trim_session_list(key, limit)


def saas_cache_generation() -> int:
    try:
        return int(st.session_state.get(SAAS_CACHE_GENERATION_KEY, 0) or 0)
    except (TypeError, ValueError):
        st.session_state[SAAS_CACHE_GENERATION_KEY] = 0
        return 0


@st.cache_data(ttl=SAAS_CACHE_TTL_SECONDS, show_spinner=False)
def _cached_fetch_saas_records(
    collection: str,
    workspace: str,
    user_email: str,
    include_all_workspaces: bool,
    platform_scope_reason: str,
    limit: int,
    cache_generation: int,
) -> Tuple[Dict[str, Any], ...]:
    if fetch_saas_records is None:
        return tuple()
    rows = fetch_saas_records(
        collection,
        workspace=workspace,
        user_email=user_email,
        include_all_workspaces=include_all_workspaces,
        platform_scope_reason=platform_scope_reason,
        limit=limit,
    )
    return tuple(dict(row) for row in rows if isinstance(row, dict))


def clear_saas_record_cache() -> None:
    st.session_state[SAAS_CACHE_GENERATION_KEY] = saas_cache_generation() + 1
    try:
        _cached_fetch_saas_records.clear()
    except (AttributeError, RuntimeError) as exc:
        LOGGER.debug("Unable to clear SaaS read cache directly: %s", exc)


def persist_saas_record(collection: str, record: Dict[str, Any]) -> Dict[str, Any]:
    if save_saas_record is None:
        return record
    try:
        persisted = save_saas_record(collection, record, user=current_user() or {})
    except ValueError as exc:
        LOGGER.error("Rejected unsupported SaaS record %s: %s", collection, exc)
        return record
    except requests.RequestException as exc:
        LOGGER.error("Network error while persisting SaaS record %s: %s", collection, exc)
        return record
    clear_saas_record_cache()
    return persisted


def load_saas_records(
    collection: str,
    workspace: str = "",
    include_all_workspaces: bool = False,
    limit: int = 500,
    user_email: str = "",
    platform_scope_reason: str = "",
) -> List[Dict[str, Any]]:
    if fetch_saas_records is None:
        return []
    try:
        if collection in SAAS_CACHEABLE_COLLECTIONS:
            return [
                dict(row)
                for row in _cached_fetch_saas_records(
                    collection,
                    workspace,
                    user_email,
                    include_all_workspaces,
                    platform_scope_reason,
                    limit,
                    saas_cache_generation(),
                )
            ]
        return fetch_saas_records(
            collection,
            workspace=workspace,
            user_email=user_email,
            include_all_workspaces=include_all_workspaces,
            platform_scope_reason=platform_scope_reason,
            limit=limit,
        )
    except ValueError as exc:
        LOGGER.error("Rejected unsupported SaaS record load %s: %s", collection, exc)
        return []
    except requests.RequestException as exc:
        LOGGER.error("Network error while loading SaaS records %s: %s", collection, exc)
        return []


def persistence_read_scope(user: Optional[Dict[str, Any]] = None, platform_scope_reason: str = "") -> Dict[str, Any]:
    candidate = user if user is not None else (current_user() or {})
    if is_platform_owner_identity(candidate):
        return {"include_all_workspaces": True, "platform_scope_reason": platform_scope_reason or "platform_owner_read"}
    return {"workspace": safe_text(candidate.get("workspace"))}


def all_user_records(limit: int = 1000) -> List[Dict[str, Any]]:
    records: List[Dict[str, Any]] = []
    seen: Set[str] = set()
    for source_rows in (
        load_saas_records("users", include_all_workspaces=True, platform_scope_reason="login_user_lookup", limit=limit),
        st.session_state.get("users", []),
    ):
        for row in source_rows or []:
            if not isinstance(row, dict):
                continue
            key = safe_text(row.get("email")).lower() or safe_text(row.get("id")).lower()
            if not key or key in seen:
                continue
            records.append(dict(row))
            seen.add(key)
    return records


def workspace_user_records(workspace: str, limit: int = 1000) -> List[Dict[str, Any]]:
    workspace_key = safe_text(workspace).strip()
    if not workspace_key or workspace_key.lower() == "platform":
        return []
    records: List[Dict[str, Any]] = []
    seen: Set[str] = set()
    for source_rows in (
        load_saas_records("users", workspace=workspace_key, limit=limit),
        st.session_state.get("users", []),
    ):
        for row in source_rows or []:
            if not isinstance(row, dict):
                continue
            if safe_text(row.get("workspace")).strip() != workspace_key:
                continue
            key = safe_text(row.get("id")).lower() or f"{safe_text(row.get('email')).lower()}::{workspace_key.lower()}"
            if not key or key in seen:
                continue
            records.append(dict(row))
            seen.add(key)
    return records


def team_workspace_options(user: Optional[Dict[str, Any]] = None) -> List[str]:
    candidate = user if user is not None else (current_user() or {})
    current_workspace = safe_text(candidate.get("workspace") or "Demo Workspace").strip()
    options: List[str] = []

    if has_permission("platform.workspaces", candidate) or has_permission("platform.users", candidate):
        for item in st.session_state.get("workspaces", []):
            name = safe_text(item.get("workspace")).strip()
            if name and name.lower() != "platform":
                options.append(name)
        for item in all_user_records(limit=2000):
            name = safe_text(item.get("workspace")).strip()
            if name and name.lower() != "platform":
                options.append(name)
    elif current_workspace and current_workspace.lower() != "platform":
        options.append(current_workspace)

    return list(dict.fromkeys(options))


def default_team_account_type(workspace: str, user: Optional[Dict[str, Any]] = None) -> str:
    for item in workspace_user_records(workspace):
        account_type = account_type_for_user(item)
        if account_type in ACCOUNT_TYPE_LABELS:
            return account_type
    current_account_type = account_type_for_user(user)
    return current_account_type if current_account_type in ACCOUNT_TYPE_LABELS else "company"


def find_user_by_email(email: str) -> Optional[Dict[str, Any]]:
    email_key = safe_text(email).strip().lower()
    if not email_key:
        return None
    for row in all_user_records():
        if safe_text(row.get("email")).strip().lower() == email_key:
            return dict(row)
    return None


def safe_user_session_record(record: Dict[str, Any]) -> Dict[str, Any]:
    excluded = {"password_hash"}
    return {key: value for key, value in (record or {}).items() if key not in excluded}


def signup_role_for_profile(primary_role: str, profile_type: str) -> str:
    role = safe_text(primary_role)
    profile = safe_text(profile_type).lower()
    if "client" in profile:
        return "Workspace Owner"
    if role in {"Translator", "Subtitler", "Transcriptionist", "Localization Engineer"}:
        return "Translator"
    if role in {"Reviewer", "LQA Specialist"}:
        return "Reviewer"
    if role == "Project Manager":
        return "Project Manager"
    return "User"


def talent_search_text(record: Dict[str, Any]) -> str:
    fields = [
        "full_name",
        "email",
        "phone",
        "city",
        "country",
        "profile_type",
        "primary_role",
        "services",
        "languages",
        "domains",
        "tools",
        "certifications",
        "availability",
        "work_preference",
        "bio",
        "workspace",
    ]
    return " ".join(safe_text(record.get(field)) for field in fields if safe_text(record.get(field))).strip()


def talent_display_record(record: Dict[str, Any]) -> Dict[str, Any]:
    return {
        "Name": safe_text(record.get("full_name") or record.get("email")),
        "Email": safe_text(record.get("email")),
        "Phone": safe_text(record.get("phone")),
        "Profile": safe_text(record.get("profile_type")),
        "Primary role": safe_text(record.get("primary_role") or record.get("role")),
        "Services": safe_text(record.get("services")),
        "Languages": safe_text(record.get("languages")),
        "Domains": safe_text(record.get("domains")),
        "Availability": safe_text(record.get("availability")),
        "Capacity": safe_text(record.get("weekly_capacity")),
        "Rates": " / ".join(
            part for part in [
                f"{safe_text(record.get('rate_currency') or 'INR')} {safe_text(record.get('hourly_rate'))}/hr" if safe_text(record.get("hourly_rate")) else "",
                f"{safe_text(record.get('rate_currency') or 'INR')} {safe_text(record.get('per_word_rate'))}/word" if safe_text(record.get("per_word_rate")) else "",
            ] if part
        ),
        "Location": ", ".join(part for part in [safe_text(record.get("city")), safe_text(record.get("country"))] if part),
        "Workspace": safe_text(record.get("workspace")),
        "Status": safe_text(record.get("talent_status") or record.get("status")),
        "Updated": record.get("updated_at", ""),
    }


def remove_saas_record(collection: str, record_id: str) -> bool:
    removed = False
    if delete_saas_record is not None:
        try:
            removed = bool(delete_saas_record(collection, record_id, **persistence_read_scope(platform_scope_reason="record_delete")))
        except ValueError as exc:
            LOGGER.error("Rejected unsupported SaaS record delete %s/%s: %s", collection, record_id, exc)
        except requests.RequestException as exc:
            LOGGER.error("Network error while deleting SaaS record %s/%s: %s", collection, record_id, exc)
    rows = st.session_state.get(collection)
    if isinstance(rows, list):
        before = len(rows)
        st.session_state[collection] = [
            item for item in rows
            if not (isinstance(item, dict) and safe_text(item.get("id")) == safe_text(record_id))
        ]
        removed = removed or len(st.session_state[collection]) != before
    if removed:
        clear_saas_record_cache()
    return removed


def _setting_json_value(record: Dict[str, Any]) -> Any:
    value = record.get("setting_value")
    if isinstance(value, str):
        try:
            return json.loads(value)
        except json.JSONDecodeError as exc:
            LOGGER.debug("Platform setting %s is not JSON: %s", safe_text(record.get("setting_key")), exc)
            return value
    return value


def upsert_platform_setting(setting_key: str, setting_value: Any, metadata: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    record = persist_saas_record("platform_settings", {
        "id": f"platform-{safe_text(setting_key)}",
        "workspace": "Platform",
        "setting_key": safe_text(setting_key),
        "setting_value": setting_value,
        "value_type": "json" if isinstance(setting_value, (dict, list, bool, int, float)) else "text",
        "metadata_json": metadata or {},
        "created_at": now_stamp(),
        "updated_at": now_stamp(),
    })
    upsert_session_record("platform_settings", record)
    return record


def legal_version_defaults() -> Dict[str, str]:
    return dict(LEGAL_VERSION_DEFAULTS)


def legal_versions() -> Dict[str, str]:
    versions = legal_version_defaults()
    persisted = st.session_state.setdefault("legal_versions", legal_version_defaults())
    if isinstance(persisted, dict):
        for key in versions:
            value = safe_text(persisted.get(key))
            if value:
                versions[key] = value[:80]
    st.session_state["legal_versions"] = versions
    return versions


def set_legal_versions(updates: Dict[str, str]) -> List[str]:
    current = legal_versions()
    cleaned = {}
    changed = []
    for key, fallback in legal_version_defaults().items():
        value = safe_text(updates.get(key) or fallback).strip()[:80]
        cleaned[key] = value or fallback
        if cleaned[key] != current.get(key):
            changed.append(key)
    st.session_state["legal_versions"] = cleaned
    if changed:
        try:
            upsert_platform_setting(
                "legal_versions",
                cleaned,
                metadata={"changed": changed, "source": "Platform Settings"},
            )
        except Exception as exc:
            LOGGER.warning("Unable to persist legal versions: %s", exc)
        add_audit("Legal versions updated", ", ".join(f"{key}={cleaned[key]}" for key in changed))
    return changed


def compliance_ack_label() -> str:
    versions = legal_versions()
    return (
        f"I accept the [Terms of Service](?public=terms) (v{versions['terms_version']}), "
        f"[Privacy Policy](?public=privacy) (v{versions['privacy_version']}), "
        f"[Cookie Notice](?public=cookies) (v{versions['cookie_version']}), "
        f"[DPA](?public=dpa) (v{versions['dpa_version']}), and "
        f"NDA/confidentiality obligations (v{versions['nda_version']}) for this workspace."
    )


def consent_versions_are_current(record: Dict[str, Any], versions: Optional[Dict[str, str]] = None) -> bool:
    versions = versions or legal_versions()
    return all(safe_text(record.get(key)) == safe_text(versions.get(key)) for key in ("terms_version", "privacy_version", "nda_version", "cookie_version", "dpa_version"))


def record_consent_acceptance(email: str, role: str, account_type: str, workspace: str, source: str = "login") -> Dict[str, Any]:
    versions = legal_versions()
    accepted_at = now_stamp()
    record = persist_saas_record("consent_records", {
        "id": f"consent-{uuid.uuid4().hex}",
        "workspace": safe_text(workspace or "Demo Workspace"),
        "user_email": safe_text(email).strip(),
        "email": safe_text(email).strip(),
        "account_type": safe_text(account_type),
        "role": safe_text(role),
        **versions,
        "accepted_at": accepted_at,
        "ip_hint": "",
        "metadata_json": {"source": safe_text(source), "app_version": APP_VERSION},
        "created_at": accepted_at,
        "updated_at": accepted_at,
    })
    upsert_session_record("consent_records", record)
    add_audit(
        "Legal terms accepted",
        f"{safe_text(email)} accepted terms={versions['terms_version']} privacy={versions['privacy_version']} nda={versions['nda_version']}",
    )
    return record


def abuse_protection_defaults() -> Dict[str, int]:
    return dict(ABUSE_PROTECTION_DEFAULTS)


def abuse_protection_settings() -> Dict[str, int]:
    settings = abuse_protection_defaults()
    persisted = st.session_state.setdefault("abuse_protection", abuse_protection_defaults())
    if isinstance(persisted, dict):
        for key, fallback in settings.items():
            try:
                value = int(persisted.get(key, fallback))
            except Exception:
                value = fallback
            settings[key] = max(0, value)
    settings["window_minutes"] = max(1, settings.get("window_minutes", ABUSE_PROTECTION_DEFAULTS["window_minutes"]))
    st.session_state["abuse_protection"] = settings
    return settings


def set_abuse_protection_settings(updates: Dict[str, int]) -> List[str]:
    current = abuse_protection_settings()
    cleaned: Dict[str, int] = {}
    changed: List[str] = []
    for key, fallback in abuse_protection_defaults().items():
        try:
            value = int(updates.get(key, fallback))
        except Exception:
            value = fallback
        if key == "window_minutes":
            value = max(1, min(1440, value))
        else:
            value = max(0, min(1000, value))
        cleaned[key] = value
        if cleaned[key] != current.get(key):
            changed.append(key)
    st.session_state["abuse_protection"] = cleaned
    if changed:
        try:
            upsert_platform_setting(
                "abuse_protection",
                cleaned,
                metadata={"changed": changed, "source": "Platform Settings"},
            )
        except Exception as exc:
            LOGGER.warning("Unable to persist abuse protection settings: %s", exc)
        add_audit("Abuse protection updated", ", ".join(f"{key}={cleaned[key]}" for key in changed))
    return changed


def abuse_identifier(action: str, identifier: str = "") -> str:
    user = current_user() or {}
    raw = safe_text(identifier or user.get("email") or user.get("workspace") or "anonymous").strip().lower()
    if not raw:
        raw = "anonymous"
    digest = hashlib.sha256(raw.encode("utf-8")).hexdigest()[:16]
    return f"{safe_text(action)}:{digest}"


def abuse_attempt_label(action: str, identifier: str = "") -> str:
    visible = safe_text(identifier or (current_user() or {}).get("email") or "anonymous").strip()
    if "@" in visible:
        name, _, domain = visible.partition("@")
        visible = f"{name[:2]}***@{domain}"
    elif len(visible) > 18:
        visible = f"{visible[:8]}...{visible[-4:]}"
    return visible or "anonymous"


def consume_abuse_attempt(action: str, identifier: str = "") -> Tuple[bool, str]:
    meta = ABUSE_ACTION_META.get(action)
    if not meta:
        return True, ""
    label, limit_key = meta
    settings = abuse_protection_settings()
    limit = int(settings.get(limit_key, 0))
    if limit <= 0:
        return True, ""
    window_seconds = max(60, int(settings.get("window_minutes", 15)) * 60)
    now_epoch = time.time()
    key = abuse_identifier(action, identifier)
    events = st.session_state.setdefault("abuse_throttle_events", {})
    attempts = [float(item) for item in events.get(key, []) if now_epoch - float(item) <= window_seconds]
    if len(attempts) >= limit:
        oldest = min(attempts) if attempts else now_epoch
        wait_seconds = max(1, int(window_seconds - (now_epoch - oldest)))
        wait_minutes = max(1, math.ceil(wait_seconds / 60))
        blocks = st.session_state.setdefault("abuse_throttle_blocks", [])
        block = {
            "time": now_stamp(),
            "action": action,
            "surface": label,
            "identifier": abuse_attempt_label(action, identifier),
            "attempts": len(attempts),
            "limit": limit,
            "window_minutes": settings.get("window_minutes", 15),
            "wait_minutes": wait_minutes,
        }
        blocks.insert(0, block)
        del blocks[100:]
        add_audit("Abuse throttle blocked", f"{label}: {block['identifier']} hit {len(attempts)}/{limit} in {settings.get('window_minutes')}m")
        return False, f"Too many {label.lower()} attempts. Please wait about {wait_minutes} minute(s) and try again."
    attempts.append(now_epoch)
    events[key] = attempts
    return True, ""


def clear_abuse_attempts(action: str, identifier: str = "") -> None:
    key = abuse_identifier(action, identifier)
    events = st.session_state.setdefault("abuse_throttle_events", {})
    events.pop(key, None)


def hydrate_platform_settings(force: bool = False) -> None:
    if st.session_state.get("_platform_settings_hydrated") and not force:
        return
    records = load_saas_records(
        "platform_settings",
        workspace="Platform",
        include_all_workspaces=True,
        platform_scope_reason="platform_settings_hydration",
        limit=SESSION_COLLECTION_LIMITS.get("platform_settings", 100),
    )
    if records:
        st.session_state["platform_settings"] = records
        feature_record = next((row for row in records if safe_text(row.get("setting_key")) == "feature_flags"), None)
        if feature_record:
            persisted_flags = _setting_json_value(feature_record)
            if isinstance(persisted_flags, dict):
                merged = feature_flag_defaults()
                merged.update({key: bool(value) for key, value in persisted_flags.items() if key in FEATURE_FLAG_META})
                st.session_state["feature_flags"] = merged
        retention_record = next((row for row in records if safe_text(row.get("setting_key")) == "retention_policy"), None)
        if retention_record:
            persisted_policy = _setting_json_value(retention_record)
            if isinstance(persisted_policy, dict):
                merged_policy = retention_policy_defaults()
                for key, value in persisted_policy.items():
                    if key in merged_policy:
                        try:
                            merged_policy[key] = max(0, int(value))
                        except Exception:
                            LOGGER.warning("Invalid persisted retention value for %s: %s", key, value)
                st.session_state["retention_policy"] = merged_policy
        legal_record = next((row for row in records if safe_text(row.get("setting_key")) == "legal_versions"), None)
        if legal_record:
            persisted_versions = _setting_json_value(legal_record)
            if isinstance(persisted_versions, dict):
                merged_versions = legal_version_defaults()
                for key, value in persisted_versions.items():
                    if key in merged_versions and safe_text(value):
                        merged_versions[key] = safe_text(value)[:80]
                st.session_state["legal_versions"] = merged_versions
        abuse_record = next((row for row in records if safe_text(row.get("setting_key")) == "abuse_protection"), None)
        if abuse_record:
            persisted_abuse = _setting_json_value(abuse_record)
            if isinstance(persisted_abuse, dict):
                merged_abuse = abuse_protection_defaults()
                for key, value in persisted_abuse.items():
                    if key in merged_abuse:
                        try:
                            merged_abuse[key] = max(0, int(value))
                        except Exception:
                            LOGGER.warning("Invalid persisted abuse protection value for %s: %s", key, value)
                merged_abuse["window_minutes"] = max(1, merged_abuse.get("window_minutes", ABUSE_PROTECTION_DEFAULTS["window_minutes"]))
                st.session_state["abuse_protection"] = merged_abuse
        subprocessor_record = next((row for row in records if safe_text(row.get("setting_key")) == "subprocessor_register"), None)
        if subprocessor_record:
            persisted_register = _setting_json_value(subprocessor_record)
            if isinstance(persisted_register, dict):
                merged_register = dict(SUBPROCESSOR_DEFAULT_REGISTER)
                for key, value in persisted_register.items():
                    if isinstance(value, dict):
                        merged_register[safe_text(key)] = {
                            **merged_register.get(safe_text(key), {}),
                            **{safe_text(child_key): safe_text(child_value) for child_key, child_value in value.items()},
                        }
                st.session_state["subprocessor_register"] = merged_register
        sso_record = next((row for row in records if safe_text(row.get("setting_key")) == "sso_connections"), None)
        if sso_record:
            persisted_sso = _setting_json_value(sso_record)
            if isinstance(persisted_sso, dict):
                st.session_state["sso_connections"] = persisted_sso
    st.session_state["_platform_settings_hydrated"] = True


def public_auth_link(route: str, token: str) -> str:
    query = f"?public={quote(route)}&token={quote(token)}"
    base_url = secret("ERRORSWEEP_PUBLIC_BASE_URL", "").strip().rstrip("/")
    if base_url:
        return f"{base_url}/{query}"
    return query


def auth_token_hash(token: str) -> str:
    return hmac.new(session_secret().encode("utf-8"), safe_text(token).encode("utf-8"), hashlib.sha256).hexdigest()


def auth_token_expired(record: Dict[str, Any]) -> bool:
    raw = safe_text(record.get("expires_at"))
    if not raw:
        return False
    try:
        expires = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        if expires.tzinfo is None:
            expires = expires.replace(tzinfo=timezone.utc)
        return datetime.now(timezone.utc) > expires
    except Exception as exc:
        LOGGER.warning("Unable to parse auth token expiry %s: %s", raw, exc)
        return True


def upsert_session_record(key: str, record: Dict[str, Any]) -> None:
    rows = st.session_state.setdefault(key, [])
    record_id = safe_text(record.get("id"))
    for idx, item in enumerate(rows):
        if record_id and safe_text(item.get("id")) == record_id:
            rows[idx] = record
            break
    else:
        rows.insert(0, record)
    trim_session_list(key, SESSION_COLLECTION_LIMITS.get(key, SESSION_HISTORY_LIMIT))


def create_auth_token(email: str, token_type: str, workspace: str = "", metadata: Optional[Dict[str, Any]] = None) -> Tuple[str, Dict[str, Any]]:
    raw_token = b64url(os.urandom(32))
    expires_at = datetime.fromtimestamp(time.time() + AUTH_TOKEN_TTL_SECONDS, timezone.utc).isoformat()
    record = persist_saas_record("auth_tokens", {
        "workspace": workspace or "Demo Workspace",
        "user_email": email,
        "email": email,
        "token_hash": auth_token_hash(raw_token),
        "token_type": token_type,
        "status": "active",
        "expires_at": expires_at,
        "used_at": None,
        "metadata_json": metadata or {},
        "created_at": now_stamp(),
        "updated_at": now_stamp(),
    })
    upsert_session_record("auth_tokens", record)
    return raw_token, record


def auth_token_records() -> List[Dict[str, Any]]:
    records = list(st.session_state.get("auth_tokens", []))
    for record in load_saas_records(
        "auth_tokens",
        include_all_workspaces=True,
        platform_scope_reason="auth_token_lookup",
        limit=SESSION_COLLECTION_LIMITS.get("auth_tokens", 500),
    ):
        if not any(safe_text(item.get("id")) == safe_text(record.get("id")) for item in records):
            records.append(record)
    return records


def find_auth_token(raw_token: str, token_type: str) -> Optional[Dict[str, Any]]:
    if not safe_text(raw_token):
        return None
    digest = auth_token_hash(raw_token)
    for record in auth_token_records():
        if not hmac.compare_digest(safe_text(record.get("token_hash")), digest):
            continue
        if safe_text(record.get("token_type")) != token_type:
            continue
        if safe_text(record.get("status")).lower() != "active":
            return None
        if auth_token_expired(record):
            record["status"] = "expired"
            record["updated_at"] = now_stamp()
            persisted = persist_saas_record("auth_tokens", record)
            upsert_session_record("auth_tokens", persisted)
            return None
        return record
    return None


def consume_auth_token(record: Dict[str, Any]) -> Dict[str, Any]:
    updated = dict(record)
    updated["status"] = "used"
    updated["used_at"] = now_stamp()
    updated["updated_at"] = now_stamp()
    persisted = persist_saas_record("auth_tokens", updated)
    upsert_session_record("auth_tokens", persisted)
    return persisted


def update_stored_user(email: str, changes: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    email_key = safe_text(email).lower()
    users = list(st.session_state.get("users", []))
    for record in load_saas_records(
        "users",
        include_all_workspaces=True,
        platform_scope_reason="user_profile_lookup",
        limit=SESSION_COLLECTION_LIMITS.get("users", 1000),
    ):
        if not any(safe_text(item.get("id")) == safe_text(record.get("id")) for item in users):
            users.append(record)
    matched = None
    for item in users:
        if safe_text(item.get("email")).lower() == email_key:
            matched = dict(item)
            break
    if matched is None:
        return None
    matched.update(changes)
    matched["updated_at"] = now_stamp()
    persisted = persist_saas_record("users", matched)
    upsert_session_record("users", persisted)
    return persisted


def update_workspace_user(email: str, workspace: str, changes: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    email_key = safe_text(email).lower()
    workspace_key = safe_text(workspace).strip()
    if not email_key or not workspace_key or workspace_key.lower() == "platform":
        return None
    matched = None
    for item in workspace_user_records(workspace_key):
        if safe_text(item.get("email")).lower() == email_key:
            matched = dict(item)
            break
    if matched is None:
        return None
    matched.update(changes)
    matched["workspace"] = workspace_key
    matched["updated_at"] = now_stamp()
    persisted = persist_saas_record("users", matched)
    upsert_session_record("users", persisted)
    return persisted


def normalized_profile_completion_status(user: Dict[str, Any]) -> str:
    return safe_text(user.get("profile_completion_status") or "pending").lower()


PROFILE_COMPLETION_PROMPT_DISMISSED_SESSION_KEY = "_profile_completion_prompt_dismissed_session"


def profile_completion_prompt_due(user: Dict[str, Any]) -> bool:
    if not user or is_platform_owner_identity(user):
        return False
    if st.session_state.get(PROFILE_COMPLETION_PROMPT_DISMISSED_SESSION_KEY):
        return False
    return normalized_profile_completion_status(user) != "completed"


def stored_metadata_dict(value: Any) -> Dict[str, Any]:
    if isinstance(value, dict):
        return dict(value)
    if isinstance(value, str) and value.strip():
        try:
            decoded = json.loads(value)
            return decoded if isinstance(decoded, dict) else {}
        except Exception:
            return {}
    return {}


def csv_choices(value: Any, allowed: List[str]) -> List[str]:
    selected = [safe_text(item) for item in safe_text(value).split(",") if safe_text(item)]
    return [item for item in selected if item in allowed]


def catalog_index(options: List[str], value: Any, default: int = 0) -> int:
    label = safe_text(value)
    return options.index(label) if label in options else default


def merge_current_user_record(record: Dict[str, Any]) -> None:
    current = dict(current_user() or {})
    account_type = current.get("account_type", "workspace")
    login_at = current.get("login_at", datetime.now(timezone.utc).isoformat())
    current.update(safe_user_session_record(record))
    current["account_type"] = account_type
    current["login_at"] = login_at
    st.session_state["user"] = current
    st.session_state["_pending_session_cookie"] = signed_session_token_for_user(current)


def save_current_user_profile(changes: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    user = current_user() or {}
    email = safe_text(user.get("email")).strip()
    if not email:
        return None
    persisted = update_stored_user(email, changes)
    if persisted:
        merge_current_user_record(persisted)
        return persisted
    fallback = {**user, **changes, "updated_at": now_stamp()}
    merge_current_user_record(fallback)
    return fallback


def dispatch_queued_email_if_configured(record: Dict[str, Any]) -> Dict[str, Any]:
    """Send newly queued auth email immediately when a live provider is configured."""
    if not isinstance(record, dict):
        return record
    provider_fn = globals().get("email_provider_label")
    provider = provider_fn() if callable(provider_fn) else "not_configured"
    if provider not in {"resend", "sendgrid", "smtp"}:
        return record
    dispatcher = globals().get("dispatch_email_notification")
    if not callable(dispatcher):
        return record
    try:
        return dispatcher(record)
    except Exception as exc:
        LOGGER.warning("Immediate email dispatch failed: %s", exc)
        return record


def queue_verification_email(email: str, workspace: str, name: str = "") -> str:
    token, _ = create_auth_token(email, "email_verification", workspace, metadata={"name": name})
    link = public_auth_link("verify", token)
    record = queue_email_notification(
        email,
        "Verify your CogniSweep email",
        f"Verify your CogniSweep workspace email for '{workspace}'.",
        "auth.email_verification",
        metadata={"workspace": workspace, "verify_url": link},
        workspace=workspace,
    )
    dispatch_queued_email_if_configured(record)
    return link


def queue_password_reset_email(email: str, workspace: str = "", *, return_record: bool = False) -> Any:
    token, _ = create_auth_token(email, "password_reset", workspace or "Demo Workspace")
    link = public_auth_link("reset", token)
    record = queue_email_notification(
        email,
        "Reset your CogniSweep password",
        "Reset your CogniSweep password from the secure action.",
        "auth.password_reset",
        metadata={"reset_url": link},
        workspace=workspace or "Demo Workspace",
    )
    dispatched = dispatch_queued_email_if_configured(record)
    if return_record:
        return link, dispatched
    return link


def hydrate_saas_state_for_user() -> None:
    user = current_user()
    if not user or st.session_state.get("_saas_state_hydrated"):
        return
    workspace = user.get("workspace", "")
    include_all = is_owner()
    for key in [
        "users",
        "workspaces",
        "projects",
        "jobs",
        "payments",
        "invoices",
        "audit_logs",
        "notifications",
        "task_queue",
        "files",
        "subscriptions",
        "checkout_sessions",
        "billing_events",
        "auth_tokens",
        "platform_settings",
        "privacy_requests",
        "support_tickets",
        "status_incidents",
        "consent_records",
    ]:
        collection_include_all = include_all or key in {"status_incidents"}
        platform_reason = ""
        if collection_include_all:
            platform_reason = "owner_state_hydration" if include_all else "status_incident_hydration"
        records = load_saas_records(
            key,
            workspace="" if collection_include_all else workspace,
            include_all_workspaces=collection_include_all,
            platform_scope_reason=platform_reason,
            limit=SESSION_COLLECTION_LIMITS.get(key, 500),
        )
        if records:
            st.session_state[key] = records
    hydrate_platform_settings(force=True)
    if fetch_persistent_usage_events is not None:
        try:
            usage_records = fetch_persistent_usage_events(
                SESSION_COLLECTION_LIMITS.get("ai_usage_events", 500),
                **persistence_read_scope(user, "owner_usage_hydration"),
            )
            if usage_records:
                st.session_state["ai_usage_events"] = usage_records
        except Exception as exc:
            LOGGER.warning("Unable to hydrate usage events: %s", exc)
    st.session_state["_saas_state_hydrated"] = True


def refresh_task_queue_state_for_user(force: bool = False) -> None:
    user = current_user()
    if not user:
        return
    now = time.monotonic()
    last_refresh = float(st.session_state.get("_task_queue_refresh_at") or 0)
    if not force and now - last_refresh < 8:
        return
    include_all = is_owner()
    try:
        clear_saas_record_cache()
        records = load_saas_records(
            "task_queue",
            workspace="" if include_all else user.get("workspace", ""),
            include_all_workspaces=include_all,
            platform_scope_reason="owner_task_queue_refresh" if include_all else "",
            limit=SESSION_COLLECTION_LIMITS.get("task_queue", 1000),
        )
        if records:
            st.session_state["task_queue"] = records
        st.session_state["_task_queue_refresh_at"] = now
    except Exception as exc:
        LOGGER.warning("Unable to refresh task queue state: %s", exc)


def b64url_decode(data: str) -> bytes:
    pad = "=" * (-len(data) % 4)
    return base64.urlsafe_b64decode(data + pad)


def sign_payload(payload: Dict[str, Any]) -> str:
    raw = json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8")
    body = b64url(raw)
    sig = hmac.new(session_secret().encode("utf-8"), body.encode("utf-8"), hashlib.sha256).hexdigest()
    return f"{body}.{sig}"


def verify_payload(token: str) -> Optional[Dict[str, Any]]:
    try:
        body, sig = token.split(".", 1)
        expected = hmac.new(session_secret().encode("utf-8"), body.encode("utf-8"), hashlib.sha256).hexdigest()
        if not hmac.compare_digest(expected, sig):
            return None
        data = json.loads(b64url_decode(body))
        return data
    except RuntimeError:
        raise
    except Exception as exc:
        LOGGER.debug("Session token verification failed: %s", exc)
        return None


def query_get(name: str) -> str:
    try:
        val = st.query_params.get(name, "")
        if isinstance(val, list):
            return val[0] if val else ""
        return val or ""
    except Exception as exc:
        LOGGER.debug("Unable to read query param %s: %s", name, exc)
        return ""


def query_set(name: str, value: str) -> None:
    try:
        st.query_params[name] = value
        return
    except Exception as exc:
        LOGGER.debug("Unable to set query param %s via st.query_params: %s", name, exc)
    try:
        params = {k: (v if isinstance(v, list) else [v]) for k, v in st.query_params.items()}
        params[name] = [value]
        st.experimental_set_query_params(**params)
    except Exception as exc:
        LOGGER.debug("Unable to set query param %s: %s", name, exc)


def query_clear(name: str) -> None:
    try:
        if name in st.query_params:
            del st.query_params[name]
        return
    except Exception as exc:
        LOGGER.debug("Unable to clear query param %s via st.query_params: %s", name, exc)
    try:
        params = {k: v for k, v in st.query_params.items() if k != name}
        st.experimental_set_query_params(**params)
    except Exception as exc:
        LOGGER.debug("Unable to clear query param %s: %s", name, exc)


def route_query_has_explicit_target() -> bool:
    return any(query_get(key) for key in ROUTE_RESTORE_BLOCKING_QUERY_KEYS)


def compact_session_user_payload(user: Dict[str, Any]) -> Dict[str, Any]:
    payload = {
        key: user.get(key)
        for key in SESSION_TOKEN_USER_FIELDS
        if user.get(key) not in (None, "")
    }
    payload["email"] = safe_text(payload.get("email") or user.get("email")).strip().lower()
    payload["role"] = safe_text(payload.get("role") or "User")
    payload["account_type"] = safe_text(payload.get("account_type") or "user")
    payload["workspace"] = safe_text(payload.get("workspace") or "Demo Workspace")
    return payload


def session_epoch_ms() -> int:
    return int(time.time() * 1000)


def session_ms_from_value(value: Any) -> int:
    if value in (None, ""):
        return 0
    text = safe_text(value).strip()
    if not text:
        return 0
    try:
        number = float(text)
        if number <= 0:
            return 0
        if number < 100_000_000_000:
            number *= 1000
        return int(number)
    except (TypeError, ValueError):
        pass
    try:
        parsed = datetime.fromisoformat(text.replace("Z", "+00:00"))
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=timezone.utc)
        return int(parsed.timestamp() * 1000)
    except Exception:
        return 0


def session_started_at_ms_from_payload(payload: Dict[str, Any]) -> int:
    return (
        session_ms_from_value(payload.get(SESSION_STARTED_AT_MS_FIELD))
        or session_ms_from_value(payload.get("session_started_at"))
        or session_ms_from_value(payload.get("login_at"))
        or session_ms_from_value(payload.get("iat"))
    )


def ensure_session_started_at_ms(user: Dict[str, Any]) -> int:
    started_at_ms = session_started_at_ms_from_payload(user or {})
    if not started_at_ms:
        started_at_ms = session_epoch_ms()
    if isinstance(user, dict):
        user[SESSION_STARTED_AT_MS_FIELD] = started_at_ms
    return started_at_ms


def session_identity_key(value: Any) -> str:
    email = safe_text(value.get("email") if isinstance(value, dict) else value).strip().lower()
    if not email:
        return ""
    return hashlib.sha256(email.encode("utf-8")).hexdigest()


@st.cache_resource(show_spinner=False)
def session_logout_registry() -> Dict[str, int]:
    return {}


def session_logout_after_ms(value: Any) -> int:
    key = session_identity_key(value)
    if not key:
        return 0
    try:
        return int(session_logout_registry().get(key, 0) or 0)
    except Exception:
        return 0


def record_session_logout(user: Dict[str, Any]) -> None:
    key = session_identity_key(user)
    if not key:
        return
    registry = session_logout_registry()
    registry[key] = max(int(registry.get(key, 0) or 0), session_epoch_ms())
    if len(registry) > SESSION_LOGOUT_REGISTRY_LIMIT:
        for stale_key, _ in sorted(registry.items(), key=lambda item: item[1])[: len(registry) - SESSION_LOGOUT_REGISTRY_LIMIT]:
            registry.pop(stale_key, None)


def session_token_revoked(payload: Dict[str, Any]) -> bool:
    if not payload:
        return False
    logout_after_ms = session_logout_after_ms(payload)
    if not logout_after_ms:
        return False
    started_at_ms = session_started_at_ms_from_payload(payload)
    if not started_at_ms:
        return True
    return started_at_ms <= logout_after_ms


def active_session_revoked(user: Dict[str, Any]) -> bool:
    return session_token_revoked(user or {})


def signed_session_token_for_user(user: Dict[str, Any]) -> str:
    issued_at_ms = session_epoch_ms()
    payload = {
        **compact_session_user_payload(user),
        "iat": issued_at_ms // 1000,
        SESSION_STARTED_AT_MS_FIELD: ensure_session_started_at_ms(user),
        "persistent": True,
    }
    token = sign_payload(payload)
    if len(token.encode("utf-8")) > SESSION_COOKIE_MAX_BYTES:
        LOGGER.warning("Signed session token is larger than the browser cookie budget: %s bytes", len(token.encode("utf-8")))
    return token


def signed_editor_launch_token_for_user(user: Dict[str, Any]) -> str:
    issued_at_ms = session_epoch_ms()
    issued_at = issued_at_ms // 1000
    payload = {
        **compact_session_user_payload(user),
        "iat": issued_at,
        SESSION_STARTED_AT_MS_FIELD: ensure_session_started_at_ms(user),
        "exp": issued_at + EDITOR_LAUNCH_TTL_SECONDS,
        "purpose": "editor_launch",
        "v": 1,
    }
    return sign_payload(payload)


def browser_cookie_controller() -> Optional[Any]:
    if CookieController is None:
        return None
    try:
        return CookieController(key=SESSION_COOKIE_CONTROLLER_KEY)
    except Exception as exc:
        LOGGER.debug("Unable to initialize browser cookie controller: %s", exc)
        return None


def component_session_cookie() -> str:
    controller = browser_cookie_controller()
    if controller is None:
        return ""
    try:
        return safe_text(controller.get(SESSION_COOKIE_NAME) or "")
    except Exception as exc:
        LOGGER.debug("Unable to read browser session cookie from component: %s", exc)
        return ""


def sync_component_session_cookie(token: str = "", clear_cookie: bool = False) -> None:
    controller = browser_cookie_controller()
    if controller is None:
        return
    try:
        if token:
            expires = datetime.now() + timedelta(seconds=SESSION_PERSISTENCE_SECONDS)
            controller.set(
                SESSION_COOKIE_NAME,
                token,
                path="/",
                expires=expires,
                max_age=SESSION_PERSISTENCE_SECONDS,
                same_site="lax",
            )
        elif clear_cookie:
            if controller.get(SESSION_COOKIE_NAME) is not None:
                controller.remove(SESSION_COOKIE_NAME, path="/", same_site="lax")
    except Exception as exc:
        LOGGER.debug("Unable to sync browser session cookie component: %s", exc)


def browser_session_cookie() -> str:
    try:
        token = safe_text(st.context.cookies.get(SESSION_COOKIE_NAME, ""))
        if token:
            return token
    except Exception as exc:
        LOGGER.debug("Unable to read browser session cookie: %s", exc)
    return component_session_cookie()


def browser_cookie_domain_js_function() -> str:
    return """
          const cookieDomainAttribute = (hostname) => {
            const host = String(hostname || "").toLowerCase();
            if (!host || host === "localhost" || host === "127.0.0.1" || host === "::1") return "";
            if (/^\\d+\\.\\d+\\.\\d+\\.\\d+$/.test(host)) return "";
            if (host === "cognisweep.com" || host.endsWith(".cognisweep.com")) return "; Domain=.cognisweep.com";
            return "";
          };
    """.rstrip()


def render_parent_script(runtime: str, *, height: int = 0, scrolling: bool = False) -> None:
    """Install app-owned JavaScript in the parent Streamlit document without eval."""
    components.html(
        f"""
        <script>
        (() => {{
          const runtime = {json.dumps(runtime)};
          const install = (targetWindow) => {{
            const targetDoc = targetWindow && targetWindow.document ? targetWindow.document : document;
            const host = targetDoc.head || targetDoc.documentElement || targetDoc.body;
            if (!host) return false;
            const script = targetDoc.createElement("script");
            script.type = "text/javascript";
            script.textContent = runtime;
            host.appendChild(script);
            script.remove();
            return true;
          }};
          try {{
            if (!install(window.parent || window)) install(window);
          }} catch (err) {{
            try {{ install(window); }} catch (fallbackErr) {{}}
          }}
        }})();
        </script>
        """,
        height=height,
        scrolling=scrolling,
    )


def render_public_landing_canonical_redirect_bridge() -> None:
    """Redirect bare public roots to the canonical marketing landing URL."""
    target_url = safe_text(PUBLIC_LANDING_CANONICAL_URL)
    if not target_url:
        return
    target_url_json = json.dumps(target_url)
    render_parent_script(
        f"""
        (() => {{
          const target = {target_url_json};
          try {{
            const current = new URL(window.location.href);
            const targetUrl = new URL(target, current.href);
            const currentHost = current.hostname.toLowerCase();
            const canonicalHost = targetUrl.hostname.toLowerCase();
            const apexHost = canonicalHost.replace(/^www\\./, "");
            const cleanPath = (value) => {{
              const path = String(value || "/").replace(/\\/+$/, "");
              return path || "/";
            }};
            const isBareRoot = cleanPath(current.pathname) === "/" && current.search === "";
            const isPublicHost = currentHost === canonicalHost || currentHost === apexHost;
            const isAlreadyCanonical = current.origin === targetUrl.origin && cleanPath(current.pathname) === cleanPath(targetUrl.pathname);
            if (isBareRoot && isPublicHost && !isAlreadyCanonical) {{
              window.location.replace(targetUrl.toString());
            }}
          }} catch (err) {{}}
        }})();
        """,
        height=0,
        scrolling=False,
    )


def render_authenticated_shell_seen_bridge() -> None:
    storage_key_json = json.dumps(SESSION_STORAGE_KEY)
    render_parent_script(
        f"""
        (() => {{
          const authShellSeenKey = {storage_key_json} + ":authenticated_shell_seen";
          const candidateWindows = [window.parent, window.top, window];
          for (const candidate of candidateWindows) {{
            try {{
              if (candidate && candidate.sessionStorage) {{
                candidate.sessionStorage.setItem(authShellSeenKey, "1");
                return;
              }}
            }} catch (err) {{}}
          }}
        }})();
        """.strip(),
        height=0,
    )


@st.fragment(run_every="2s")
def render_authenticated_logout_watchdog() -> None:
    """Force authenticated shells to leave when another tab revoked the session."""
    if not (st.session_state.get("authenticated") and st.session_state.get("user")):
        st.empty()
        return
    user = st.session_state.get("user") or {}
    if not active_session_revoked(user):
        st.empty()
        return

    st.session_state.pop("user", None)
    st.session_state.pop("authenticated", None)
    st.session_state.pop("_saas_state_hydrated", None)
    st.session_state.pop(LOGIN_SUCCESS_PENDING_KEY, None)
    st.session_state.pop("_session_query_fallback_attached", None)
    st.session_state.pop("_session_query_fallback_attach_attempts", None)
    st.session_state["_clear_session_cookie"] = True
    st.session_state[LOGOUT_BROWSER_CLEANUP_KEY] = True
    st.session_state[LOGOUT_SKIP_RESTORE_KEY] = True
    for key in ("es_session", "es_restore", AUTH_CHECK_QUERY_PARAM, EDITOR_LAUNCH_QUERY_PARAM, EDITOR_AUTH_FAILED_QUERY_PARAM, EDITOR_SUBMITTED_QUERY_PARAM, EDITOR_SUBMITTED_TYPE_QUERY_PARAM, "es_page", "es_editor", "job_id", "review_id", "task_id", "tool_tab", "es_app_nav", "route", "public", "return_to", "es_logout", LOGOUT_DONE_QUERY_PARAM):
        query_clear(key)
    query_set("es_page", "Landing")
    query_set(LOGOUT_DONE_QUERY_PARAM, "1")
    st.rerun(scope="app")


def set_auth_debug_state(
    cookie_found: bool,
    session_valid: bool,
    route_decision: str = "",
    route: Optional[Dict[str, Any]] = None,
    *,
    handoff_token_found: bool = False,
) -> None:
    st.session_state["_auth_debug"] = {
        "cookie_found": bool(cookie_found),
        "handoff_token_found": bool(handoff_token_found),
        "session_valid": bool(session_valid),
        "authenticated": bool(st.session_state.get("authenticated") and st.session_state.get("user")),
        "route_decision": safe_text(route_decision),
        "resolved_route": route or {},
    }


def render_auth_debug_panel(route: Optional[Dict[str, Any]] = None, route_decision: str = "") -> None:
    if query_get("debug_auth") != "1":
        return
    debug = dict(st.session_state.get("_auth_debug") or {})
    if route_decision:
        debug["route_decision"] = route_decision
    if route is not None:
        debug["resolved_route"] = route
    debug["authenticated"] = bool(st.session_state.get("authenticated") and st.session_state.get("user"))
    st.info("Auth debug")
    st.json({
        "cookie_found": bool(debug.get("cookie_found")),
        "handoff_token_found": bool(debug.get("handoff_token_found")),
        "session_valid": bool(debug.get("session_valid")),
        "authenticated": bool(debug.get("authenticated")),
        "route_decision": safe_text(debug.get("route_decision")),
        "resolved_route": debug.get("resolved_route") or {},
        "owner_username_configured": bool(configured_owner_username()),
        "owner_password_hash_configured": bool(configured_owner_password_hash()),
        "unlimited_owner_email_configured": bool(secret(UNLIMITED_ACCESS_EMAIL_SECRET, "")),
        "unlimited_owner_password_hash_configured": bool(secret(UNLIMITED_ACCESS_PASSWORD_HASH_SECRET, "")),
    })


