def runtime_commit_hint() -> str:
    for key in ("STREAMLIT_GIT_COMMIT", "GIT_COMMIT", "SOURCE_COMMIT", "COMMIT_SHA", "RENDER_GIT_COMMIT"):
        value = safe_text(os.getenv(key))
        if value:
            return value
    return ""


