def restore_user_from_signed_session(token: str) -> bool:
    if not safe_text(token):
        return False
    data = verify_payload(token)
    if not data:
        return False
    if session_token_revoked(data):
        return False
    token_user = safe_user_session_record({key: value for key, value in data.items() if key not in {"iat", "persistent", "v"}})
    stored_user = find_user_by_email(safe_text(token_user.get("email"))) or {}
    user = safe_user_session_record(stored_user or token_user)
    for key in SESSION_TOKEN_USER_FIELDS:
        if not safe_text(user.get(key)) and safe_text(token_user.get(key)):
            user[key] = token_user.get(key)
    user.setdefault("email", "")
    user.setdefault("role", "User")
    user.setdefault("account_type", "user")
    user.setdefault("workspace", "Demo Workspace")
    user.setdefault("login_at", "")
    user[SESSION_STARTED_AT_MS_FIELD] = session_started_at_ms_from_payload(data) or ensure_session_started_at_ms(user)
    st.session_state["user"] = user
    st.session_state["authenticated"] = True
    return True


def restore_user_from_editor_launch_token(token: str) -> bool:
    if not safe_text(token):
        return False
    data = verify_payload(token)
    if not data:
        return False
    if safe_text(data.get("purpose")) != "editor_launch":
        return False
    expires_at = int(data.get("exp") or 0)
    if not expires_at or expires_at < int(time.time()):
        return False
    if session_token_revoked(data):
        return False
    token_user = safe_user_session_record({key: value for key, value in data.items() if key in SESSION_TOKEN_USER_FIELDS})
    stored_user = find_user_by_email(safe_text(token_user.get("email"))) or {}
    user = safe_user_session_record(stored_user or token_user)
    for key in SESSION_TOKEN_USER_FIELDS:
        if not safe_text(user.get(key)) and safe_text(token_user.get(key)):
            user[key] = token_user.get(key)
    user.setdefault("email", "")
    user.setdefault("role", "User")
    user.setdefault("account_type", "user")
    user.setdefault("workspace", "Demo Workspace")
    user.setdefault("login_at", "")
    user[SESSION_STARTED_AT_MS_FIELD] = session_started_at_ms_from_payload(data) or ensure_session_started_at_ms(user)
    st.session_state["user"] = user
    st.session_state["authenticated"] = True
    return True


def restore_session_from_cookie() -> None:
    launch_token = query_get(EDITOR_LAUNCH_QUERY_PARAM)
    handoff_token = safe_text(query_get(SESSION_HANDOFF_QUERY_PARAM))
    token = browser_session_cookie()
    cookie_found = bool(token)
    handoff_token_found = bool(handoff_token)
    if not token and handoff_token:
        token = handoff_token
    session_valid = False
    editor_target = bool(query_get("es_editor") or query_get("job_id") or query_get("review_id"))
    st.session_state.pop("_editor_auth_restore_failed", None)
    if st.session_state.get("authenticated") and st.session_state.get("user"):
        if active_session_revoked(st.session_state.get("user") or {}):
            st.session_state.pop("user", None)
            st.session_state.pop("authenticated", None)
            st.session_state["_clear_session_cookie"] = True
            set_auth_debug_state(cookie_found, False, "session_revoked", handoff_token_found=handoff_token_found)
            return
        ensure_session_started_at_ms(st.session_state.get("user") or {})
        session_valid = True
        st.session_state["_pending_session_cookie"] = signed_session_token_for_user(st.session_state.get("user") or {})
        if cookie_found and handoff_token_found:
            query_clear(SESSION_HANDOFF_QUERY_PARAM)
        query_clear(EDITOR_LAUNCH_QUERY_PARAM)
        query_clear(EDITOR_AUTH_FAILED_QUERY_PARAM)
        set_auth_debug_state(cookie_found, session_valid, handoff_token_found=handoff_token_found)
        return
    if launch_token:
        session_valid = restore_user_from_editor_launch_token(launch_token)
        if session_valid:
            st.session_state["_pending_session_cookie"] = signed_session_token_for_user(st.session_state.get("user") or {})
            query_clear(EDITOR_LAUNCH_QUERY_PARAM)
            query_clear(EDITOR_AUTH_FAILED_QUERY_PARAM)
            query_clear(AUTH_CHECK_QUERY_PARAM)
            query_clear("es_session")
            query_clear("es_restore")
            query_clear("es_restore_miss")
            set_auth_debug_state(cookie_found, session_valid, handoff_token_found=handoff_token_found)
            return
        if editor_target:
            st.session_state["_editor_auth_restore_failed"] = True
    if token:
        session_valid = restore_user_from_signed_session(token)
        if session_valid:
            st.session_state["_pending_session_cookie"] = token
            query_clear(AUTH_CHECK_QUERY_PARAM)
            query_clear(EDITOR_LAUNCH_QUERY_PARAM)
            query_clear(EDITOR_AUTH_FAILED_QUERY_PARAM)
            if cookie_found:
                query_clear(SESSION_HANDOFF_QUERY_PARAM)
            query_clear("es_restore")
            query_clear("es_restore_miss")
        else:
            st.session_state.pop("user", None)
            st.session_state.pop("authenticated", None)
            st.session_state.pop("_session_query_fallback_attached", None)
            st.session_state.pop("_session_query_fallback_attach_attempts", None)
            if handoff_token_found:
                query_clear(SESSION_HANDOFF_QUERY_PARAM)
            if editor_target:
                st.session_state["_editor_auth_restore_failed"] = True
            else:
                st.session_state["_clear_session_cookie"] = True
    set_auth_debug_state(cookie_found, session_valid, handoff_token_found=handoff_token_found)


def sync_browser_session_cookie() -> None:
    """Mirror the signed session into a browser cookie so reloads survive.

    Streamlit app code cannot set HttpOnly cookies directly. This keeps the
    token out of URLs and browser history; a deployment proxy should upgrade
    this to a Secure HttpOnly Set-Cookie header when available.
    """
    token = safe_text(st.session_state.pop("_pending_session_cookie", ""))
    clear_cookie = bool(st.session_state.pop("_clear_session_cookie", False))
    defer_storage_clear_for_logout = bool(clear_cookie and st.session_state.get(LOGOUT_BROWSER_CLEANUP_KEY))
    if not token and not clear_cookie and st.session_state.get("authenticated") and st.session_state.get("user"):
        token = signed_session_token_for_user(st.session_state.get("user") or {})
    if not token and not clear_cookie:
        return
    token_json = json.dumps(token)
    name_json = json.dumps(SESSION_COOKIE_NAME)
    storage_key_json = json.dumps(SESSION_STORAGE_KEY)
    route_storage_key_json = json.dumps(ROUTE_STORAGE_KEY)
    logout_key_json = json.dumps(LOGOUT_BROADCAST_KEY)
    defer_storage_clear_json = json.dumps(defer_storage_clear_for_logout)
    max_age = SESSION_PERSISTENCE_SECONDS if token else 0
    domain_js = browser_cookie_domain_js_function()
    sync_component_session_cookie(token, clear_cookie=clear_cookie)
    components.html(
        f"""
        <script>
        (function() {{
          const name = {name_json};
          const storageKey = {storage_key_json};
          const routeStorageKey = {route_storage_key_json};
          const logoutKey = {logout_key_json};
          const value = {token_json};
          const deferStorageClearForLogout = {defer_storage_clear_json};
          const candidateWindows = [window.parent, window.top, window];
          const firstWindow = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.location) return candidate;
              }} catch (err) {{}}
            }}
            return window;
          }};
          const hostWindow = firstWindow();
          const secure = hostWindow.location.protocol === "https:" ? "; Secure" : "";
{domain_js}
          const firstDocument = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.document) return candidate.document;
              }} catch (err) {{}}
            }}
            return document;
          }};
          const firstStorage = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.localStorage) return candidate.localStorage;
              }} catch (err) {{}}
            }}
            try {{ return window.localStorage; }} catch (err) {{}}
            return null;
          }};
          let sharedStorage = null;
          try {{ sharedStorage = firstStorage(); }} catch (err) {{}}
          const pendingLogout = (() => {{
            try {{ return sharedStorage ? String(sharedStorage.getItem(logoutKey) || "") : ""; }}
            catch (err) {{ return ""; }}
          }})();
          if (value && pendingLogout) {{
            try {{
              if (sharedStorage) {{
                sharedStorage.removeItem(storageKey);
                sharedStorage.removeItem(routeStorageKey);
              }}
            }} catch (err) {{}}
            try {{
              const targetDoc = firstDocument();
              const domainAttr = cookieDomainAttribute(hostWindow.location.hostname);
              targetDoc.cookie = name + "=; Max-Age=0; Path=/; SameSite=Lax" + secure;
              targetDoc.cookie = name + "=; Max-Age=0; Path=/; SameSite=Lax" + secure + domainAttr;
            }} catch (err) {{}}
            try {{
              const loc = hostWindow.location;
              {landing_redirect_url_js(include_logout_marker=True, include_signed_out_marker=True)}
              const nextUrl = url.toString();
              if (loc.href !== nextUrl) loc.replace(nextUrl);
            }} catch (err) {{}}
            return;
          }}
          try {{
            const targetDoc = firstDocument();
            const domainAttr = cookieDomainAttribute(hostWindow.location.hostname);
            if (value) {{
              targetDoc.cookie = name + "=" + encodeURIComponent(value) +
                "; Max-Age={max_age}; Path=/; SameSite=Lax" + secure + domainAttr;
            }} else {{
              targetDoc.cookie = name + "=; Max-Age=0; Path=/; SameSite=Lax" + secure;
              targetDoc.cookie = name + "=; Max-Age=0; Path=/; SameSite=Lax" + secure + domainAttr;
            }}
          }} catch (err) {{}}
          try {{
            const storage = sharedStorage || firstStorage();
            if (!storage) return;
            if (value) {{
              storage.setItem(storageKey, value);
            }}
            else if (!deferStorageClearForLogout) {{
              storage.removeItem(storageKey);
              storage.removeItem(routeStorageKey);
            }}
          }} catch (err) {{}}
        }})();
        </script>
        """,
        height=0,
    )


def render_browser_session_bootstrap(route: Optional[Dict[str, Any]] = None) -> None:
    """Promote an existing browser token into the real cookie before routing settles."""
    if is_authenticated():
        return
    route = route or {}
    route_name = safe_text(route.get("public") or route.get("route")).strip().lower()
    should_try_bootstrap = (
        route_name in AUTHENTICATED_PUBLIC_ENTRY_ROUTES
        or protected_route_requested()
        or (
            not route_query_has_explicit_target()
            and not query_get("public")
            and not query_get("route")
        )
    )
    if not should_try_bootstrap:
        return

    cookie_name_json = json.dumps(SESSION_COOKIE_NAME)
    storage_key_json = json.dumps(SESSION_STORAGE_KEY)
    logout_key_json = json.dumps(LOGOUT_BROADCAST_KEY)
    route_param_keys_json = json.dumps(list(ROUTE_STORAGE_PARAM_KEYS))
    editor_auth_failed_param_json = json.dumps(EDITOR_AUTH_FAILED_QUERY_PARAM)
    signed_out_param_json = json.dumps(LOGOUT_DONE_QUERY_PARAM)
    public_entry_pages_json = json.dumps(["", "landing", "login", "signup", "sign up"])
    domain_js = browser_cookie_domain_js_function()
    bootstrap_runtime = f"""
        (function() {{
          try {{
            const cookieName = {cookie_name_json};
            const storageKey = {storage_key_json};
            const logoutKey = {logout_key_json};
            const routeParamKeys = {route_param_keys_json};
            const editorAuthFailedParam = {editor_auth_failed_param_json};
            const signedOutParam = {signed_out_param_json};
            const handledLogoutKey = logoutKey + ":handled";
            const publicEntryPages = new Set({public_entry_pages_json});
            const candidateWindows = [window.parent, window.top, window];
{domain_js}
            const firstWindow = () => {{
              for (const candidate of candidateWindows) {{
                try {{
                  if (candidate && candidate.location) return candidate;
                }} catch (err) {{}}
              }}
              return window;
            }};
            const firstDocument = () => {{
              for (const candidate of candidateWindows) {{
                try {{
                  if (candidate && candidate.document) return candidate.document;
                }} catch (err) {{}}
              }}
              return document;
            }};
            const firstStorage = (kind) => {{
              for (const candidate of candidateWindows) {{
                try {{
                  if (candidate && candidate[kind]) return candidate[kind];
                }} catch (err) {{}}
              }}
              try {{ return window[kind]; }} catch (err) {{}}
              return null;
            }};
            const normalizedPage = (value) => String(value || "")
              .replace(/[+_-]/g, " ")
              .replace(/\\s+/g, " ")
              .trim()
              .toLowerCase();
            const readCookie = (doc) => {{
              try {{
                const prefix = cookieName + "=";
                for (const part of String(doc.cookie || "").split(";")) {{
                  const item = part.trim();
                  if (item.startsWith(prefix)) return decodeURIComponent(item.slice(prefix.length));
                }}
              }} catch (err) {{}}
              return "";
            }};
            const loc = firstWindow().location;
            const targetDoc = firstDocument();
            const localStorage = firstStorage("localStorage");
            const sessionStorage = firstStorage("sessionStorage");
            const url = new URL(loc.href);
            const page = normalizedPage(url.searchParams.get("es_page"));
            const publicRoute = normalizedPage(url.searchParams.get("public") || url.searchParams.get("route"));
            const hasRouteTarget = ["es_page", "es_editor", "job_id", "review_id", "task_id", "route", "public"].some((key) => url.searchParams.has(key));
            const hasEditorTarget = ["es_editor", "job_id", "review_id", "task_id"].some((key) => url.searchParams.has(key));
            const hasEditorLaunchToken = !!url.searchParams.get("es_launch");
            const hasProtectedTarget = (
              hasEditorTarget
              || (!!page && !publicEntryPages.has(page))
              || normalizedPage(url.searchParams.get("route")) === "human review editor"
              || normalizedPage(url.searchParams.get("route")) === "human_review_editor"
            );
            const publicEntry = !hasRouteTarget || (!hasProtectedTarget && (publicEntryPages.has(page) || publicEntryPages.has(publicRoute)));
            if (!publicEntry && !hasProtectedTarget) return;

            const cleanOriginalParams = () => {{
              const originalParams = new URLSearchParams(url.search);
              ["es_session", "es_restore", "es_restore_miss", "es_auth_checked", "es_launch", "es_editor_auth_failed", "es_app_nav"].forEach((key) => originalParams.delete(key));
              return originalParams;
            }};
            const clearBootstrapState = () => {{
              if (!sessionStorage) return;
              try {{
                sessionStorage.removeItem(storageKey + "_bootstrap_attempted");
                sessionStorage.removeItem(storageKey + "_bootstrap_attempts");
                sessionStorage.removeItem(storageKey + "_bootstrap_token");
              }} catch (err) {{}}
            }};
            const clearBrowserSessionToken = (tokenToClear) => {{
              const secure = loc.protocol === "https:" ? "; Secure" : "";
              const domainAttr = cookieDomainAttribute(loc.hostname);
              try {{
                targetDoc.cookie = cookieName + "=; Max-Age=0; Path=/; SameSite=Lax" + secure;
                targetDoc.cookie = cookieName + "=; Max-Age=0; Path=/; SameSite=Lax" + secure + domainAttr;
              }} catch (err) {{}}
              try {{
                if (localStorage && (!tokenToClear || String(localStorage.getItem(storageKey) || "") === tokenToClear)) {{
                  localStorage.removeItem(storageKey);
                }}
              }} catch (err) {{}}
              clearBootstrapState();
            }};
            const routeToAuthFallback = () => {{
              if (hasEditorTarget) {{
                ["es_session", "es_restore", "es_restore_miss", "es_auth_checked", "es_app_nav"].forEach((key) => url.searchParams.delete(key));
                url.searchParams.set(editorAuthFailedParam, "1");
                loc.replace(url.toString());
                return;
              }}
              const originalParams = cleanOriginalParams();
              Array.from(url.searchParams.keys()).forEach((key) => url.searchParams.delete(key));
              if (publicEntry) {{
                url.searchParams.set("es_page", "Landing");
              }} else {{
                url.searchParams.set("es_page", "Login");
                const returnTo = originalParams.toString();
                if (returnTo) url.searchParams.set("return_to", returnTo);
              }}
              loc.replace(url.toString());
            }};
            const routeToSignedOutLanding = () => {{
              Array.from(url.searchParams.keys()).forEach((key) => url.searchParams.delete(key));
              url.searchParams.set("es_page", "Landing");
              url.searchParams.set(signedOutParam, "1");
              const nextUrl = url.toString();
              if (loc.href !== nextUrl) loc.replace(nextUrl);
            }};
            const cookieToken = readCookie(targetDoc);
            const storageToken = localStorage ? String(localStorage.getItem(storageKey) || "") : "";
            const logoutValue = localStorage ? String(localStorage.getItem(logoutKey) || "") : "";
            if (logoutValue) {{
              clearBrowserSessionToken("");
              try {{
                if (sessionStorage) sessionStorage.setItem(handledLogoutKey, logoutValue);
              }} catch (err) {{}}
              if (publicEntry && !hasProtectedTarget) return;
              routeToSignedOutLanding();
              return;
            }}
            const token = cookieToken || storageToken;
            if (!token) {{
              if (!hasEditorTarget) clearBrowserSessionToken("");
              if (hasEditorTarget && hasEditorLaunchToken) {{
                return;
              }}
              routeToAuthFallback();
              return;
            }}
            const attemptKey = storageKey + "_bootstrap_attempts";
            const attemptTokenKey = storageKey + "_bootstrap_token";
            const maxBootstrapAttempts = 3;
            let attempts = 0;
            if (sessionStorage) {{
              try {{
                const previousToken = String(sessionStorage.getItem(attemptTokenKey) || "");
                if (previousToken !== token) {{
                  sessionStorage.setItem(attemptTokenKey, token);
                  sessionStorage.setItem(attemptKey, "0");
                }} else {{
                  const parsedAttempts = Number(sessionStorage.getItem(attemptKey) || "0");
                  attempts = Number.isFinite(parsedAttempts) && parsedAttempts > 0 ? parsedAttempts : 0;
                }}
              }} catch (err) {{}}
            }}
            if (attempts >= maxBootstrapAttempts) {{
              if (cookieToken && storageToken && storageToken !== cookieToken) {{
                clearBrowserSessionToken(cookieToken);
                if (sessionStorage) {{
                  try {{
                    sessionStorage.setItem(attemptTokenKey, storageToken);
                    sessionStorage.setItem(attemptKey, "0");
                  }} catch (err) {{}}
                }}
                loc.reload();
                return;
              }}
              if (!hasEditorTarget) clearBrowserSessionToken(token);
              routeToAuthFallback();
              return;
            }}
            if (sessionStorage) {{
              try {{
                sessionStorage.setItem(attemptTokenKey, token);
                sessionStorage.setItem(attemptKey, String(attempts + 1));
              }} catch (err) {{}}
            }}

            const secure = loc.protocol === "https:" ? "; Secure" : "";
            targetDoc.cookie = cookieName + "=" + encodeURIComponent(token) +
              "; Max-Age={SESSION_PERSISTENCE_SECONDS}; Path=/; SameSite=Lax" + secure + cookieDomainAttribute(loc.hostname);
            if (localStorage) localStorage.setItem(storageKey, token);

            ["es_restore", "es_restore_miss", "es_auth_checked", "es_launch", "es_editor_auth_failed", "es_app_nav"].forEach((key) => url.searchParams.delete(key));
            url.searchParams.set("es_session", token);
            if (publicEntry) {{
              ["public", "route", "return_to", "tool_tab", "es_app_nav"].forEach((key) => url.searchParams.delete(key));
              url.searchParams.set("es_page", "Dashboard");
            }}
            const nextUrl = url.toString();
            if (nextUrl === loc.href) loc.reload();
            else loc.replace(nextUrl);
          }} catch (err) {{}}
        }})();
    """
    render_parent_script(bootstrap_runtime)


def auth_bootstrap_pending(route: Optional[Dict[str, Any]] = None) -> bool:
    if st.session_state.get("authenticated") and st.session_state.get("user"):
        return False
    if query_get(EDITOR_AUTH_FAILED_QUERY_PARAM) == "1" or st.session_state.get("_editor_auth_restore_failed"):
        return False
    route = route or {}
    route_name = safe_text(route.get("public") or route.get("route")).strip().lower()
    if route_name in PUBLIC_ROUTES:
        return False
    public_es_route = public_route_for_es_page(query_get("es_page"))
    if public_es_route and public_es_route in PUBLIC_ROUTES:
        return False
    route_page = normalize_es_page(route.get("page") or route.get("es_page"))
    if route_page in known_protected_es_pages():
        return True
    route_alias_page = normalize_es_page(ROUTE_PAGE_ALIASES.get(route_name, ""))
    if route_alias_page in known_protected_es_pages():
        return True
    if protected_route_requested():
        return True
    return (
        not route_query_has_explicit_target()
        and not query_get("public")
        and not query_get("route")
    )


def current_auth_state(route: Optional[Dict[str, Any]] = None) -> str:
    if is_authenticated():
        return AUTH_STATE_AUTHENTICATED
    if auth_bootstrap_pending(route):
        return AUTH_STATE_UNKNOWN
    return AUTH_STATE_UNAUTHENTICATED


def render_auth_unknown_state(route: Optional[Dict[str, Any]] = None) -> None:
    set_auth_debug_state(bool(browser_session_cookie()), False, "auth_unknown_resolving", route or {})
    render_browser_session_bootstrap(route)
    route = route or {}
    route_name = safe_text(route.get("public") or route.get("route")).strip().lower()
    route_page = normalize_es_page(route.get("page") or route.get("es_page"))
    route_alias_page = normalize_es_page(ROUTE_PAGE_ALIASES.get(route_name, ""))
    protected_fallback = (
        route_page in known_protected_es_pages()
        or route_alias_page in known_protected_es_pages()
        or protected_route_requested()
        or safe_text(route.get("es_editor") or query_get("es_editor"))
        or safe_text(route.get("job_id") or query_get("job_id"))
        or safe_text(route.get("review_id") or query_get("review_id"))
    )
    if protected_fallback:
        st.session_state["auth_return_to"] = encode_return_to()
        if editor_route_target_requested(route):
            render_auth_debug_panel(route, "auth_unknown_editor_restore")
            render_auth_transition_shell("Opening editor...")
        else:
            login_route = {"route": "login", "public": "login", "page": "Login", "es_page": "Login"}
            render_auth_debug_panel(login_route, "auth_unknown_login_fallback")
            render_auth_transition_shell("Opening your workspace...")
    else:
        landing_route = {"route": "landing", "public": "landing", "page": "Landing", "es_page": "Landing"}
        render_auth_debug_panel(landing_route, "auth_unknown_landing_fallback")
        render_auth_transition_shell("Opening CogniSweep...")
    st.stop()


def editor_route_target_requested(route: Optional[Dict[str, Any]] = None) -> bool:
    route = route or {}
    return bool(
        safe_text(route.get("es_editor") or query_get("es_editor"))
        or safe_text(route.get("job_id") or query_get("job_id"))
        or safe_text(route.get("review_id") or query_get("review_id"))
    )


