def landing_redirect_url_js(include_logout_marker: bool = False, include_signed_out_marker: bool = False) -> str:
    logout_marker_js = 'url.searchParams.set("es_logout", "1");' if include_logout_marker else 'url.searchParams.delete("es_logout");'
    signed_out_marker_js = f'url.searchParams.set("{LOGOUT_DONE_QUERY_PARAM}", "1");' if include_signed_out_marker else f'url.searchParams.delete("{LOGOUT_DONE_QUERY_PARAM}");'
    return f"""
            const url = new URL(loc.href);
            ["es_session", "es_restore", "es_restore_miss", "es_auth_checked", "es_launch", "es_editor_auth_failed", "es_editor", "job_id", "review_id", "task_id", "tool_tab", "es_app_nav", "route", "public", "return_to", "es_logout", "{LOGOUT_DONE_QUERY_PARAM}"].forEach((key) => url.searchParams.delete(key));
            url.searchParams.set("es_page", "Landing");
            {logout_marker_js}
            {signed_out_marker_js}
    """


def render_global_logout_listener() -> None:
    cookie_name_json = json.dumps(SESSION_COOKIE_NAME)
    storage_key_json = json.dumps(SESSION_STORAGE_KEY)
    route_storage_key_json = json.dumps(ROUTE_STORAGE_KEY)
    logout_key_json = json.dumps(LOGOUT_BROADCAST_KEY)
    login_key_json = json.dumps(LOGIN_BROADCAST_KEY)
    signed_out_param_json = json.dumps(LOGOUT_DONE_QUERY_PARAM)
    domain_js = browser_cookie_domain_js_function()
    logout_runtime = f"""
        (function() {{
          const listenerVersion = "auth-sync-v9-focus-logout-marker-2026-06-23";
          const previousListener = window.__errorsweepGlobalLogoutListener;
          if (previousListener && previousListener.version === listenerVersion) return;
          if (previousListener && typeof previousListener.dispose === "function") {{
            try {{ previousListener.dispose(); }} catch (err) {{}}
          }}
          const cleanup = [];
          const intervals = [];
          let broadcastChannel = null;
          const cookieName = {cookie_name_json};
          const storageKey = {storage_key_json};
          const routeStorageKey = {route_storage_key_json};
          const logoutKey = {logout_key_json};
          const loginKey = {login_key_json};
          const handledLogoutKey = logoutKey + ":handled";
          const handledLoginKey = loginKey + ":handled";
          const authShellSeenKey = storageKey + ":authenticated_shell_seen";
          const signedOutParam = {signed_out_param_json};
          const candidateWindows = [window.parent, window.top, window];
{domain_js}
          const firstWindow = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.location) return candidate;
              }} catch (err) {{}}
            }}
            return window;
          }};
          const firstDocument = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.document) return candidate.document;
              }} catch (err) {{}}
            }}
            return document;
          }};
          const firstStorage = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.localStorage) return candidate.localStorage;
              }} catch (err) {{}}
            }}
            try {{ return window.localStorage; }} catch (err) {{}}
            return null;
          }};
          const firstSessionStorage = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.sessionStorage) return candidate.sessionStorage;
              }} catch (err) {{}}
            }}
            try {{ return window.sessionStorage; }} catch (err) {{}}
            return null;
          }};
          const currentSessionValue = () => {{
            try {{
              const storage = firstStorage();
              return storage ? String(storage.getItem(storageKey) || "") : "";
            }} catch (err) {{}}
            return "";
          }};
          const currentLogoutValue = () => {{
            try {{
              const storage = firstStorage();
              return storage ? String(storage.getItem(logoutKey) || "") : "";
            }} catch (err) {{}}
            return "";
          }};
          const currentLoginValue = () => {{
            try {{
              const storage = firstStorage();
              return storage ? String(storage.getItem(loginKey) || "") : "";
            }} catch (err) {{}}
            return "";
          }};
          const handledValue = (key) => {{
            try {{
              const storage = firstSessionStorage();
              return storage ? String(storage.getItem(key) || "") : "";
            }} catch (err) {{}}
            return "";
          }};
          const markHandled = (key, value) => {{
            if (!value) return;
            try {{
              const storage = firstSessionStorage();
              if (storage) storage.setItem(key, String(value));
            }} catch (err) {{}}
          }};
          const authenticatedShellSeen = () => {{
            try {{
              const storage = firstSessionStorage();
              if (storage && storage.getItem(authShellSeenKey) === "1") return true;
            }} catch (err) {{}}
            try {{
              const doc = firstDocument();
              return !!(doc && doc.querySelector("#errorsweep-root-shell-marker,#errorsweep-editor-shell-marker"));
            }} catch (err) {{}}
            return false;
          }};
          let seenLogoutValue = handledValue(handledLogoutKey);
          let seenLoginValue = handledValue(handledLoginKey);
          let sawSessionToken = !!currentSessionValue();
          const publicEntryPages = new Set(["", "landing", "login", "signup", "sign up"]);
          const normalizedPage = (value) => String(value || "").replace(/[+_-]/g, " ").replace(/\\s+/g, " ").trim().toLowerCase();
          const currentPublicEntryUrl = (url) => {{
            const route = normalizedPage(url.searchParams.get("route") || url.searchParams.get("public"));
            const page = normalizedPage(url.searchParams.get("es_page"));
            const hasAnyRouteTarget = ["es_page", "es_editor", "job_id", "review_id", "route", "public", "return_to"].some((key) => url.searchParams.has(key));
            const hasProtectedTarget = (
              ["es_editor", "job_id", "review_id"].some((key) => url.searchParams.has(key))
              || route === "human review editor"
              || route === "human_review_editor"
              || (!!page && !publicEntryPages.has(page))
            );
            return !hasAnyRouteTarget || (!hasProtectedTarget && (publicEntryPages.has(route) || publicEntryPages.has(page)));
          }};
          const restoreAuthAndGoDashboard = (token) => {{
            if (!token) return;
            try {{
              const loc = firstWindow().location;
              const url = new URL(loc.href);
              if (!currentPublicEntryUrl(url)) return;
              const secure = loc.protocol === "https:" ? "; Secure" : "";
              firstDocument().cookie = cookieName + "=" + encodeURIComponent(token) +
                "; Max-Age={SESSION_PERSISTENCE_SECONDS}; Path=/; SameSite=Lax" + secure + cookieDomainAttribute(loc.hostname);
              try {{
                const storage = firstStorage();
                if (storage) storage.removeItem(logoutKey);
              }} catch (err) {{}}
              ["public", "route", "return_to", "es_restore", "es_restore_miss", "es_launch", "es_editor_auth_failed", "tool_tab", "es_app_nav"].forEach((key) => url.searchParams.delete(key));
              url.searchParams.set("es_page", "Dashboard");
              url.searchParams.set("es_session", token);
              if (loc.href !== url.toString()) loc.replace(url.toString());
            }} catch (err) {{}}
          }};
          const clearAuthAndGoLanding = (logoutValue) => {{
            const marker = String(logoutValue || currentLogoutValue() || "");
            try {{
              const loc = firstWindow().location;
              const secure = loc.protocol === "https:" ? "; Secure" : "";
              const targetDoc = firstDocument();
              targetDoc.cookie = cookieName + "=; Max-Age=0; Path=/; SameSite=Lax" + secure;
              targetDoc.cookie = cookieName + "=; Max-Age=0; Path=/; SameSite=Lax" + secure + cookieDomainAttribute(loc.hostname);
            }} catch (err) {{}}
            try {{
              const storage = firstStorage();
              if (storage) {{
                storage.removeItem(storageKey);
                storage.removeItem(routeStorageKey);
                storage.removeItem(loginKey);
              }}
            }} catch (err) {{}}
            try {{
              const scoped = firstSessionStorage();
              if (scoped) scoped.removeItem(authShellSeenKey);
            }} catch (err) {{}}
            try {{
              const loc = firstWindow().location;
              const currentUrl = new URL(loc.href);
              const alreadySignedOutLanding = (
                currentUrl.searchParams.get(signedOutParam) === "1"
                && normalizedPage(currentUrl.searchParams.get("es_page")) === "landing"
              );
              if (alreadySignedOutLanding) {{
                markHandled(handledLogoutKey, marker);
                return;
              }}
              markHandled(handledLogoutKey, marker);
              {landing_redirect_url_js(include_logout_marker=True, include_signed_out_marker=True)}
              if (loc.href !== url.toString()) loc.replace(url.toString());
            }} catch (err) {{}}
          }};
          const handleLogoutValue = (value) => {{
            const marker = String(value || "");
            if (!marker || marker === handledValue(handledLogoutKey)) return;
            seenLogoutValue = marker;
            const loc = firstWindow().location;
            const currentUrl = new URL(loc.href);
            const sessionValue = currentSessionValue();
            const alreadyPublicWithoutSession = !sessionValue && !sawSessionToken && !authenticatedShellSeen() && currentPublicEntryUrl(currentUrl);
            if (alreadyPublicWithoutSession) {{
              markHandled(handledLogoutKey, marker);
              return;
            }}
            clearAuthAndGoLanding(marker);
          }};
          const handleLoginValue = (value) => {{
            const marker = String(value || "");
            if (!marker || marker === handledValue(handledLoginKey)) return;
            seenLoginValue = marker;
            markHandled(handledLoginKey, marker);
            const token = currentSessionValue();
            if (token) restoreAuthAndGoDashboard(token);
          }};
          const checkLogoutMarker = () => {{
            const value = currentLogoutValue();
            if (value && value !== seenLogoutValue && value !== handledValue(handledLogoutKey)) {{
              handleLogoutValue(value);
              return;
            }}
            const loginValue = currentLoginValue();
            if (loginValue && loginValue !== seenLoginValue && loginValue !== handledValue(handledLoginKey)) {{
              handleLoginValue(loginValue);
              return;
            }}
            const sessionValue = currentSessionValue();
            if (sessionValue) {{
              sawSessionToken = true;
              return;
            }}
            if (sawSessionToken) clearAuthAndGoLanding(currentLogoutValue());
          }};
          const handleStorageEvent = (event) => {{
            if (event.key === logoutKey && event.newValue) {{
              handleLogoutValue(event.newValue);
              return;
            }}
            if (event.key === loginKey && event.newValue) {{
              handleLoginValue(event.newValue);
              return;
            }}
            if (event.key === storageKey && event.newValue && !currentLogoutValue()) restoreAuthAndGoDashboard(event.newValue);
          }};
          window.addEventListener("storage", handleStorageEvent);
          cleanup.push(() => window.removeEventListener("storage", handleStorageEvent));
          const hostWindow = firstWindow();
          if (hostWindow !== window) {{
            try {{
              hostWindow.addEventListener("storage", handleStorageEvent);
              cleanup.push(() => hostWindow.removeEventListener("storage", handleStorageEvent));
            }} catch (err) {{}}
          }}
          intervals.push(window.setInterval(checkLogoutMarker, 1200));
          if (hostWindow !== window) {{
            try {{ intervals.push(hostWindow.setInterval(checkLogoutMarker, 1200)); }} catch (err) {{}}
          }}
          try {{
            const targetDoc = firstDocument();
            targetDoc.addEventListener("visibilitychange", checkLogoutMarker);
            cleanup.push(() => targetDoc.removeEventListener("visibilitychange", checkLogoutMarker));
          }} catch (err) {{}}
          ["focus", "pageshow", "pointerdown", "keydown"].forEach((eventName) => {{
            try {{
              hostWindow.addEventListener(eventName, checkLogoutMarker, true);
              cleanup.push(() => hostWindow.removeEventListener(eventName, checkLogoutMarker, true));
            }} catch (err) {{}}
          }});
          try {{
            if ("BroadcastChannel" in window) {{
              broadcastChannel = new BroadcastChannel(logoutKey);
              broadcastChannel.onmessage = (event) => {{
                const value = event && event.data ? String(event.data.value || event.data || "") : String(Date.now());
                handleLogoutValue(value);
              }};
            }}
          }} catch (err) {{}}
          window.__errorsweepGlobalLogoutListener = {{
            version: listenerVersion,
            dispose: () => {{
              cleanup.forEach((fn) => {{ try {{ fn(); }} catch (err) {{}} }});
              intervals.forEach((id) => {{ try {{ window.clearInterval(id); hostWindow.clearInterval(id); }} catch (err) {{}} }});
              try {{ if (broadcastChannel) broadcastChannel.close(); }} catch (err) {{}}
            }},
          }};
          checkLogoutMarker();
        }})();
        """.strip()
    render_parent_script(logout_runtime, height=0)


def render_logout_bridge(redirect_to_landing: bool = True) -> None:
    cookie_name_json = json.dumps(SESSION_COOKIE_NAME)
    storage_key_json = json.dumps(SESSION_STORAGE_KEY)
    route_storage_key_json = json.dumps(ROUTE_STORAGE_KEY)
    logout_key_json = json.dumps(LOGOUT_BROADCAST_KEY)
    login_key_json = json.dumps(LOGIN_BROADCAST_KEY)
    redirect_to_landing_json = json.dumps(bool(redirect_to_landing))
    domain_js = browser_cookie_domain_js_function()
    logout_runtime = f"""
        (function() {{
          try {{
            const cookieName = {cookie_name_json};
            const storageKey = {storage_key_json};
            const routeStorageKey = {route_storage_key_json};
            const logoutKey = {logout_key_json};
            const loginKey = {login_key_json};
            const redirectToLanding = {redirect_to_landing_json};
            const logoutMarker = String(Date.now()) + ":" + Math.random().toString(36).slice(2);
            const handledLogoutKey = logoutKey + ":handled";
            const handledLoginKey = loginKey + ":handled";
            const authShellSeenKey = storageKey + ":authenticated_shell_seen";
            const candidateWindows = [window.parent, window.top, window];
{domain_js}
            const firstWindow = () => {{
              for (const candidate of candidateWindows) {{
                try {{
                  if (candidate && candidate.location) return candidate;
                }} catch (err) {{}}
              }}
              return window;
            }};
            const firstDocument = () => {{
              for (const candidate of candidateWindows) {{
                try {{
                  if (candidate && candidate.document) return candidate.document;
                }} catch (err) {{}}
              }}
              return document;
            }};
            const firstStorage = (kind) => {{
              for (const candidate of candidateWindows) {{
                try {{
                  if (candidate && candidate[kind]) return candidate[kind];
                }} catch (err) {{}}
              }}
              try {{ return window[kind]; }} catch (err) {{}}
              return null;
            }};
            let sharedStorage = null;
            const getSharedStorage = () => {{
              try {{
                if (!sharedStorage) sharedStorage = firstStorage("localStorage");
                return sharedStorage;
              }} catch (err) {{}}
              return null;
            }};
            const clearSharedSessionState = () => {{
              try {{
                const storage = getSharedStorage();
                if (storage) {{
                  storage.removeItem(storageKey);
                  storage.removeItem(routeStorageKey);
                  storage.removeItem(loginKey);
                }}
              }} catch (err) {{}}
            }};
            const broadcastLogout = (hostWindow) => {{
              try {{
                const storage = getSharedStorage();
                if (storage) storage.setItem(logoutKey, logoutMarker);
              }} catch (err) {{}}
              try {{
                const Channel = hostWindow.BroadcastChannel || window.BroadcastChannel;
                if (Channel) {{
                  const channel = new Channel(logoutKey);
                  channel.postMessage({{type: "logout", value: logoutMarker}});
                  channel.close();
                }}
              }} catch (err) {{}}
            }};
            const clearBrowserAuth = () => {{
              const hostWindow = firstWindow();
              const loc = hostWindow.location;
              const secure = loc.protocol === "https:" ? "; Secure" : "";
              try {{
                const targetDoc = firstDocument();
                targetDoc.cookie = cookieName + "=; Max-Age=0; Path=/; SameSite=Lax" + secure;
                targetDoc.cookie = cookieName + "=; Max-Age=0; Path=/; SameSite=Lax" + secure + cookieDomainAttribute(loc.hostname);
              }} catch (err) {{}}
              broadcastLogout(hostWindow);
              [900, 2400].forEach((delay) => window.setTimeout(clearSharedSessionState, delay));
              try {{
                const scoped = firstStorage("sessionStorage");
                if (scoped) {{
                  scoped.setItem(handledLogoutKey, logoutMarker);
                  scoped.removeItem(handledLoginKey);
                  scoped.removeItem(storageKey + "_bootstrap_attempted");
                  scoped.removeItem(storageKey + "_bootstrap_attempts");
                  scoped.removeItem(storageKey + "_bootstrap_token");
                  scoped.removeItem(storageKey + "_public_resume_attempts");
                  scoped.removeItem(storageKey + "_public_resume_token");
                  scoped.removeItem(authShellSeenKey);
                }}
              }} catch (err) {{}}
            }};
            const goLanding = () => {{
              clearBrowserAuth();
              if (!redirectToLanding) return;
              const loc = firstWindow().location;
              {landing_redirect_url_js(include_signed_out_marker=True)}
              const nextUrl = url.toString();
              if (loc.href !== nextUrl) loc.replace(nextUrl);
            }};
            goLanding();
            [150, 500, 1200].forEach((delay) => window.setTimeout(goLanding, delay));
          }} catch (err) {{}}
        }})();
    """
    render_parent_script(logout_runtime, height=1, scrolling=False)


def render_pending_logout_cleanup() -> None:
    if st.session_state.pop(LOGOUT_BROWSER_CLEANUP_KEY, False):
        render_logout_bridge(redirect_to_landing=False)


def login_launch_params(return_to: str, fallback_page: str = "Dashboard") -> Dict[str, str]:
    """Build the same-session route that should render after successful login."""
    fallback_page = normalize_es_page(fallback_page or "Dashboard")
    if public_route_for_es_page(fallback_page):
        fallback_page = "Dashboard"
    fallback = route_query_for_page(fallback_page)
    if not safe_text(return_to):
        return fallback

    parsed = parse_qs(return_to.lstrip("?"), keep_blank_values=False)
    flat = {key: safe_text(values[0]) for key, values in parsed.items() if values}
    route = flat.get("route", "").strip().lower()
    page = normalize_es_page(flat.get("es_page"))

    if route in {"login", "landing", "signup"} or public_route_for_es_page(page) in {"login", "landing", "signup"}:
        return fallback
    if route == "human_review_editor" or is_human_review_editor_page(page):
        review_id = safe_text(flat.get("review_id"))
        return {"es_editor": "human_review", "review_id": review_id} if review_id else fallback
    if flat.get("es_editor"):
        editor_params = {key: value for key, value in flat.items() if key in ROUTE_STORAGE_PARAM_KEYS and safe_text(value)}
        return editor_params or fallback
    if route in ROUTE_PAGE_ALIASES and ROUTE_PAGE_ALIASES[route]:
        page = normalize_es_page(ROUTE_PAGE_ALIASES[route])
        return route_query_for_page(page, {key: value for key, value in flat.items() if key != "route"})
    if flat.get("es_page") and page in known_protected_es_pages():
        return route_query_for_page(page, {key: value for key, value in flat.items() if key not in {"route", "es_page"}})
    return fallback


def render_logged_in_login_state(opened_elsewhere: bool = False) -> None:
    status_line = "Your CogniSweep session is active."
    st.success("You are logged in")
    st.markdown(f"**{status_line}**")
    c1, c2 = st.columns(2)
    if c1.button("Open Dashboard", key="logged_in_open_dashboard", use_container_width=True):
        navigate_es_page("Dashboard")
    if c2.button("Logout", key="logged_in_logout", use_container_width=True):
        logout()
    st.markdown(
        dedent(f"""
        <section class="es-auth-shell es-login-status-card" aria-label="Logged in">
          <div class="es-lp-brand">
            <div class="es-lp-logo" aria-hidden="true"></div>
            <div>
              <div class="es-lp-brand-name">You are logged in</div>
              <div style="color:rgba(255,255,255,.68);font-weight:700;margin-top:4px;">{escape(status_line)}</div>
            </div>
          </div>
        </section>
        """).strip(),
        unsafe_allow_html=True,
    )


def login_user(email: str, role: str, account_type: str, workspace: str = "Demo Workspace", *, sync_route_storage: bool = True) -> None:
    stored_user = find_user_by_email(email) or {}
    resolved_account_type = "owner" if safe_text(account_type).lower() == "owner" else safe_text(stored_user.get("account_type") or account_type or "workspace")
    login_time = datetime.now(timezone.utc)
    session_started_at_ms = session_epoch_ms()
    user = {
        "email": email,
        "role": safe_text(stored_user.get("role") or role or "User"),
        "account_type": resolved_account_type,
        "workspace": safe_text(stored_user.get("workspace") or workspace or "Demo Workspace"),
        "login_at": login_time.isoformat(),
        SESSION_STARTED_AT_MS_FIELD: session_started_at_ms,
    }
    user.update(safe_user_session_record(stored_user))
    user["account_type"] = resolved_account_type
    user["login_at"] = login_time.isoformat()
    user[SESSION_STARTED_AT_MS_FIELD] = session_started_at_ms
    return_to = query_get("return_to") or safe_text(st.session_state.get("auth_return_to", ""))
    target_page = "Dashboard"
    if return_to:
        parsed_return_to = parse_qs(return_to.lstrip("?"), keep_blank_values=False)
        target_page = normalize_es_page((parsed_return_to.get("es_page") or ["Dashboard"])[0])
        if public_route_for_es_page(target_page) == "login":
            target_page = "Dashboard"
    st.session_state["user"] = user
    st.session_state["authenticated"] = True
    session_token = signed_session_token_for_user(user)
    st.session_state["_pending_session_cookie"] = session_token
    launch_params = login_launch_params(return_to, target_page)
    launch_page = normalize_es_page(launch_params.get("es_page") or target_page or "Dashboard")
    if launch_params.get("es_page"):
        launch_params["es_page"] = launch_page
    launch_params[SESSION_HANDOFF_QUERY_PARAM] = session_token
    st.session_state["es_page"] = launch_page
    st.session_state.page = launch_page if launch_page in known_protected_es_pages() else "Dashboard"
    if launch_params.get("review_id"):
        st.session_state["active_review_session_id"] = launch_params["review_id"]
    st.session_state["current_route"] = {"page": st.session_state.page, **launch_params}
    set_route_query(launch_params, sync_storage=sync_route_storage)
    query_clear("public")
    query_clear("return_to")
    query_clear(AUTH_CHECK_QUERY_PARAM)
    query_clear(EDITOR_LAUNCH_QUERY_PARAM)
    query_clear(EDITOR_AUTH_FAILED_QUERY_PARAM)
    query_clear("es_restore")
    query_clear("es_restore_miss")


def render_login_success_handoff(target_route: Dict[str, Any]) -> None:
    """Give the browser one stable render pass to persist the session token."""
    user = st.session_state.get("user") or {}
    if not user:
        return
    token = signed_session_token_for_user(user)
    target_params = protected_query_params_from_route(target_route)
    target_params[SESSION_HANDOFF_QUERY_PARAM] = token
    if query_get("debug_auth") == "1":
        target_params["debug_auth"] = "1"
    target_url = "?" + urlencode(target_params)
    st.session_state["_pending_session_cookie"] = token
    sync_component_session_cookie(token)
    set_auth_debug_state(
        bool(browser_session_cookie()),
        True,
        "login_success_handoff",
        target_route,
        handoff_token_found=True,
    )
    render_auth_debug_panel(target_route, "login_success_handoff")
    render_auth_transition_shell("Opening your workspace...")
    st.markdown(
        f'<a href="{escape(target_url)}" target="_self">Continue to Dashboard</a>',
        unsafe_allow_html=True,
    )
    name_json = json.dumps(SESSION_COOKIE_NAME)
    storage_key_json = json.dumps(SESSION_STORAGE_KEY)
    route_storage_key_json = json.dumps(ROUTE_STORAGE_KEY)
    logout_key_json = json.dumps(LOGOUT_BROADCAST_KEY)
    login_key_json = json.dumps(LOGIN_BROADCAST_KEY)
    token_json = json.dumps(token)
    target_url_json = json.dumps(target_url)
    domain_js = browser_cookie_domain_js_function()
    render_parent_script(
        f"""
        (() => {{
          const cookieName = {name_json};
          const storageKey = {storage_key_json};
          const routeStorageKey = {route_storage_key_json};
          const logoutKey = {logout_key_json};
          const loginKey = {login_key_json};
          const token = {token_json};
          const targetUrl = {target_url_json};
          const loginMarker = String(Date.now()) + ":" + Math.random().toString(36).slice(2);
          const handledLogoutKey = logoutKey + ":handled";
          const handledLoginKey = loginKey + ":handled";
          const candidateWindows = [window.parent, window.top, window];
{domain_js}
          const firstWindow = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.location) return candidate;
              }} catch (err) {{}}
            }}
            return window;
          }};
          const firstDocument = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.document) return candidate.document;
              }} catch (err) {{}}
            }}
            return document;
          }};
          const firstStorage = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.localStorage) return candidate.localStorage;
              }} catch (err) {{}}
            }}
            try {{ return window.localStorage; }} catch (err) {{}}
            return null;
          }};
          const firstSessionStorage = () => {{
            for (const candidate of candidateWindows) {{
              try {{
                if (candidate && candidate.sessionStorage) return candidate.sessionStorage;
              }} catch (err) {{}}
            }}
            try {{ return window.sessionStorage; }} catch (err) {{}}
            return null;
          }};
          const persistSession = () => {{
            const hostWindow = firstWindow();
            const targetDoc = firstDocument();
            const secure = hostWindow.location.protocol === "https:" ? "; Secure" : "";
            try {{
              targetDoc.cookie = cookieName + "=" + encodeURIComponent(token) +
                "; Max-Age={SESSION_PERSISTENCE_SECONDS}; Path=/; SameSite=Lax" + secure + cookieDomainAttribute(hostWindow.location.hostname);
            }} catch (err) {{}}
            try {{
              const storage = firstStorage();
              if (storage) {{
                storage.removeItem(logoutKey);
                storage.setItem(storageKey, token);
                storage.setItem(routeStorageKey, JSON.stringify({{"es_page": "Dashboard"}}));
                storage.setItem(loginKey, loginMarker);
              }}
            }} catch (err) {{}}
            try {{
              const scoped = firstSessionStorage();
              if (scoped) {{
                scoped.removeItem(handledLogoutKey);
                scoped.setItem(handledLoginKey, loginMarker);
              }}
            }} catch (err) {{}}
          }};
          persistSession();
          [50, 200, 500].forEach((delay) => window.setTimeout(persistSession, delay));
          window.setTimeout(() => {{
            try {{ firstWindow().location.replace(targetUrl); }}
            catch (err) {{ window.location.href = targetUrl; }}
          }}, 180);
        }})();
        """.strip(),
        height=0,
    )
    st.stop()


def ensure_authenticated_session_query_fallback(route: Optional[Dict[str, Any]] = None) -> None:
    """Keep a signed URL fallback when Streamlit Cloud cannot see browser cookies."""
    if not (st.session_state.get("authenticated") and st.session_state.get("user")):
        return
    route = route or {}
    public_route = safe_text(route.get("public") or route.get("route")).strip().lower()
    if public_route in PUBLIC_ROUTES and public_route not in AUTHENTICATED_PUBLIC_ENTRY_ROUTES:
        return
    if browser_session_cookie() or query_get(SESSION_HANDOFF_QUERY_PARAM):
        return
    token = signed_session_token_for_user(st.session_state.get("user") or {})
    params = protected_query_params_from_route(route or authenticated_shell_route_from_session())
    params[SESSION_HANDOFF_QUERY_PARAM] = token
    if query_get(BROWSER_TIMEZONE_QUERY_PARAM):
        params[BROWSER_TIMEZONE_QUERY_PARAM] = query_get(BROWSER_TIMEZONE_QUERY_PARAM)
    if query_get("debug_auth") == "1":
        params["debug_auth"] = "1"
    attach_key = "_session_query_fallback_attached"
    attempts_key = "_session_query_fallback_attach_attempts"
    signature = json.dumps(params, sort_keys=True)
    attempts = int(st.session_state.get(attempts_key) or 0) if st.session_state.get(attach_key) == signature else 0
    if attempts >= 3:
        return
    st.session_state[attach_key] = signature
    st.session_state[attempts_key] = attempts + 1
    set_route_query(params, sync_storage=False)
    st.rerun()


LOGIN_EMAIL_KEY = "unified_login_email"
LOGIN_PASSWORD_KEY = "unified_login_password"
LOGIN_ACCEPT_KEY = "unified_login_compliance_ack"
LOGIN_FEEDBACK_KEY = "_unified_login_feedback"
LOGIN_SUCCESS_PENDING_KEY = "_login_success_dashboard_pending"


def set_login_feedback(level: str, message: str, caption: str = "") -> None:
    st.session_state[LOGIN_FEEDBACK_KEY] = {
        "level": safe_text(level) or "error",
        "message": safe_text(message),
        "caption": safe_text(caption),
    }


def handle_unified_login_submit() -> None:
    """Authenticate before the post-submit script pass renders public Login UI."""
    st.session_state.pop(LOGIN_FEEDBACK_KEY, None)
    clean_email = safe_text(st.session_state.get(LOGIN_EMAIL_KEY, "")).strip()
    password = st.session_state.get(LOGIN_PASSWORD_KEY, "") or ""
    accepted = bool(st.session_state.get(LOGIN_ACCEPT_KEY, False))

    if not clean_email or not password:
        set_login_feedback("error", "Please enter your email and password.")
        return
    if not accepted:
        set_login_feedback("error", "Please accept the workspace compliance terms before signing in.")
        return

    allowed_attempt, throttle_message = consume_abuse_attempt("workspace_login", clean_email)
    if not allowed_attempt:
        set_login_feedback("error", throttle_message)
        return

    owner_user = unlimited_access_email() or configured_owner_username(local_default=True)
    owner_password_hash = unlimited_access_password_hash()
    owner_secret_available = bool(owner_password_hash or password_configured("ERRORSWEEP_OWNER_PASSWORD_HASH", "ERRORSWEEP_OWNER_PASSWORD"))
    owner_is_configured = bool(owner_user) and owner_secret_available
    bootstrap_user = secret("ERRORSWEEP_USER_USERNAME", "user@cognisweep.local")
    bootstrap_is_configured = password_configured("ERRORSWEEP_USER_PASSWORD_HASH", "ERRORSWEEP_USER_PASSWORD")
    default_role = secret("ERRORSWEEP_DEFAULT_USER_ROLE", "Workspace Owner")
    email_key = clean_email.lower()

    owner_email_matches = bool(owner_user) and hmac.compare_digest(email_key, owner_user)
    owner_password_ok = False
    if owner_password_hash:
        owner_password_ok = verify_password(password, owner_password_hash)
    elif owner_secret_available:
        owner_password_ok = verify_login_password(password, "ERRORSWEEP_OWNER_PASSWORD_HASH", "ERRORSWEEP_OWNER_PASSWORD")

    if owner_email_matches and not owner_secret_available:
        LOGGER.error("Platform owner login attempted but ERRORSWEEP_OWNER_PASSWORD_HASH is not configured.")
        set_login_feedback("error", "Platform owner login is not configured. Set ERRORSWEEP_OWNER_PASSWORD_HASH in Streamlit secrets.")
        return
    if owner_email_matches and owner_secret_available and not owner_password_ok:
        LOGGER.warning("Platform owner login password mismatch for the configured owner account.")
        set_login_feedback(
            "error",
            "Platform owner password does not match the configured owner hash. Regenerate ERRORSWEEP_OWNER_PASSWORD_HASH in Streamlit secrets for the current password.",
        )
        return

    if owner_is_configured and hmac.compare_digest(email_key, owner_user) and owner_password_ok:
        clear_abuse_attempts("workspace_login", clean_email)
        st.session_state[LOGIN_SUCCESS_PENDING_KEY] = True
        ensure_unlimited_access_account(owner_user, owner_password_hash)
        login_user(owner_user, "Platform Owner", "owner", "Platform", sync_route_storage=False)
        record_consent_acceptance(owner_user, "Platform Owner", "owner", "Platform", "unified_login")
        add_audit("Unified owner login", owner_user)
        return

    if bootstrap_is_configured and hmac.compare_digest(clean_email, bootstrap_user.strip()) and verify_login_password(password, "ERRORSWEEP_USER_PASSWORD_HASH", "ERRORSWEEP_USER_PASSWORD"):
        configured_workspace = secret("ERRORSWEEP_ORG_NAME", "Demo Workspace")
        clear_abuse_attempts("workspace_login", clean_email)
        st.session_state[LOGIN_SUCCESS_PENDING_KEY] = True
        login_user(clean_email, default_role, "workspace", configured_workspace, sync_route_storage=False)
        record_consent_acceptance(clean_email, default_role, "workspace", configured_workspace, "unified_login")
        add_audit("Unified workspace login", clean_email)
        return

    matched = find_user_by_email(clean_email)
    if matched and safe_text(matched.get("status", "Active")).lower() not in {"active", "invited"}:
        set_login_feedback("error", "This account is not active. Contact your workspace owner or CogniSweep management.")
        return
    if matched and verify_password(password, safe_text(matched.get("password_hash", ""))):
        if is_production_mode() and not bool(matched.get("email_verified")):
            verify_url = queue_verification_email(clean_email, matched.get("workspace", "Demo Workspace"))
            caption = f"Local verification link: {verify_url}" if email_provider_label() == "not_configured" else ""
            set_login_feedback("warning", "Please verify your email before signing in. A verification link was added to the notification outbox.", caption)
            return
        matched_role = safe_text(matched.get("role") or default_role or "User")
        matched_workspace = safe_text(matched.get("workspace") or "Demo Workspace")
        account_type = safe_text(matched.get("account_type")) or ("owner" if matched_role == "Platform Owner" or matched_workspace == "Platform" else "workspace")
        clear_abuse_attempts("workspace_login", clean_email)
        st.session_state[LOGIN_SUCCESS_PENDING_KEY] = True
        login_user(clean_email, matched_role, account_type, matched_workspace, sync_route_storage=False)
        record_consent_acceptance(clean_email, matched_role, account_type, matched_workspace, "unified_login")
        add_audit("Unified login", clean_email)
        return

    set_login_feedback("error", "Invalid email or password.")


def logout() -> None:
    logout_user = st.session_state.get("user") or {}
    record_session_logout(logout_user)
    st.session_state.pop("user", None)
    st.session_state.pop("authenticated", None)
    st.session_state.pop("_saas_state_hydrated", None)
    st.session_state.pop(LOGIN_SUCCESS_PENDING_KEY, None)
    st.session_state.pop("_session_query_fallback_attached", None)
    st.session_state.pop("_session_query_fallback_attach_attempts", None)
    st.session_state["_clear_session_cookie"] = True
    st.session_state[LOGOUT_BROWSER_CLEANUP_KEY] = True
    st.session_state[LOGOUT_SKIP_RESTORE_KEY] = True
    for key in ("es_session", "es_restore", AUTH_CHECK_QUERY_PARAM, EDITOR_LAUNCH_QUERY_PARAM, EDITOR_AUTH_FAILED_QUERY_PARAM, EDITOR_SUBMITTED_QUERY_PARAM, EDITOR_SUBMITTED_TYPE_QUERY_PARAM, "es_page", "es_editor", "job_id", "review_id", "task_id", "tool_tab", "es_app_nav", "route", "public", "return_to", "es_logout", LOGOUT_DONE_QUERY_PARAM):
        query_clear(key)
    query_set("es_page", "Landing")
    query_set(LOGOUT_DONE_QUERY_PARAM, "1")
    st.rerun()


