def ensure_unlimited_access_account(owner_email: str = "", password_hash: str = "") -> None:
    owner_email = early_safe_text(owner_email or unlimited_access_email()).lower()
    if not owner_email:
        LOGGER.warning("Unlimited owner account is not configured; set ERRORSWEEP_OWNER_USERNAME and ERRORSWEEP_OWNER_PASSWORD_HASH.")
        return
    password_hash = early_safe_text(password_hash or unlimited_access_password_hash())
    user_record = {
        "email": owner_email,
        "workspace": "Platform",
        "role": "Platform Owner",
        "account_type": "platform",
        "plan": "Unlimited",
        "status": "Active",
        "email_verified": True,
    }
    if password_hash:
        user_record["password_hash"] = password_hash
    workspace_record = {
        "workspace": UNLIMITED_ACCESS_WORKSPACE,
        "owner": owner_email,
        "plan": "Unlimited",
        "status": "Active",
        "users": 1,
        "jobs": 0,
    }
    subscription_record = {
        "workspace": UNLIMITED_ACCESS_WORKSPACE,
        "plan": "Unlimited",
        "status": "Active",
        "billing_cycle": "internal",
        "currency": "INR",
        "base_amount": 0,
        "included_segments": 1_000_000_000,
        "included_characters": 1_000_000_000_000,
        "included_seats": 1_000_000,
        "provider": "internal",
    }

    def upsert_by(items_key: str, record: Dict[str, Any], match_key: str) -> None:
        rows = st.session_state.setdefault(items_key, [])
        wanted = str(record.get(match_key) or "").strip().lower()
        for idx, item in enumerate(rows):
            if str(item.get(match_key) or "").strip().lower() == wanted:
                rows[idx] = {**item, **record}
                break
        else:
            rows.insert(0, record)

    upsert_by("users", user_record, "email")
    upsert_by("workspaces", workspace_record, "workspace")
    upsert_by("subscriptions", subscription_record, "workspace")


init_state()
if unlimited_access_configured():
    ensure_unlimited_access_account()
trim_session_collections()


