def page_route(page: str) -> None:
    st.session_state.page = page
    query_set("es_page", page)
    st.rerun()


def public_page_link(page: str) -> str:
    route = public_route_for_es_page(page) or es_page_alias_key(page)
    page_name = PUBLIC_ROUTE_PAGE_NAMES.get(route, safe_text(page).strip().title() or "Landing")
    return "?" + urlencode({"es_page": page_name})


def public_login_link_target() -> str:
    return 'target="_self"'


def route_query_for_page(page: str, extra: Optional[Dict[str, str]] = None) -> Dict[str, str]:
    params = {"es_page": normalize_es_page(page), "es_app_nav": "1"}
    for key, value in (extra or {}).items():
        if key != "route" and safe_text(value):
            params[key] = safe_text(value)
    return params


def app_page_link(page: str, extra: Optional[Dict[str, str]] = None) -> str:
    return "?" + urlencode(route_query_for_page(page, extra))


def editor_back_link(page: str, extra: Optional[Dict[str, str]] = None) -> str:
    params = route_query_for_page(page, extra)
    user = current_user() if st.session_state.get("authenticated") and st.session_state.get("user") else {}
    if user:
        params[SESSION_HANDOFF_QUERY_PARAM] = signed_session_token_for_user(user)
    return "?" + urlencode(params)


def native_nav_key(prefix: str, page: str, extra: Optional[Dict[str, str]] = None) -> str:
    slug = re.sub(r"[^a-z0-9]+", "_", es_page_alias_key(page)).strip("_") or "page"
    clean_extra = {key: safe_text(value) for key, value in (extra or {}).items() if safe_text(value)}
    if clean_extra:
        payload = urlencode(sorted(clean_extra.items()))
        slug = f"{slug}_{hashlib.sha1(payload.encode('utf-8')).hexdigest()[:8]}"
    clean_prefix = re.sub(r"[^a-z0-9_]+", "_", safe_text(prefix).lower()).strip("_") or "nav"
    return f"{clean_prefix}_native_nav_{slug}"


def app_nav_attr(key: str, href: str = "") -> str:
    attrs = f'data-es-app-nav="{escape(key, quote=True)}"'
    if safe_text(href):
        attrs += f' data-es-app-href="{escape(href, quote=True)}"'
    return attrs


def app_nav_target_from_href(
    targets: List[Dict[str, Any]],
    prefix: str,
    href: str,
    label: str = "",
) -> str:
    """Register a same-app protected href for no-reload navigation."""
    href = safe_text(href)
    if not href.startswith("?"):
        return ""
    parsed = parse_qs(href.lstrip("?"), keep_blank_values=False)
    page = normalize_es_page((parsed.get("es_page") or [""])[0])
    if page not in known_protected_es_pages():
        return ""
    extra = {
        key: safe_text(values[0])
        for key, values in parsed.items()
        if key != "es_page" and values and safe_text(values[0])
    }
    key = native_nav_key(prefix, page, extra)
    targets.append({"key": key, "page": page, "extra": extra, "label": label or page})
    return app_nav_attr(key, href)


def render_app_navigation_targets(targets: List[Dict[str, Any]], prefix: str) -> None:
    """Hidden callbacks used by the HTML shell to navigate without a full app reload."""
    unique_targets: Dict[str, Dict[str, Any]] = {}
    for target in targets:
        key = safe_text(target.get("key"))
        page = normalize_es_page(target.get("page"))
        if not key or not page:
            continue
        unique_targets[key] = {
            "key": key,
            "page": page,
            "extra": {k: safe_text(v) for k, v in (target.get("extra") or {}).items() if safe_text(v)},
            "label": safe_text(target.get("label") or page),
        }
    if not unique_targets:
        return
    with st.container(key=f"{prefix}_app_nav_targets", gap=None):
        for target in unique_targets.values():
            if st.button(f"Route {target['label']}", key=target["key"]):
                navigate_es_page(target["page"], **target["extra"])


def render_app_navigation_bridge() -> None:
    render_parent_script(
        """
        (() => {
          if (!document || !document.body) return;
          const cssEscape = (value) => {
            if (window.CSS && window.CSS.escape) return window.CSS.escape(value);
            return String(value || "").replace(/[^a-zA-Z0-9_-]/g, "\\$&");
          };
          const clickTarget = (key) => {
            if (!key) return false;
            const wrapper = document.querySelector(".st-key-" + cssEscape(key));
            const button = wrapper && (
              wrapper.querySelector('[data-testid="stButton"] button') ||
              wrapper.querySelector(".stButton button") ||
              wrapper.querySelector("button")
            );
            if (!button || button.disabled) return false;
            window.setTimeout(() => button.click(), 0);
            return true;
          };
          const sameOriginUrl = (href) => {
            try {
              const url = new URL(href, window.location.href);
              if (url.origin !== window.location.origin) return null;
              return url;
            } catch (err) {
              return null;
            }
          };
          const handleClick = (event) => {
            const trigger = event.target && event.target.closest ? event.target.closest("[data-es-app-nav]") : null;
            if (!trigger) return;
            const target = String(trigger.getAttribute("target") || "_self").toLowerCase();
            if (target && target !== "_self") return;
            const key = trigger.getAttribute("data-es-app-nav");
            const href = trigger.getAttribute("data-es-app-href") || trigger.href || trigger.getAttribute("href") || "";
            return window.__errorsweepAppNavigate(event, key, href);
          };
          window.__errorsweepAppNavigate = (event, key, href) => {
            const url = sameOriginUrl(href || "");
            if (!url || !key) return true;
            const trigger = event && event.target && event.target.closest ? event.target.closest("[data-es-app-nav]") : null;
            const target = trigger ? String(trigger.getAttribute("target") || "_self").toLowerCase() : "_self";
            if (target && target !== "_self") return true;
            event.preventDefault();
            event.stopPropagation();
            if (event.stopImmediatePropagation) event.stopImmediatePropagation();
            const handled = clickTarget(key);
            window.__errorsweepLastAppNav = {
              key,
              href: url.toString(),
              handled,
              at: Date.now()
            };
            if (!handled) {
              window.location.href = url.toString();
            }
            return false;
          };
          const bindTriggerListeners = () => {
            Array.from(document.querySelectorAll("[data-es-app-nav]")).forEach((trigger) => {
              if (trigger.__errorsweepAppNavHandler) {
                trigger.removeEventListener("click", trigger.__errorsweepAppNavHandler, true);
              }
              trigger.__errorsweepAppNavHandler = handleClick;
              trigger.addEventListener("click", handleClick, true);
            });
            window.__errorsweepAppNavBoundAt = Date.now();
            window.__errorsweepAppNavParentRuntime = true;
          };
          const findCurrentTarget = () => {
            const current = new URL(window.location.href);
            const currentSearch = current.searchParams.toString();
            const triggers = Array.from(document.querySelectorAll("[data-es-app-nav]"));
            return triggers.find((trigger) => {
              const url = sameOriginUrl(trigger.getAttribute("data-es-app-href") || trigger.href || trigger.getAttribute("href") || "");
              return url && url.searchParams.toString() === currentSearch;
            });
          };
          const handlePopState = () => {
            const anchor = findCurrentTarget();
            const key = anchor && anchor.getAttribute("data-es-app-nav");
            const handled = key ? clickTarget(key) : false;
            window.__errorsweepLastAppNav = {
              key: key || "",
              href: window.location.href,
              handled,
              popstate: true,
              at: Date.now()
            };
            if (handled) return;
            window.location.reload();
          };
          if (document.__errorsweepAppNavClick) {
            document.removeEventListener("click", document.__errorsweepAppNavClick, true);
          }
          document.__errorsweepAppNavClick = handleClick;
          document.addEventListener("click", handleClick, true);
          if (document.__errorsweepAppNavObserver) {
            document.__errorsweepAppNavObserver.disconnect();
          }
          let bindTimer = null;
          document.__errorsweepAppNavObserver = new MutationObserver(() => {
            if (bindTimer) window.clearTimeout(bindTimer);
            bindTimer = window.setTimeout(bindTriggerListeners, 0);
          });
          document.__errorsweepAppNavObserver.observe(document.body, { childList: true, subtree: true });
          [0, 50, 250, 1000].forEach((delay) => window.setTimeout(bindTriggerListeners, delay));
          if (window.__errorsweepAppNavPopState) {
            window.removeEventListener("popstate", window.__errorsweepAppNavPopState);
          }
          window.__errorsweepAppNavPopState = handlePopState;
          window.addEventListener("popstate", handlePopState);
        })();
        """,
        height=0,
        scrolling=False,
    )


def human_review_editor_link(review_id: str) -> str:
    review_id = safe_text(review_id)
    return "?" + urlencode({"es_editor": "human_review", "review_id": review_id}) if review_id else app_page_link("Human Review Editor")


def task_monitor_link(task_id: str) -> str:
    return app_page_link("Jobs", {"task_id": task_id})


def set_route_query(params: Dict[str, str], *, sync_storage: bool = True) -> None:
    params = {key: safe_text(value) for key, value in params.items() if key != "route" and safe_text(value)}
    for stale in ("public", "return_to", "route", "es_page", "es_editor", "job_id", "review_id", "task_id", "tool_tab", "es_panel", "es_app_nav", "es_session", "es_restore", "es_restore_miss", EDITOR_LAUNCH_QUERY_PARAM, EDITOR_AUTH_FAILED_QUERY_PARAM, EDITOR_SUBMITTED_QUERY_PARAM, EDITOR_SUBMITTED_TYPE_QUERY_PARAM, AUTH_CHECK_QUERY_PARAM):
        if stale not in params:
            if stale == SESSION_HANDOFF_QUERY_PARAM and query_get(SESSION_HANDOFF_QUERY_PARAM) and not browser_session_cookie():
                continue
            query_clear(stale)
    for key, value in params.items():
        query_set(key, value)
    if sync_storage:
        sync_browser_route_state(params)


def public_route_for_es_page(page: str) -> str:
    if not safe_text(page):
        return ""
    normalized_page = normalize_es_page(page)
    for route, page_name in PUBLIC_ROUTE_PAGE_NAMES.items():
        if normalized_page == page_name:
            return route
    return PUBLIC_ES_PAGE_ALIASES.get(es_page_alias_key(page), "")


def authenticated_public_entry_route(route: Dict[str, Any]) -> bool:
    """Authenticated users should enter the product, not stay on auth pages."""
    public_route = safe_text(route.get("public") or route.get("route")).strip().lower()
    return public_route in AUTHENTICATED_PUBLIC_ENTRY_ROUTES


def authenticated_login_handoff_route(route: Dict[str, Any]) -> bool:
    """Login no longer launches a separate dashboard tab, so there is no handoff route."""
    return False


def authenticated_shell_route_from_session(default_page: str = "Dashboard") -> Dict[str, str]:
    """Build a protected route from session state when query params are stale."""
    current = st.session_state.get("current_route")
    if isinstance(current, dict):
        editor_type = safe_text(current.get("es_editor"))
        page = normalize_es_page(current.get("es_page") or current.get("page") or "")
        if editor_type:
            params = {
                key: safe_text(current.get(key))
                for key in ROUTE_STORAGE_PARAM_KEYS
                if safe_text(current.get(key))
            }
            params["es_editor"] = editor_type
            return {"route": "human_review_editor" if editor_type == "human_review" else "cat_editor", **params}
        if is_human_review_editor_page(page):
            review_id = safe_text(current.get("review_id"))
            if review_id:
                return {"route": "human_review_editor", "es_editor": "human_review", "review_id": review_id}
            return {"route": PAGE_ROUTE_SLUGS.get(default_page) or es_page_alias_key(default_page) or "dashboard", "page": normalize_es_page(default_page), "es_page": normalize_es_page(default_page)}
        if page in known_protected_es_pages() and not public_route_for_es_page(page):
            route_slug = safe_text(current.get("route")).strip().lower()
            if route_slug in PUBLIC_ROUTES or not route_slug:
                route_slug = PAGE_ROUTE_SLUGS.get(page) or es_page_alias_key(page) or "dashboard"
            route = {"route": route_slug, "page": page, "es_page": page}
            for key in ("job_id", "review_id"):
                value = safe_text(current.get(key))
                if value:
                    route[key] = value
            return route

    page = normalize_es_page(st.session_state.get("page") or st.session_state.get("es_page") or default_page)
    if public_route_for_es_page(page) or page not in known_protected_es_pages():
        page = normalize_es_page(default_page)
    return {"route": PAGE_ROUTE_SLUGS.get(page) or es_page_alias_key(page) or "dashboard", "page": page, "es_page": page}


def protected_query_params_from_route(route: Dict[str, Any]) -> Dict[str, str]:
    params = {
        key: safe_text(route.get(key))
        for key in ROUTE_STORAGE_PARAM_KEYS
        if safe_text(route.get(key))
    }
    if params.get("es_editor") == "human_review" and params.get("review_id"):
        params.pop("es_page", None)
        return params
    page = normalize_es_page(params.get("es_page") or route.get("page") or "Dashboard")
    if not page or public_route_for_es_page(page):
        page = "Dashboard"
    params["es_page"] = page
    return params


def browser_route_storage_params(params: Optional[Dict[str, Any]] = None) -> Dict[str, str]:
    params = params or {}
    stored: Dict[str, str] = {}
    raw_page = safe_text(params.get("es_page") or params.get("page"))
    page = normalize_es_page(raw_page) if raw_page else ""
    if page and not public_route_for_es_page(page) and page in known_protected_es_pages():
        stored["es_page"] = page
    for key in ("es_editor", "job_id", "review_id"):
        value = safe_text(params.get(key) or query_get(key))
        if value:
            stored[key] = value
    if stored.get("es_page") or (stored.get("es_editor") and (stored.get("job_id") or stored.get("review_id"))):
        return stored
    return {}


def sync_browser_route_state(params: Optional[Dict[str, Any]] = None, clear: bool = False) -> None:
    stored = {} if clear else browser_route_storage_params(params)
    if not stored and not clear:
        return
    storage_key_json = json.dumps(ROUTE_STORAGE_KEY)
    value_json = json.dumps(stored)
    should_clear_json = json.dumps(bool(clear))
    components.html(
        f"""
        <script>
        (function() {{
          try {{
            const routeStorageKey = {storage_key_json};
            const value = {value_json};
            const shouldClear = {should_clear_json};
            const storage = (window.parent && window.parent.localStorage) ? window.parent.localStorage : window.localStorage;
            if (shouldClear) storage.removeItem(routeStorageKey);
            else storage.setItem(routeStorageKey, JSON.stringify(value));
          }} catch (err) {{}}
        }})();
        </script>
        """,
        height=0,
    )


def render_route_restore_bridge() -> None:
    route_storage_key_json = json.dumps(ROUTE_STORAGE_KEY)
    route_blocking_keys_json = json.dumps(list(ROUTE_RESTORE_BLOCKING_QUERY_KEYS))
    route_param_keys_json = json.dumps(list(ROUTE_STORAGE_PARAM_KEYS))
    components.html(
        f"""
        <script>
        (function() {{
          try {{
            const routeStorageKey = {route_storage_key_json};
            const routeBlockingKeys = {route_blocking_keys_json};
            const routeParamKeys = {route_param_keys_json};
            const storage = (window.parent && window.parent.localStorage) ? window.parent.localStorage : window.localStorage;
            const savedRoute = storage.getItem(routeStorageKey);
            if (!savedRoute) return;
            const loc = window.parent ? window.parent.location : window.location;
            const url = new URL(loc.href);
            const hasAnyQuery = Array.from(url.searchParams.keys()).length > 0;
            if (!hasAnyQuery) return;
            if (routeBlockingKeys.some((key) => url.searchParams.has(key))) return;
            const params = JSON.parse(savedRoute);
            if (!params || (!params.es_page && !params.es_editor)) return;
            Object.entries(params).forEach(([key, value]) => {{
              if (routeParamKeys.includes(key) && value) {{
                url.searchParams.set(key, String(value));
              }}
            }});
            loc.replace(url.toString());
          }} catch (err) {{}}
        }})();
        </script>
        """,
        height=0,
    )


def sync_browser_timezone() -> None:
    """Expose the browser timezone to Streamlit so UI timestamps are viewer-local."""
    timezone_param_json = json.dumps(BROWSER_TIMEZONE_QUERY_PARAM)
    storage_key_json = json.dumps(BROWSER_TIMEZONE_STORAGE_KEY)
    render_parent_script(
        f"""
        (() => {{
          const timezoneParam = {timezone_param_json};
          const storageKey = {storage_key_json};
          let browserTimezone = "";
          try {{
            browserTimezone = Intl.DateTimeFormat().resolvedOptions().timeZone || "";
          }} catch (err) {{}}
          if (!browserTimezone || !/^[A-Za-z0-9_+\\-/]+$/.test(browserTimezone)) return;
          try {{
            window.localStorage.setItem(storageKey, browserTimezone);
          }} catch (err) {{}}
          let url;
          try {{
            url = new URL(window.location.href);
          }} catch (err) {{
            return;
          }}
          if (url.searchParams.get(timezoneParam) === browserTimezone) return;
          url.searchParams.set(timezoneParam, browserTimezone);
          const nextUrl = url.toString();
          try {{
            window.history.replaceState({{}}, "", nextUrl);
          }} catch (err) {{}}
          try {{
            const reloadKey = storageKey + ":last_sync";
            const lastSync = window.sessionStorage.getItem(reloadKey) || "";
            if (lastSync !== browserTimezone) {{
              window.sessionStorage.setItem(reloadKey, browserTimezone);
              window.location.replace(nextUrl);
            }}
          }} catch (err) {{}}
        }})();
        """
    )


def install_local_time_render_bridge() -> None:
    """Format marked UTC timestamps in the browser's local timezone."""
    render_parent_script(
        """
        (() => {
          const bridgeVersion = "local-time-v2";
          if (window.__cognisweepLocalTimeObserver && window.__cognisweepLocalTimeObserverVersion !== bridgeVersion) {
            try { window.__cognisweepLocalTimeObserver.disconnect(); } catch (err) {}
            window.__cognisweepLocalTimeObserver = null;
          }
          window.__cognisweepLocalTimeObserverVersion = bridgeVersion;
          const browserTimeZone = (() => {
            try { return Intl.DateTimeFormat().resolvedOptions().timeZone || ""; } catch (err) { return ""; }
          })();
          const zoneAliases = {
            "Asia/Calcutta": "IST",
            "Asia/Kolkata": "IST"
          };
          const displayZoneName = (fallback) => zoneAliases[browserTimeZone] || fallback || "";
          const formatLocalTime = (isoValue) => {
            const date = new Date(isoValue);
            if (Number.isNaN(date.getTime())) return "";
            const formatter = new Intl.DateTimeFormat(undefined, {
              year: "numeric",
              month: "2-digit",
              day: "2-digit",
              hour: "2-digit",
              minute: "2-digit",
              hour12: true,
              timeZoneName: "short"
            });
            const parts = {};
            formatter.formatToParts(date).forEach((part) => {
              if (part.type !== "literal") parts[part.type] = part.value;
            });
            const zone = displayZoneName(parts.timeZoneName);
            return `${parts.year}-${parts.month}-${parts.day} ${parts.hour}:${parts.minute} ${parts.dayPeriod || ""} ${zone}`.trim();
          };
          const render = () => {
            document.querySelectorAll("time[data-es-local-time]").forEach((node) => {
              const isoValue = node.getAttribute("datetime") || node.getAttribute("data-utc") || "";
              const formatted = formatLocalTime(isoValue);
              if (!formatted) return;
              if (node.getAttribute("data-es-local-rendered") === formatted && node.textContent === formatted) return;
              node.setAttribute("data-es-local-rendered", formatted);
              if (node.textContent !== formatted) node.textContent = formatted;
            });
          };
          let renderQueued = false;
          const scheduleRender = () => {
            if (renderQueued) return;
            renderQueued = true;
            window.requestAnimationFrame(() => {
              renderQueued = false;
              render();
            });
          };
          render();
          if (!window.__cognisweepLocalTimeObserver) {
            window.__cognisweepLocalTimeObserver = new MutationObserver(scheduleRender);
            window.__cognisweepLocalTimeObserver.observe(document.body || document.documentElement, { childList: true, subtree: true });
          }
        })();
        """
    )


def is_human_review_editor_page(page: str) -> bool:
    normalized_page = normalize_es_page(page)
    return normalized_page == "Human Review Editor" or safe_text(page).strip() in HUMAN_REVIEW_EDITOR_PAGES


def navigate_es_page(page_name: str, **params: str) -> None:
    """Navigate with the existing es_page query model and remove route conflicts."""
    page_name = normalize_es_page(page_name or "Dashboard")
    clean_params = {key: safe_text(value) for key, value in params.items() if safe_text(value)}
    st.session_state["es_page"] = page_name
    if page_name in allowed_pages():
        st.session_state.page = page_name
    for key, value in clean_params.items():
        st.session_state[key] = value
    if clean_params.get("review_id"):
        st.session_state["active_review_session_id"] = clean_params["review_id"]
    st.session_state["current_route"] = {"page": page_name, "es_page": page_name, **clean_params}

    st.query_params["es_page"] = page_name
    for key in ("route", "public", "return_to", "es_session", "es_restore", "es_restore_miss", EDITOR_LAUNCH_QUERY_PARAM, EDITOR_AUTH_FAILED_QUERY_PARAM, EDITOR_SUBMITTED_QUERY_PARAM, EDITOR_SUBMITTED_TYPE_QUERY_PARAM, "tool_tab", "es_panel", "es_app_nav", AUTH_CHECK_QUERY_PARAM):
        if key in st.query_params:
            del st.query_params[key]
    if st.session_state.get("authenticated") and st.session_state.get("user") and not browser_session_cookie():
        st.query_params[SESSION_HANDOFF_QUERY_PARAM] = signed_session_token_for_user(st.session_state.get("user") or {})
        
    for key, value in clean_params.items():
        st.query_params[key] = str(value)
        
    st.rerun()


def navigate(route: str, params: Optional[Dict[str, str]] = None, **kwargs: str) -> None:
    """Central app navigation that preserves the current Streamlit session."""
    route_value = safe_text(route) or "dashboard"
    route_key = route_value.strip().lower().replace(" ", "_")
    merged_params = {**(params or {}), **{key: value for key, value in kwargs.items() if safe_text(value)}}
    if route_key == "human_review_editor":
        review_id = safe_text(merged_params.get("review_id"))
        if not review_id:
            st.error("Cannot open Human Review Editor: missing review_id.")
            st.stop()
        st.session_state["active_review_session_id"] = review_id
        st.session_state["current_route"] = {"route": "human_review_editor", "es_editor": "human_review", "review_id": review_id}
        set_route_query({"es_editor": "human_review", "review_id": review_id})
        st.rerun()
    if route_key in ROUTE_PAGE_ALIASES and ROUTE_PAGE_ALIASES[route_key]:
        page = ROUTE_PAGE_ALIASES[route_key]
        navigate_es_page(page, **merged_params)
    page = route_value
    navigate_es_page(page, **merged_params)


def navigate_to_human_review_editor(review_id: str = "") -> None:
    review_id = (
        safe_text(review_id)
        or query_get("review_id")
        or safe_text(st.session_state.get("review_id", ""))
        or safe_text(st.session_state.get("active_review_session_id", ""))
    )
    if not review_id:
        st.error("Cannot open Human Review Editor: missing review_id.")
        st.stop()
    st.session_state["active_review_session_id"] = review_id
    st.session_state["current_route"] = {"route": "human_review_editor", "es_editor": "human_review", "review_id": review_id}
    set_route_query({"es_editor": "human_review", "review_id": review_id})
    st.rerun()


def requested_route_params() -> Dict[str, str]:
    params: Dict[str, str] = {}
    for key in ("es_page", "es_editor", "job_id", "review_id"):
        value = query_get(key)
        if value:
            params[key] = normalize_es_page(value) if key == "es_page" else value
    route = safe_text(query_get("route")).strip().lower()
    if params:
        if route:
            query_clear("route")
        return params
    if route:
        if route in {"editor", "cat_editor"}:
            params["es_editor"] = safe_text(query_get("es_editor") or "cat")
            if query_get("job_id"):
                params["job_id"] = query_get("job_id")
        elif route == "human_review_editor":
            review_id = query_get("review_id")
            params["es_editor"] = "human_review"
            if review_id:
                params["review_id"] = review_id
        elif route in ROUTE_PAGE_ALIASES:
            page = ROUTE_PAGE_ALIASES[route]
            if page:
                params["es_page"] = normalize_es_page(page)
            else:
                params["es_page"] = PUBLIC_ROUTE_PAGE_NAMES.get(route, normalize_es_page(route))
    return params


def protected_route_requested() -> bool:
    route = safe_text(query_get("route")).strip().lower()
    es_page = normalize_es_page(query_get("es_page"))
    has_editor_target = any(query_get(key) for key in ("es_editor", "job_id", "review_id"))
    public_es_route = public_route_for_es_page(es_page)
    if public_es_route and public_es_route in PUBLIC_ROUTES and not has_editor_target:
        return False
    public_routes = PUBLIC_ROUTES
    if route in public_routes and not (query_get("es_page") or has_editor_target):
        return False
    if is_human_review_editor_page(es_page) or has_editor_target:
        return True
    if es_page in known_protected_es_pages():
        return True
    if route == "human_review_editor":
        return True
    if route in ROUTE_PAGE_ALIASES and ROUTE_PAGE_ALIASES[route]:
        return normalize_es_page(ROUTE_PAGE_ALIASES[route]) in known_protected_es_pages()
    return False


def get_current_route() -> Dict[str, str]:
    params = requested_route_params()
    if params:
        if params.get("es_page"):
            params["es_page"] = normalize_es_page(params.get("es_page"))
        public_route = public_route_for_es_page(safe_text(params.get("es_page")))
        if public_route:
            return {"route": public_route, "public": public_route, "page": PUBLIC_ROUTE_PAGE_NAMES.get(public_route, params.get("es_page", "Landing")), **params}
        legacy_public_route = safe_text(params.get("route")).strip().lower()
        if legacy_public_route and legacy_public_route in PUBLIC_ROUTES:
            return {"route": legacy_public_route, "public": legacy_public_route, **params}
        if is_human_review_editor_page(safe_text(params.get("es_page"))):
            return {"route": "human_review_editor", **params}
        if params.get("es_editor"):
            editor_route = "human_review_editor" if safe_text(params.get("es_editor")) == "human_review" else "cat_editor"
            return {"route": editor_route, **params}
        page_value = params.get("es_page", st.session_state.get("page", "Dashboard"))
        if page_value not in known_protected_es_pages():
            return {"route": "unknown", "unknown": page_value, **params}
        route_slug = params.get("route") or PAGE_ROUTE_SLUGS.get(page_value) or es_page_alias_key(page_value) or "dashboard"
        return {"route": route_slug, "page": page_value, **params}
    public_route = safe_text(query_get("public") or query_get("route")).strip().lower()
    if public_route and public_route in PUBLIC_ROUTES:
        return {"route": safe_text(public_route), "public": safe_text(public_route), "page": PUBLIC_ROUTE_PAGE_NAMES.get(public_route, "Landing")}
    if public_route:
        return {"route": public_route, "unknown": public_route}
    if not route_query_has_explicit_target():
        return {"route": "landing", "public": "landing", "page": "Landing", "es_page": "Landing"}
    return {"route": "page", "page": safe_text(st.session_state.get("page", "Dashboard")) or "Dashboard"}


def is_authenticated() -> bool:
    if not (st.session_state.get("authenticated") and st.session_state.get("user")):
        restore_session_from_cookie()
    return bool(st.session_state.get("authenticated") and st.session_state.get("user"))


def redirect_to_login_with_return_to(reason: str = "unknown") -> None:
    if query_get("debug_auth") == "1":
        st.warning(f"Redirecting to Login. Reason: {reason}")
    return_url = encode_return_to()
    st.session_state["post_login_return_to"] = return_url
    st.session_state["_router_redirect_reason"] = reason
    st.query_params.clear()
    st.query_params["es_page"] = "Login"
    if return_url:
        st.query_params["return_to"] = return_url
    st.stop()


def require_auth(route: Optional[Any] = None) -> bool:
    if is_authenticated():
        return True
        
    if isinstance(route, dict):
        if route.get("route") == "public":
            return True
        if route.get("route") in {"page", "editor"} and not protected_route_requested():
            return True
            
    redirect_to_login_with_return_to(reason="protected_page_without_valid_session")
    st.stop()
    return False


def encode_return_to(params: Optional[Dict[str, str]] = None) -> str:
    route_params = params or requested_route_params()
    return urlencode({key: value for key, value in route_params.items() if safe_text(value)})


def apply_return_to(return_to: str) -> bool:
    if not safe_text(return_to):
        return False
    parsed = parse_qs(return_to.lstrip("?"), keep_blank_values=False)
    flat = {key: safe_text(values[0]) for key, values in parsed.items() if values}
    route = flat.get("route", "").strip().lower()
    page = normalize_es_page(flat.get("es_page"))
    if route == "login" or public_route_for_es_page(page) == "login":
        st.session_state.page = "Dashboard"
        st.session_state["current_route"] = {"page": "Dashboard", "es_page": "Dashboard"}
        set_route_query({"es_page": "Dashboard"})
        return True
    if route == "human_review_editor" or is_human_review_editor_page(page):
        review_id = safe_text(flat.get("review_id"))
        if not review_id:
            st.session_state.page = "Dashboard"
            st.session_state["current_route"] = {"page": "Dashboard", "es_page": "Dashboard"}
            set_route_query({"es_page": "Dashboard"})
            return True
        st.session_state["active_review_session_id"] = review_id
        st.session_state["current_route"] = {"route": "human_review_editor", "es_editor": "human_review", "review_id": review_id}
        set_route_query({"es_editor": "human_review", "review_id": review_id})
        return True
    if route in ROUTE_PAGE_ALIASES and ROUTE_PAGE_ALIASES[route]:
        page = normalize_es_page(ROUTE_PAGE_ALIASES[route])
        extra = {key: value for key, value in flat.items() if key != "route"}
        st.session_state.page = page
        st.session_state["current_route"] = {"page": page, "es_page": page, **extra}
        set_route_query({"es_page": page, **extra})
        return True
    if flat.get("es_editor") == "human_review" and flat.get("review_id"):
        review_id = safe_text(flat.get("review_id"))
        st.session_state["active_review_session_id"] = review_id
        st.session_state["current_route"] = {"route": "human_review_editor", "es_editor": "human_review", "review_id": review_id}
        set_route_query({"es_editor": "human_review", "review_id": review_id})
        return True
    if flat.get("es_editor") and flat.get("job_id"):
        for key, value in flat.items():
            if key != "route":
                query_set(key, value)
        query_clear("route")
        st.session_state["current_route"] = dict(flat)
        return True
    page_value = flat.get("es_page")
    if page_value:
        page = normalize_es_page(page_value)
        st.session_state.page = page
        st.session_state["current_route"] = {"page": page, "es_page": page}
        set_route_query(route_query_for_page(page, {k: v for k, v in flat.items() if k not in {"es_page", "route"}}))
        return True
    return False


def open_page(page: str) -> None:
    """Open an internal CogniSweep route as a dedicated page in the same session."""
    params: Dict[str, str] = {}
    if page == "Human Review Workspace":
        session_id = st.session_state.get("active_review_session_id")
        if session_id:
            params["review_id"] = str(session_id)
    navigate(page, params)


def nav_button(page: str, key_prefix: str = "nav") -> None:
    label = page
    if st.session_state.get("nav_compact"):
        label = "".join(part[:1] for part in re.split(r"[\s/&]+", page) if part)[:4].upper() or page[:3].upper()
    key = native_nav_key(key_prefix, page)
    state = "active" if st.session_state.get("page") == page else "idle"
    with st.container(key=f"{key}_legacy_{state}", gap=None):
        if st.button(label, key=key, use_container_width=True, help=f"Open {page}"):
            navigate_es_page(page)


def topnav_page_order(pages: List[str]) -> List[str]:
    hidden_pages = set(HIDDEN_EDITOR_PAGES)
    ordered: List[str] = []
    for page in WORKSPACE_PAGES + OWNER_PAGES:
        if page in pages and page not in hidden_pages and page not in ordered:
            ordered.append(page)
    for page in pages:
        if page not in hidden_pages and page not in ordered:
            ordered.append(page)
    return ordered


def topnav_panel_link(page: str, panel: str) -> str:
    return "?" + urlencode({"es_page": normalize_es_page(page), "es_panel": safe_text(panel)})


def current_ui_language(user: Optional[Dict[str, Any]] = None) -> Tuple[str, str]:
    candidate = user if user is not None else (current_user() or {})
    metadata = stored_metadata_dict(candidate.get("metadata_json"))
    code = safe_text(st.session_state.get("ui_language") or metadata.get("ui_language") or "EN").upper()
    labels = dict(UI_LANGUAGE_OPTIONS)
    if code not in labels:
        code = "EN"
    return code, labels.get(code, "English")


def notification_time_value(record: Dict[str, Any]) -> str:
    return safe_text(record.get("created") or record.get("created_at") or record.get("updated_at"))


def notification_meta(record: Dict[str, Any]) -> Dict[str, Any]:
    metadata = record.get("metadata_json")
    if isinstance(metadata, dict):
        return dict(metadata)
    if isinstance(metadata, str) and metadata.strip():
        try:
            decoded = json.loads(metadata)
            return decoded if isinstance(decoded, dict) else {}
        except Exception:
            return {}
    return {}


def notification_read_at(record: Dict[str, Any]) -> str:
    metadata = notification_meta(record)
    return safe_text(record.get("read_at") or metadata.get("read_at"))


def notification_dismissed_at(record: Dict[str, Any]) -> str:
    metadata = notification_meta(record)
    return safe_text(record.get("dismissed_at") or metadata.get("dismissed_at"))


def notification_dedupe_key(record: Dict[str, Any]) -> str:
    event_type = safe_text(record.get("event_type"))
    recipient = safe_text(record.get("recipient")).lower()
    metadata = notification_meta(record)
    action_target = safe_text(metadata.get("verify_url") or metadata.get("reset_url") or metadata.get("cta_url"))
    if event_type in {"auth.email_verification", "auth.password_reset", "signup.welcome"}:
        return f"{event_type}:{recipient}"
    return f"{event_type}:{recipient}:{safe_text(record.get('subject')).lower()}:{action_target}"


def sanitize_notification_message(value: Any) -> str:
    text = safe_text(value)
    text = re.sub(r"\?public=(verify|reset)&token=[^\s)]+", "use the action below", text)
    text = re.sub(r"https?://[^\s)]+", "use the action below", text)
    return re.sub(r"\s+", " ", text).strip()


def notification_kind_label(event_type: str) -> str:
    if event_type.startswith("auth."):
        return "Account"
    if event_type.startswith("signup"):
        return "Onboarding"
    if event_type.startswith("billing"):
        return "Billing"
    if "invite" in event_type:
        return "Team"
    if "support" in event_type:
        return "Support"
    if "status" in event_type:
        return "Status"
    return "Notice"


def note_action_link(active_page: str, action: str, note_id: str = "", panel: str = "notes", page: str = "") -> str:
    params = {"es_page": normalize_es_page(page or active_page), "es_panel": panel, "es_note_action": safe_text(action)}
    if safe_text(note_id):
        params["note_id"] = safe_text(note_id)
    return "?" + urlencode(params)


def update_notification_record(note_id: str, changes: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    note_id = safe_text(note_id)
    if not note_id:
        return None
    for idx, item in enumerate(st.session_state.get("notifications", [])):
        if safe_text(item.get("id")) != note_id:
            continue
        updated = dict(item)
        metadata = notification_meta(updated)
        for key, value in changes.items():
            if key in {"read_at", "dismissed_at"}:
                updated[key] = value
                metadata[key] = value
            else:
                updated[key] = value
        updated["metadata_json"] = metadata
        updated["updated_at"] = now_stamp()
        persisted = persist_saas_record("notifications", updated)
        st.session_state.notifications[idx] = persisted
        return persisted
    return None


def handle_topnav_note_action() -> None:
    action = safe_text(query_get("es_note_action")).lower()
    note_id = safe_text(query_get("note_id"))
    if not action:
        return
    if action == "read":
        update_notification_record(note_id, {"read_at": now_stamp()})
        query_clear("es_note_action")
        query_clear("note_id")
        st.rerun()
    if action == "dismiss":
        update_notification_record(note_id, {"dismissed_at": now_stamp(), "read_at": now_stamp()})
        query_clear("es_note_action")
        query_clear("note_id")
        st.rerun()
    if action == "complete_profile":
        open_account_professional_profile_editor()
        update_notification_record(note_id, {"read_at": now_stamp()})
        query_clear("es_panel")
        query_clear("es_note_action")
        query_clear("note_id")
        st.rerun()


def user_visible_notifications(user: Dict[str, Any]) -> List[Dict[str, Any]]:
    email = safe_text(user.get("email")).lower()
    workspace = safe_text(user.get("workspace")).lower()
    if is_owner():
        rows = list(st.session_state.get("notifications", []))
    else:
        rows = []
        for item in st.session_state.get("notifications", []):
            recipient = safe_text(item.get("recipient")).lower()
            item_workspace = safe_text(item.get("workspace")).lower()
            if recipient == email or (not recipient and item_workspace == workspace):
                rows.append(item)
    deduped: List[Dict[str, Any]] = []
    seen: Set[str] = set()
    for item in sorted(rows, key=notification_time_value, reverse=True):
        if notification_dismissed_at(item):
            continue
        key = notification_dedupe_key(item)
        if key in seen:
            continue
        seen.add(key)
        deduped.append(item)
    return deduped


def normalized_notification_note(record: Dict[str, Any], user: Dict[str, Any], active_page: str) -> Dict[str, Any]:
    metadata = notification_meta(record)
    event_type = safe_text(record.get("event_type") or "notice")
    title = safe_text(record.get("subject") or metadata.get("title") or event_type.replace(".", " ").title())
    message = sanitize_notification_message(record.get("body") or metadata.get("message") or title)
    note_id = safe_text(record.get("id"))
    is_read = bool(notification_read_at(record))
    actions: List[Dict[str, str]] = []
    action_required = False

    if event_type == "auth.email_verification" and not bool(user.get("email_verified")):
        verify_url = safe_text(metadata.get("verify_url"))
        title = "Verify your email"
        message = "Secure your CogniSweep account by verifying your email address."
        action_required = True
        if verify_url:
            actions.append({"label": "Verify email", "href": verify_url, "kind": "primary"})
    elif event_type == "auth.password_reset":
        reset_url = safe_text(metadata.get("reset_url"))
        title = "Password reset requested"
        message = "Use the password reset action if you requested this change."
        if reset_url:
            actions.append({"label": "Reset password", "href": reset_url, "kind": "primary"})
    elif event_type == "signup.welcome":
        title = "Welcome to CogniSweep"
        message = "Your account is ready. Complete your profile to help employers and managers match you with suitable work."
        if normalized_profile_completion_status(user) != "completed":
            action_required = True
            actions.append({"label": "Complete profile", "href": note_action_link(active_page, "complete_profile", note_id, page="Dashboard"), "kind": "primary"})
    elif event_type.startswith("billing"):
        actions.append({"label": "Open Billing", "href": page_link("Billing"), "kind": "primary"})
    elif "invite" in event_type:
        actions.append({"label": "Open Jobs", "href": page_link("Jobs"), "kind": "primary"})

    if not is_read:
        actions.append({"label": "Mark as read", "href": note_action_link(active_page, "read", note_id), "kind": ""})
    actions.append({"label": "Dismiss", "href": note_action_link(active_page, "dismiss", note_id), "kind": "danger"})

    return {
        "id": note_id,
        "type": notification_kind_label(event_type),
        "title": title,
        "message": message,
        "created": notification_time_value(record),
        "is_read": is_read,
        "action_required": action_required,
        "actions": actions,
    }


def normalized_notification_notes(records: List[Dict[str, Any]], user: Dict[str, Any], active_page: str) -> List[Dict[str, Any]]:
    notes = [normalized_notification_note(record, user, active_page) for record in records]
    return sorted(notes, key=lambda note: safe_text(note.get("created")), reverse=True)


def notification_badge_count(notes: List[Dict[str, Any]]) -> int:
    return sum(1 for note in notes if not note.get("is_read") or note.get("action_required"))


def render_topnav_notes_panel(active_page: str, notifications: List[Dict[str, Any]], user: Dict[str, Any]) -> None:
    notes = normalized_notification_notes(notifications, user, active_page)
    unread_count = notification_badge_count(notes)
    close_href = page_link(active_page)
    nav_targets: List[Dict[str, Any]] = []
    close_attr = app_nav_target_from_href(nav_targets, "topnav_panel", close_href, "Close notifications")
    close_control = (
        f'<button type="button" class="es-topnav-panel-close" {close_attr}>Close</button>'
        if close_attr
        else f'<a class="es-topnav-panel-close" href="{escape(close_href)}" target="_self">Close</a>'
    )
    rows = []
    for note in notes[:12]:
        action_parts: List[str] = []
        for action in note.get("actions", []):
            label = safe_text(action.get("label", ""))
            href = safe_text(action.get("href", "#"))
            kind = escape(action.get("kind", ""))
            action_attr = app_nav_target_from_href(nav_targets, "topnav_panel", href, label)
            if action_attr:
                action_parts.append(f'<button type="button" class="es-note-action {kind}" {action_attr}>{escape(label)}</button>')
            else:
                action_parts.append(f'<a class="es-note-action {kind}" href="{escape(href)}" target="_self">{escape(label)}</a>')
        action_html = "".join(action_parts)
        unread_cls = " unread" if (not note.get("is_read") or note.get("action_required")) else ""
        dot_html = '<span class="es-note-dot"></span>' if unread_cls else ''
        rows.append(
            f'<article class="es-note-item{unread_cls}">'
            '<div class="es-note-topline">'
            f'<span class="es-note-type">{escape(safe_text(note.get("type")))}</span>{dot_html}'
            '</div>'
            f'<b>{escape(safe_text(note.get("title")))}</b>'
            f'<div class="es-note-message">{escape(safe_text(note.get("message")))}</div>'
            f'<div class="es-note-meta">{escape(format_local_time(note.get("created")) or safe_text(note.get("created")))}'
            f' - {"Unread" if not note.get("is_read") else "Read"}</div>'
            f'<div class="es-note-actions">{action_html}</div>'
            '</article>'
        )
    notes_html = "".join(rows) if rows else '<div class="es-note-empty"><b>No unread notifications</b><br>Important account, billing, team, and workflow notes will appear here.</div>'
    st.markdown(
        dedent(f"""
        <section class="es-topnav-panel" aria-label="Notification drawer">
          <div class="es-topnav-panel-head">
            <div>
              <div class="es-topnav-panel-title">Notifications</div>
              <div class="es-note-meta">{unread_count} unread or action-required</div>
            </div>
            {close_control}
          </div>
          <div class="es-note-list">{notes_html}</div>
        </section>
        """).strip(),
        unsafe_allow_html=True,
    )
    render_app_navigation_targets(nav_targets, "topnav_panel")
    render_app_navigation_bridge()


def render_topnav_language_panel(active_page: str, user: Dict[str, Any]) -> None:
    close_href = page_link(active_page)
    nav_targets: List[Dict[str, Any]] = []
    close_attr = app_nav_target_from_href(nav_targets, "topnav_language_panel", close_href, "Close language")
    close_control = (
        f'<button type="button" class="es-topnav-panel-close" {close_attr}>Close</button>'
        if close_attr
        else f'<a class="es-topnav-panel-close" href="{escape(close_href)}" target="_self">Close</a>'
    )
    current_code, _ = current_ui_language(user)
    option_labels = [f"{code} - {label}" for code, label in UI_LANGUAGE_OPTIONS]
    default_index = next((idx for idx, (code, _) in enumerate(UI_LANGUAGE_OPTIONS) if code == current_code), 0)
    st.markdown(
        dedent(f"""
        <section class="es-topnav-panel" aria-label="UI language selector">
          <div class="es-topnav-panel-head">
            <div class="es-topnav-panel-title">UI language</div>
            {close_control}
          </div>
        </section>
        """).strip(),
        unsafe_allow_html=True,
    )
    render_app_navigation_targets(nav_targets, "topnav_language_panel")
    render_app_navigation_bridge()
    with st.container(key="topnav_language_selector"):
        selected = st.selectbox("Interface language", option_labels, index=default_index, key="topnav_ui_language_select")
        if st.button("Apply language", use_container_width=False, key="topnav_apply_language"):
            code = selected.split(" - ", 1)[0]
            label = dict(UI_LANGUAGE_OPTIONS).get(code, "English")
            st.session_state["ui_language"] = code
            metadata = stored_metadata_dict(user.get("metadata_json"))
            save_current_user_profile({
                "metadata_json": {
                    **metadata,
                    "ui_language": code,
                    "ui_language_label": label,
                },
            })
            query_clear("es_panel")
            st.rerun()


def render_topnav_panel(active_page: str, user: Dict[str, Any], notifications: List[Dict[str, Any]]) -> None:
    panel = safe_text(query_get("es_panel")).lower()
    permissions = effective_permissions(user)
    if panel == "notes" and "notes.view" in permissions:
        render_topnav_notes_panel(active_page, notifications, user)
    elif panel in {"language", "lang"} and "language.select" in permissions:
        render_topnav_language_panel(active_page, user)


def render_native_route_button(
    page: str,
    label: str,
    prefix: str,
    *,
    active: bool = False,
    extra: Optional[Dict[str, str]] = None,
    help_text: str = "",
    kind: str = "nav",
) -> None:
    """Render internal app navigation as a real Streamlit callback, not a browser link."""
    clean_extra = {key: safe_text(value) for key, value in (extra or {}).items() if safe_text(value)}
    key = native_nav_key(prefix, page, clean_extra)
    state = "active" if active else "idle"
    clean_kind = re.sub(r"[^a-z0-9_]+", "_", safe_text(kind).lower()).strip("_") or "nav"
    with st.container(key=f"{key}_{clean_kind}_{state}", gap=None):
        if st.button(label, key=key, use_container_width=True, help=help_text or None):
            navigate_es_page(page, **clean_extra)


def render_navigation() -> None:
    """Render the shared top navigation bar for all roles. Hides unauthorized menu items based on role."""
    user = current_user() or {}
    permissions = effective_permissions(user)
    pages = allowed_pages()

    # Page label display names
    label_map = {
        "Dashboard": "Dashboard",
        "Projects": "Projects",
        "Jobs": "Jobs",
        "Job History": "History",
        "CogniSweep QA": "QA Reports",
        "CogniSweep Pro": "Translation",
        "Subtitle / Transcription Editor": "Media Studio",
        "Scorecards": "Scorecards",
        "Memory & Rules": "Rules",
        "Team & Roles": "Team",
        "Billing": "Billing",
        "Account": "Account",
        "Admin": "Admin",
    }
    nav_targets: List[Dict[str, Any]] = []
    nav_pages = topnav_page_order(pages)
    primary_nav_pages = [page for page in nav_pages if page in WORKSPACE_PAGES]
    owner_nav_pages = [page for page in OWNER_PAGES if page in pages] if is_owner() else []

    def nav_href(page: str, extra: Optional[Dict[str, str]] = None) -> str:
        params = {"es_page": normalize_es_page(page)}
        for key, value in (extra or {}).items():
            if key != "route" and safe_text(value):
                params[key] = safe_text(value)
        return "?" + urlencode(params)

    def nav_target_attr(page: str, extra: Optional[Dict[str, str]] = None, label: str = "") -> str:
        clean_extra = {key: safe_text(value) for key, value in (extra or {}).items() if safe_text(value)}
        key = native_nav_key("topnav_app", page, clean_extra)
        nav_targets.append({"key": key, "page": page, "extra": clean_extra, "label": label or page})
        return app_nav_attr(key, nav_href(page, clean_extra))

    workspace_links = []
    for page in primary_nav_pages:
        active = " active" if st.session_state.get("page") == page else ""
        workspace_links.append(
            f'<button type="button" class="es-topnav-link{active}" {nav_target_attr(page, label=label_map.get(page, page))}>{escape(label_map.get(page, page))}</button>'
        )
    owner_links = []
    for page in owner_nav_pages:
        active = " active" if st.session_state.get("page") == page else ""
        owner_links.append(
            f'<button type="button" class="es-topnav-owner-link{active}" {nav_target_attr(page)}>{escape(page)}</button>'
        )
    open_count = sum(
        1
        for job in st.session_state.get("jobs", [])
        if safe_text(job.get("status", "")).lower() in {"draft", "needs human review", "needs_review", "running"}
    )
    notification_count = len(st.session_state.get("notifications", []))
    user_email = safe_text(user.get("email", "user@errorsweep.local"))
    user_name = display_name_from_user(user)
    role = current_role()
    active_panel = safe_text(query_get("es_panel")).lower()
    current_page = safe_text(st.session_state.get("page") or "Dashboard")
    notifications = st.session_state.get("notifications", [])
    unread_notes = notification_badge_count(normalized_notification_notes(st.session_state.get("notifications", []), user, current_page))
    ui_language_code, _ = current_ui_language(user)
    notes_href = nav_href(current_page, {"es_panel": "notes"})
    language_href = nav_href(current_page, {"es_panel": "language"})
    settings_page = "Platform Settings" if is_owner() else ("Admin" if "Admin" in pages else "Account")
    jobs_nav_attr = nav_target_attr("Jobs") if "Jobs" in pages else ""
    notes_nav_attr = nav_target_attr(current_page, {"es_panel": "notes"}, "Notes")
    language_nav_attr = nav_target_attr(current_page, {"es_panel": "language"}, "Language")
    account_nav_attr = nav_target_attr("Account")
    settings_nav_attr = nav_target_attr(settings_page)
    billing_nav_attr = nav_target_attr("Billing") if "Billing" in pages else ""
    notes_badge = f'<i class="es-topnav-badge">{unread_notes}</i>' if unread_notes else ""
    jobs_tool = (
        f'<button type="button" class="es-topnav-tool" title="Open jobs" {jobs_nav_attr}>'
        f'<b>{open_count}</b><span>Jobs</span></button>'
        if "Jobs" in pages else ""
    )
    notes_tool = (
        f'<button type="button" class="es-topnav-tool{" active" if active_panel == "notes" else ""}" '
        f'title="Open notifications" {notes_nav_attr}>'
        f'<b>{unread_notes}</b><span>Notes</span>{notes_badge}</button>'
        if "notes.view" in permissions
        else ""
    )
    language_tool = (
        f'<button type="button" class="es-topnav-tool{" active" if active_panel in {"language", "lang"} else ""}" '
        f'title="Change interface language" {language_nav_attr}>'
        f'<b>{escape(ui_language_code or "EN")}</b><span>Lang</span></button>'
        if "language.select" in permissions
        else ""
    )
    user_avatar = escape(monogram(user_name or user_email or "User"))
    billing_item = (
        f'<button type="button" {billing_nav_attr}>Billing <span>Plan</span></button>'
        if "Billing" in pages
        else ""
    )
    jobs_menu_item = (
        f'<button type="button" {jobs_nav_attr}>Jobs <span>{open_count}</span></button>'
        if "Jobs" in pages
        else ""
    )
    topnav = f"""
    <nav class="es-topnav">
      <div class="es-topnav-row">
        <div class="es-topnav-brand">
          <div class="es-topnav-mark" aria-hidden="true"></div>
          <div class="es-topnav-brand-copy">
            <div class="es-topnav-name">Cogni<span>Sweep</span></div>
          </div>
        </div>
        <div class="es-topnav-links">
          {''.join(workspace_links)}
        </div>
        <div class="es-topnav-tools">
          {jobs_tool}
          {notes_tool}
          {language_tool}
          <div class="es-topnav-user-wrap">
            <div class="es-topnav-user" tabindex="0" title="Account menu">
              <div>
                <div style="font-weight:900;white-space:nowrap;">{escape(user_name)}</div>
                <div style="font-size:11px;color:#8ea1dc;font-weight:800;">{escape(role)}</div>
              </div>
              <div class="es-topnav-avatar">{user_avatar}</div>
              <span class="es-account-caret">v</span>
            </div>
            <div class="es-account-menu">
              <button type="button" {account_nav_attr}>Profile <span>Account</span></button>
              <button type="button" {settings_nav_attr}>Settings <span>{escape(settings_page)}</span></button>
              {billing_item}
              {jobs_menu_item}
              <a class="logout" href="?es_logout=1" target="_self">Logout <span>Exit</span></a>
            </div>
          </div>
        </div>
      </div>
      {f'<div class="es-topnav-owner-row"><span class="es-topnav-owner-tag">Owner tools</span><div class="es-topnav-owner-links">{"".join(owner_links)}</div></div>' if owner_links else ''}
    </nav>
    """
    st.markdown(topnav, unsafe_allow_html=True)
    render_app_navigation_targets(nav_targets, "topnav")
    render_app_navigation_bridge()
    render_topnav_panel(current_page, user, notifications)


# ==========================================================
# General helpers
# ==========================================================

def now_stamp() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")


def timezone_from_name(value: Any) -> Optional[ZoneInfo]:
    name = safe_text(value)
    if not name:
        return None
    try:
        return ZoneInfo(name)
    except Exception as exc:
        LOGGER.debug("Invalid timezone %s: %s", name, exc)
        return None


def user_timezone_name() -> str:
    user = current_user() or {}
    return safe_text(user.get("timezone"))


def browser_timezone_name() -> str:
    query_timezone = safe_text(query_get(BROWSER_TIMEZONE_QUERY_PARAM))
    if query_timezone and timezone_from_name(query_timezone):
        st.session_state["browser_timezone"] = query_timezone
        return query_timezone
    session_timezone = safe_text(st.session_state.get("browser_timezone"))
    if session_timezone and timezone_from_name(session_timezone):
        return session_timezone
    try:
        context_timezone = safe_text(getattr(st.context, "timezone", None))
        if context_timezone and timezone_from_name(context_timezone):
            st.session_state["browser_timezone"] = context_timezone
            return context_timezone
    except Exception as exc:
        LOGGER.debug("Browser timezone unavailable: %s", exc)
    return ""


def local_timezone() -> timezone:
    """Return the viewer's timezone, preferring browser/user settings over server time."""
    configured = secret("ERRORSWEEP_DISPLAY_TIMEZONE", secret("TZ", "")).strip()
    for candidate in (browser_timezone_name(), user_timezone_name(), configured):
        tz = timezone_from_name(candidate)
        if tz:
            return tz
    return datetime.now().astimezone().tzinfo or timezone.utc


def parse_datetime_value(value: Any, *, naive_tz: timezone = timezone.utc) -> Optional[datetime]:
    if value in (None, ""):
        return None
    if isinstance(value, (int, float)):
        try:
            if float(value) > 1_000_000_000:
                return datetime.fromtimestamp(float(value), tz=timezone.utc)
        except Exception:
            return None
    raw = str(value).strip()
    if not raw:
        return None
    try:
        numeric = float(raw)
    except (TypeError, ValueError):
        numeric = None
    if numeric and numeric > 1_000_000_000:
        return datetime.fromtimestamp(numeric, tz=timezone.utc)
    parse_raw = raw
    explicit_utc = False
    if parse_raw.upper().endswith(" UTC"):
        parse_raw = parse_raw[:-4].strip()
        explicit_utc = True
    try:
        dt = datetime.fromisoformat(parse_raw.replace("Z", "+00:00"))
    except ValueError:
        dt = None
        for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M", "%Y-%m-%d %I:%M %p", "%Y-%m-%d"):
            try:
                dt = datetime.strptime(parse_raw, fmt)
                break
            except ValueError:
                continue
        if dt is None:
            return None
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc if explicit_utc else naive_tz)
    return dt


def format_local_time(value: Any) -> str:
    if value in (None, ""):
        return ""
    dt = parse_datetime_value(value, naive_tz=timezone.utc)
    if dt is None:
        return safe_text(value)
    local_dt = dt.astimezone(local_timezone())
    zone = local_dt.tzname() or ""
    if " " in zone:
        zone = "".join(part[0] for part in zone.split() if part[:1]).upper()
    return f"{local_dt.strftime('%Y-%m-%d %I:%M %p')} {zone}".strip()


def utc_iso_for_time(value: Any) -> str:
    dt = parse_datetime_value(value, naive_tz=timezone.utc)
    if dt is None:
        return ""
    return dt.astimezone(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")


def local_time_html(value: Any) -> str:
    fallback = format_local_time(value)
    iso_value = utc_iso_for_time(value)
    if not iso_value:
        return escape(fallback)
    return f'<time data-es-local-time datetime="{escape(iso_value, quote=True)}">{escape(fallback)}</time>'


def display_records(records: List[Dict[str, Any]], time_columns: Optional[set] = None) -> List[Dict[str, Any]]:
    cols = time_columns or TIME_DISPLAY_COLUMNS
    output = []
    for record in records or []:
        item = dict(record)
        for key in list(item.keys()):
            if key in cols or key.lower() in cols or key.endswith("_at"):
                item[key] = format_local_time(item.get(key))
        output.append(item)
    return output


def display_dataframe(records: List[Dict[str, Any]], **kwargs) -> None:
    st.dataframe(pd.DataFrame(display_records(records)), use_container_width=True, hide_index=True, **kwargs)


def language_resource_master_key() -> str:
    """Return the app secret used only for encrypting external resource keys."""
    explicit = secret("ERRORSWEEP_LANGUAGE_RESOURCE_MASTER_KEY", "")
    if len(explicit.strip()) >= 32:
        return explicit.strip()
    session_secret = secret("ERRORSWEEP_SESSION_SECRET", "")
    if len(session_secret.strip()) >= 32 and session_secret.strip() != DEFAULT_SESSION_SECRET:
        return session_secret.strip()
    if not is_production_mode():
        return DEFAULT_SESSION_SECRET * 2
    return ""


def language_resource_secret_ready() -> bool:
    return bool(language_resource_master_key())


def coerce_string_list(value: Any) -> List[str]:
    if isinstance(value, list):
        return [safe_text(item) for item in value if safe_text(item)]
    if isinstance(value, tuple):
        return [safe_text(item) for item in value if safe_text(item)]
    if isinstance(value, str):
        text = value.strip()
        if not text:
            return []
        try:
            decoded = json.loads(text)
            if isinstance(decoded, list):
                return [safe_text(item) for item in decoded if safe_text(item)]
        except json.JSONDecodeError:
            return [safe_text(item) for item in re.split(r"[,;\n|]+", text) if safe_text(item)]
        return [safe_text(item) for item in re.split(r"[,;\n|]+", text) if safe_text(item)]
    return []


def resource_ids_text(value: Any) -> str:
    return ", ".join(coerce_string_list(value))


def language_resource_collection_records(collection: str, limit: int = 500) -> List[Dict[str, Any]]:
    user = current_user() or {}
    workspace = safe_text(user.get("workspace") or "Demo Workspace")
    records: List[Dict[str, Any]] = []
    seen: Set[str] = set()
    for source_rows in (
        load_saas_records(collection, workspace=workspace, limit=limit),
        st.session_state.get(collection, []),
    ):
        for row in source_rows or []:
            if not isinstance(row, dict):
                continue
            record = dict(row)
            key = safe_text(
                record.get("connection_id")
                or record.get("binding_id")
                or record.get("audit_id")
                or record.get("cache_id")
                or record.get("id")
            )
            if not key:
                continue
            dedupe_key = f"{collection}:{key}"
            if dedupe_key in seen:
                continue
            records.append(record)
            seen.add(dedupe_key)
    return records


def upsert_session_record(collection: str, record: Dict[str, Any], identity_key: Optional[str] = None) -> None:
    rows = st.session_state.setdefault(collection, [])
    wanted = safe_text(record.get(identity_key) if identity_key else "")
    wanted = wanted or safe_text(record.get("id"))
    for idx, item in enumerate(rows):
        item_identity = safe_text(item.get(identity_key) if identity_key else "")
        item_identity = item_identity or safe_text(item.get("id"))
        if wanted and item_identity == wanted:
            rows[idx] = {**item, **record}
            break
    else:
        rows.insert(0, record)
    trim_session_list(collection, SESSION_COLLECTION_LIMITS.get(collection, SESSION_HISTORY_LIMIT))


def remove_session_record(collection: str, identity_key: str, identity_value: str) -> None:
    wanted = safe_text(identity_value)
    st.session_state[collection] = [
        item for item in st.session_state.get(collection, [])
        if safe_text(item.get(identity_key) or item.get("id")) != wanted
    ]


def visible_language_resource_connections(include_disabled: bool = True) -> List[Dict[str, Any]]:
    user = current_user() or {}
    user_email = safe_text(user.get("email")).lower()
    workspace = safe_text(user.get("workspace") or "Demo Workspace")
    rows = language_resource_collection_records(
        "integration_connections",
        SESSION_COLLECTION_LIMITS.get("integration_connections", 500),
    )
    visible: List[Dict[str, Any]] = []
    for row in rows:
        scope = safe_text(row.get("scope") or "Personal")
        row_email = safe_text(row.get("user_email") or row.get("owner_user_id")).lower()
        row_workspace = safe_text(row.get("workspace"))
        personal = scope.lower().startswith("personal")
        workspace_shared = scope.lower().startswith("workspace")
        if personal and row_email != user_email:
            continue
        if workspace_shared and row_workspace != workspace and not is_platform_owner_identity(user):
            continue
        if not include_disabled and safe_text(row.get("status")).lower() in {"disabled", "revoked", "deleted"}:
            continue
        visible.append(dict(row))
    visible.sort(key=lambda item: (not bool(item.get("is_personal_default")), int(item.get("priority", 100) or 100), safe_text(item.get("connection_name")).lower()))
    return visible


def language_resource_connection_by_id(connection_id: str) -> Optional[Dict[str, Any]]:
    wanted = safe_text(connection_id)
    if not wanted:
        return None
    for item in visible_language_resource_connections(include_disabled=True):
        if safe_text(item.get("connection_id") or item.get("id")) == wanted:
            return dict(item)
    return None


def visible_resource_bindings(include_disabled: bool = False) -> List[Dict[str, Any]]:
    user = current_user() or {}
    user_email = safe_text(user.get("email")).lower()
    workspace = safe_text(user.get("workspace") or "Demo Workspace")
    rows = language_resource_collection_records(
        "resource_bindings",
        SESSION_COLLECTION_LIMITS.get("resource_bindings", 1000),
    )
    visible = []
    for row in rows:
        if safe_text(row.get("workspace")) != workspace and not is_platform_owner_identity(user):
            continue
        if safe_text(row.get("user_email")).lower() not in {"", user_email} and not has_permission("integrations.resources.bind", user):
            continue
        if not include_disabled and not bool(row.get("enabled", True)):
            continue
        visible.append(dict(row))
    visible.sort(key=lambda item: int(item.get("priority", 100) or 100))
    return visible


def record_integration_audit(
    connection_id: str,
    action: str,
    success: bool,
    provider_status_code: Optional[int] = None,
    latency_ms: Optional[int] = None,
    metadata: Optional[Dict[str, Any]] = None,
) -> None:
    user = current_user() or {}
    record = {
        "audit_id": uuid.uuid4().hex,
        "connection_id": safe_text(connection_id),
        "workspace": safe_text(user.get("workspace") or "Demo Workspace"),
        "user_email": safe_text(user.get("email")).lower(),
        "user_id": safe_text(user.get("email")).lower(),
        "action": safe_text(action),
        "success": bool(success),
        "provider_status_code": provider_status_code,
        "latency_ms": latency_ms,
        "metadata_json": metadata or {},
        "created_at": now_stamp(),
    }
    persisted = persist_saas_record("integration_audit", record)
    upsert_session_record("integration_audit", persisted, "audit_id")


def save_language_resource_connection(record: Dict[str, Any]) -> Dict[str, Any]:
    persisted = persist_saas_record("integration_connections", record)
    upsert_session_record("integration_connections", persisted, "connection_id")
    return persisted


def save_resource_binding(record: Dict[str, Any]) -> Dict[str, Any]:
    persisted = persist_saas_record("resource_bindings", record)
    upsert_session_record("resource_bindings", persisted, "binding_id")
    return persisted


def delete_language_resource_connection(connection_id: str) -> bool:
    wanted = safe_text(connection_id)
    if not wanted:
        return False
    record = language_resource_connection_by_id(wanted)
    record_id = safe_text((record or {}).get("id") or wanted)
    deleted = False
    if delete_saas_record is not None and record_id:
        try:
            user = current_user() or {}
            deleted = delete_saas_record(
                "integration_connections",
                record_id,
                workspace=safe_text(user.get("workspace")),
                user_email=safe_text(user.get("email")).lower(),
            )
        except Exception as exc:
            LOGGER.warning("Unable to delete language resource connection %s: %s", wanted, exc)
    remove_session_record("integration_connections", "connection_id", wanted)
    for binding in list(visible_resource_bindings(include_disabled=True)):
        if safe_text(binding.get("connection_id")) == wanted:
            remove_session_record("resource_bindings", "binding_id", safe_text(binding.get("binding_id") or binding.get("id")))
    record_integration_audit(wanted, "delete_connection", True)
    return deleted or True


def connection_connector_config(connection: Dict[str, Any], api_secret: str = "") -> ConnectorConfig:
    return ConnectorConfig(
        connection_id=safe_text(connection.get("connection_id") or connection.get("id")),
        provider=safe_text(connection.get("provider") or "Generic REST"),
        connection_name=safe_text(connection.get("connection_name") or "External resources"),
        base_url=safe_text(connection.get("base_url")),
        auth_type=safe_text(connection.get("auth_type") or "Bearer token"),
        api_secret=api_secret,
        organization_id=safe_text(connection.get("organization_id")),
        provider_workspace_id=safe_text(connection.get("provider_workspace_id")),
    )


def decrypt_language_resource_secret(connection: Dict[str, Any]) -> str:
    encrypted = safe_text(connection.get("encrypted_secret"))
    if not encrypted:
        return ""
    master = language_resource_master_key()
    if not master:
        raise LanguageResourceSecretError("missing_master_key", "Language-resource encryption key is not configured.")
    return decrypt_api_secret(encrypted, master)


def test_language_resource_connection(connection: Dict[str, Any], api_secret: str = "") -> Tuple[Dict[str, Any], Optional[LanguageResourceError]]:
    start = time.perf_counter()
    connection_id = safe_text(connection.get("connection_id") or connection.get("id") or uuid.uuid4().hex)
    try:
        secret_value = api_secret or decrypt_language_resource_secret(connection)
        connector = make_connector(connection_connector_config(connection, secret_value))
        result = connector.test_connection()
        result["last_tested_at"] = now_stamp()
        record_integration_audit(
            connection_id,
            "test_connection",
            True,
            latency_ms=int((time.perf_counter() - start) * 1000),
            metadata={
                "provider": safe_text(connection.get("provider")),
                "tm_count": result.get("tm_count", 0),
                "glossary_count": result.get("glossary_count", 0),
                "dnt_count": result.get("dnt_count", 0),
            },
        )
        return result, None
    except Exception as exc:
        err = exc if isinstance(exc, LanguageResourceError) else LanguageResourceError("provider_error", "External language resource connection failed.")
        record_integration_audit(
            connection_id,
            "test_connection",
            False,
            provider_status_code=getattr(err, "status_code", None),
            latency_ms=int((time.perf_counter() - start) * 1000),
            metadata={"error_code": getattr(err, "code", "provider_error")},
        )
        return {}, err


def active_language_resource_connections(project_id: str = "") -> List[Tuple[Dict[str, Any], Dict[str, Any]]]:
    connections = visible_language_resource_connections(include_disabled=False)
    by_id = {safe_text(item.get("connection_id") or item.get("id")): item for item in connections}
    project_key = safe_text(project_id)
    active: List[Tuple[Dict[str, Any], Dict[str, Any]]] = []
    seen: Set[str] = set()
    for binding in visible_resource_bindings(include_disabled=False):
        if project_key and safe_text(binding.get("project_id")) not in {"", project_key}:
            continue
        connection = by_id.get(safe_text(binding.get("connection_id")))
        if not connection:
            continue
        cid = safe_text(connection.get("connection_id") or connection.get("id"))
        active.append((connection, binding))
        seen.add(cid)
    for connection in connections:
        cid = safe_text(connection.get("connection_id") or connection.get("id"))
        if cid in seen:
            continue
        if bool(connection.get("is_personal_default")) or not active:
            active.append((connection, {}))
            seen.add(cid)
    return active[:5]


def get_language_resource_cache(cache_key: str) -> Optional[Dict[str, Any]]:
    now = time.time()
    cache = st.session_state.setdefault("_language_resource_runtime_cache", {})
    item = cache.get(cache_key)
    if not isinstance(item, dict):
        return None
    if float(item.get("expires_epoch", 0) or 0) < now:
        cache.pop(cache_key, None)
        return None
    value = item.get("value")
    return dict(value) if isinstance(value, dict) else None


def set_language_resource_cache(cache_key: str, value: Dict[str, Any], cache_seconds: int) -> None:
    ttl = max(30, min(int(cache_seconds or DEFAULT_CACHE_SECONDS), 3600))
    cache = st.session_state.setdefault("_language_resource_runtime_cache", {})
    cache[cache_key] = {
        "expires_epoch": time.time() + ttl,
        "value": value,
    }
    if len(cache) > 200:
        for key, item in sorted(cache.items(), key=lambda pair: float((pair[1] or {}).get("expires_epoch", 0) or 0))[:-160]:
            cache.pop(key, None)


def dedupe_external_results(results: List[Dict[str, Any]], key_fields: Tuple[str, ...], limit: int) -> List[Dict[str, Any]]:
    deduped: List[Dict[str, Any]] = []
    seen: Dict[Tuple[str, ...], Dict[str, Any]] = {}
    for item in results:
        key = tuple(safe_text(item.get(field)).lower() for field in key_fields)
        if key in seen:
            existing = seen[key]
            providers = set(coerce_string_list(existing.get("providers") or existing.get("provider")))
            providers.add(safe_text(item.get("provider")))
            existing["providers"] = sorted(provider for provider in providers if provider)
            try:
                if float(item.get("match_score") or 0) > float(existing.get("match_score") or 0):
                    existing["match_score"] = item.get("match_score")
            except (TypeError, ValueError):
                pass
            continue
        copy = dict(item)
        copy["providers"] = [safe_text(item.get("provider"))] if safe_text(item.get("provider")) else []
        seen[key] = copy
        deduped.append(copy)
    return deduped[:limit]


def external_language_resource_lookup(
    source_text: str,
    source_language: str = "",
    target_language: str = "",
    project_id: str = "",
) -> Dict[str, Any]:
    source = safe_text(source_text)
    if not source or not has_permission("integrations.external_resources.use"):
        return {"tm": [], "glossary": [], "dnt": [], "connections": [], "errors": []}

    tm_results: List[Dict[str, Any]] = []
    glossary_results: List[Dict[str, Any]] = []
    dnt_results: List[Dict[str, Any]] = []
    statuses: List[Dict[str, Any]] = []
    errors: List[Dict[str, str]] = []

    for connection, binding in active_language_resource_connections(project_id):
        connection_id = safe_text(connection.get("connection_id") or connection.get("id"))
        if not bool(connection.get("automatic_lookup_enabled", True)):
            continue
        src_lang = safe_text(binding.get("source_language") or connection.get("source_language") or source_language)
        tgt_lang = safe_text(binding.get("target_language") or connection.get("target_language") or target_language)
        cache_seconds = int(connection.get("cache_seconds") or DEFAULT_CACHE_SECONDS)
        cache_key = language_resource_lookup_hash(connection_id, source, src_lang, tgt_lang, "all")
        cached = get_language_resource_cache(cache_key)
        if cached:
            for key in ("tm", "glossary", "dnt"):
                for item in cached.get(key, []):
                    copy = dict(item)
                    copy["cached"] = True
                    if key == "tm":
                        tm_results.append(copy)
                    elif key == "glossary":
                        glossary_results.append(copy)
                    else:
                        dnt_results.append(copy)
            statuses.append({"connection": safe_text(connection.get("connection_name")), "status": "cached"})
            continue
        try:
            api_secret = decrypt_language_resource_secret(connection)
            connector = make_connector(connection_connector_config(connection, api_secret))
            tm_ids = coerce_string_list(binding.get("tm_resource_ids") or connection.get("tm_resource_ids"))
            glossary_ids = coerce_string_list(binding.get("glossary_resource_ids") or connection.get("glossary_resource_ids"))
            dnt_ids = coerce_string_list(binding.get("dnt_resource_ids") or connection.get("dnt_resource_ids"))
            tm = connector.search_tm(source, src_lang, tgt_lang, limit=5, resource_ids=tm_ids)
            glossary = connector.lookup_terms(source, src_lang, tgt_lang, resource_ids=glossary_ids)
            dnt = connector.lookup_dnt(source, src_lang, resource_ids=dnt_ids)
            payload = {"tm": tm, "glossary": glossary, "dnt": dnt}
            set_language_resource_cache(cache_key, payload, cache_seconds)
            tm_results.extend(tm)
            glossary_results.extend(glossary)
            dnt_results.extend(dnt)
            statuses.append({"connection": safe_text(connection.get("connection_name")), "status": "connected"})
        except Exception as exc:
            err = exc if isinstance(exc, LanguageResourceError) else LanguageResourceError("provider_error", "External language resource lookup failed.")
            errors.append(
                {
                    "connection": safe_text(connection.get("connection_name")),
                    "code": safe_text(getattr(err, "code", "provider_error")),
                    "message": safe_text(str(err)),
                }
            )
            statuses.append({"connection": safe_text(connection.get("connection_name")), "status": "degraded"})
            record_integration_audit(
                connection_id,
                "editor_lookup",
                False,
                provider_status_code=getattr(err, "status_code", None),
                metadata={"error_code": getattr(err, "code", "provider_error")},
            )

    def tm_sort(item: Dict[str, Any]) -> Tuple[int, float, str]:
        exact = 1 if safe_text(item.get("source_text")).lower() == source.lower() else 0
        try:
            score = float(item.get("match_score") or 0)
        except (TypeError, ValueError):
            score = 0.0
        return (exact, score, safe_text(item.get("updated_at")))

    tm_results = sorted(tm_results, key=tm_sort, reverse=True)
    return {
        "tm": dedupe_external_results(tm_results, ("source_text", "target_text"), 8),
        "glossary": dedupe_external_results(glossary_results, ("source_term", "target_term"), 12),
        "dnt": dedupe_external_results(dnt_results, ("term",), 12),
        "connections": statuses,
        "errors": errors,
    }


def add_audit(action: str, details: str = "") -> None:
    record = {
        "time": now_stamp(),
        "actor": (current_user() or {}).get("email", "unknown"),
        "workspace": (current_user() or {}).get("workspace", "Demo Workspace"),
        "action": action,
        "details": details,
    }
    record = persist_saas_record("audit_logs", record)
    st.session_state.audit_logs.insert(0, record)
    trim_session_list("audit_logs")


AUDIT_CHAIN_VERSION = "errorsweep-audit-chain-v1"


def audit_sort_key(record: Dict[str, Any]) -> str:
    parsed = parse_record_datetime(record.get("created_at") or record.get("time") or record.get("updated_at"))
    if parsed:
        return parsed.isoformat()
    return safe_text(record.get("time") or record.get("created_at") or record.get("updated_at") or record.get("id"))


def canonical_audit_record(record: Dict[str, Any]) -> Dict[str, Any]:
    excluded = {"sequence", "record_hash", "previous_chain_hash", "chain_hash", "chain_valid"}
    canonical = {}
    for key, value in sorted((record or {}).items(), key=lambda item: safe_text(item[0])):
        if key in excluded:
            continue
        if isinstance(value, (dict, list, tuple)):
            canonical[safe_text(key)] = json.loads(json.dumps(value, ensure_ascii=False, default=safe_text))
        else:
            canonical[safe_text(key)] = safe_text(value) if value is not None else ""
    return canonical


def audit_record_digest(record: Dict[str, Any]) -> str:
    payload = json.dumps(canonical_audit_record(record), ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(payload.encode("utf-8")).hexdigest()


def audit_chain_rows(records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    sorted_records = sorted([dict(item) for item in records or []], key=audit_sort_key)
    previous_hash = "0" * 64
    rows = []
    for index, record in enumerate(sorted_records, start=1):
        record_hash = audit_record_digest(record)
        chain_payload = json.dumps(
            {
                "version": AUDIT_CHAIN_VERSION,
                "sequence": index,
                "previous_chain_hash": previous_hash,
                "record_hash": record_hash,
            },
            sort_keys=True,
            separators=(",", ":"),
        )
        chain_hash = hashlib.sha256(chain_payload.encode("utf-8")).hexdigest()
        rows.append({
            "sequence": index,
            "record_hash": record_hash,
            "previous_chain_hash": previous_hash,
            "chain_hash": chain_hash,
            "chain_valid": True,
            **record,
        })
        previous_hash = chain_hash
    return rows


def audit_snapshot_report(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    chain_rows = audit_chain_rows(records)
    return {
        "export_type": "errorsweep_tamper_evident_audit_snapshot",
        "version": AUDIT_CHAIN_VERSION,
        "generated_at": now_stamp(),
        "requested_by": safe_text((current_user() or {}).get("email")),
        "record_count": len(chain_rows),
        "first_event": chain_rows[0].get("time") if chain_rows else "",
        "last_event": chain_rows[-1].get("time") if chain_rows else "",
        "hash_algorithm": "sha256",
        "genesis_hash": "0" * 64,
        "final_chain_hash": chain_rows[-1].get("chain_hash") if chain_rows else "",
        "records": chain_rows,
    }


def audit_snapshot_json(records: List[Dict[str, Any]]) -> str:
    return json.dumps(audit_snapshot_report(records), ensure_ascii=False, indent=2, default=safe_text)


