    add("SSO", "ERRORSWEEP_SSO_HANDOFF_SECRET", secret_is_configured("ERRORSWEEP_SSO_HANDOFF_SECRET"), "Live SSO handoff", "Shared secret used by the trusted IdP/broker to sign short-lived CogniSweep handoff tokens.")
