def render_external_editor_router() -> bool:
    route = get_current_route()
    if route.get("route") == "human_review_editor":
        review_id = safe_text(route.get("review_id") or query_get("review_id"))
        if not review_id:
            st.error("Missing review_id. Open Human Review Editor from the Translation Studio result page.")
            return True
        if not load_external_editor_payload(review_id):
            st.error("Review not found. Go back to the Translation Studio result page and open the Human Review Editor again.")
            return True
        render_external_cat_editor(review_id)
        return True
    requested_page = safe_text(route.get("page") or route.get("es_page"))
    if requested_page in HUMAN_REVIEW_EDITOR_PAGES:
        review_id = safe_text(route.get("review_id") or query_get("review_id"))
        if not review_id:
            st.error("Missing review_id. Open Human Review Editor from the Translation Studio result page.")
            return True
        if not load_external_editor_payload(review_id):
            st.error("Review not found. Go back to the Translation Studio result page and open the Human Review Editor again.")
            return True
        render_external_cat_editor(review_id)
        return True
    editor_type = safe_text(route.get("es_editor") or query_get("es_editor"))
    if not editor_type:
        return False
    if editor_type == "human_review":
        review_id = safe_text(route.get("review_id") or query_get("review_id"))
        if not review_id:
            st.error("Missing review_id. Open Human Review Editor from the Translation Studio result page.")
            return True
        if not load_external_editor_payload(review_id):
            st.error("Review not found. Go back to the Translation Studio result page and open the Human Review Editor again.")
            return True
        render_external_cat_editor(review_id)
        return True
    job_id = safe_text(route.get("job_id") or query_get("job_id"))
    if editor_type == "cat":
        render_external_cat_editor(job_id)
        return True
    if editor_type == "media":
        render_external_media_editor(job_id)
        return True
    st.error("Unknown editor route.")
    return True



def build_reviewed_translation_workbook(rows: List[Dict[str, Any]]) -> bytes:
    """Excel output from Human Review. Always safe and easy for clients to review."""
    wb = Workbook()
    ws = wb.active
    ws.title = "Reviewed Translation"
    headers = ["Segment ID", "Location", "Source Text", "Final Translation", "Status", "Match", "Language", "Notes"]
    ws.append(headers)
    for row in rows:
        source_text = safe_text(row.get("source", ""))
        target_text = repair_localization_translation(source_text, row.get("target", ""))
        ws.append([
            row.get("id", ""),
            row.get("location", ""),
            source_text,
            target_text,
            row.get("status", ""),
            row.get("match", ""),
            row.get("language", ""),
            row.get("notes", ""),
        ])
    for cell in ws[1]:
        cell.font = Font(bold=True, color="FFFFFF")
        cell.fill = PatternFill(start_color="1F4E78", end_color="1F4E78", fill_type="solid")
        cell.alignment = Alignment(wrap_text=True, vertical="top")
    widths = {"A": 12, "B": 22, "C": 55, "D": 55, "E": 18, "F": 14, "G": 16, "H": 28}
    for col, width in widths.items():
        ws.column_dimensions[col].width = width
    for row in ws.iter_rows(min_row=2):
        for cell in row:
            cell.alignment = Alignment(wrap_text=True, vertical="top")
    bio = io.BytesIO()
    wb.save(bio)
    bio.seek(0)
    return bio.getvalue()


def build_reviewed_plain_text(rows: List[Dict[str, Any]]) -> bytes:
    return "\n".join(repair_localization_translation(r.get("source", ""), r.get("target", "")) for r in rows).encode("utf-8-sig")


COMPLETED_WITH_WARNINGS_STATUS = "Completed with warnings"
COMPLETION_STATUS_VALUES = {
    "approved",
    "confirmed",
    "done",
    "complete",
    "completed",
    "submitted",
    COMPLETED_WITH_WARNINGS_STATUS.lower(),
}
COMPLETION_IGNORED_FINDINGS_KEYS = (
    "ignored_validation_findings",
    "ignoredValidationFindings",
    "completion_validation_findings",
    "completionValidationFindings",
)


def normalize_completion_validation_finding(
    finding: Any,
    row: Optional[Dict[str, Any]] = None,
    editor_type: str = "",
    row_index: int = 0,
) -> Dict[str, Any]:
    row = row or {}
    if isinstance(finding, dict):
        severity = safe_text(
            finding.get("Severity")
            or finding.get("severity")
            or finding.get("Status")
            or finding.get("label")
            or "Review"
        )
        message = safe_text(
            finding.get("Wrong Part")
            or finding.get("Explanation")
            or finding.get("issue")
            or finding.get("message")
            or finding.get("Check")
            or "Review this segment before completing it."
        )
        category = safe_text(finding.get("Error Type") or finding.get("category") or finding.get("type") or "Validation")
        suggestion = safe_text(finding.get("Suggestion") or finding.get("action") or finding.get("fix") or "")
        location = safe_text(finding.get("Location") or finding.get("Segment ID") or finding.get("row") or f"Segment {row_index or row.get('id', '')}")
        source = safe_text(finding.get("Source Text") or row.get("source", ""))
        target = safe_text(finding.get("Translation") or row.get("target") or row.get("translation") or "")
        rule_id = safe_text(finding.get("Rule ID") or finding.get("rule_id") or "")
    else:
        severity = "Review"
        message = safe_text(finding) or "Review this segment before completing it."
        category = "Validation"
        suggestion = ""
        location = f"Segment {row_index or row.get('id', '')}"
        source = safe_text(row.get("source", ""))
        target = safe_text(row.get("target") or row.get("translation") or "")
        rule_id = ""

    return {
        "row": row_index or row.get("id") or "",
        "location": location,
        "editor": safe_text(editor_type) or "editor",
        "severity": severity or "Review",
        "category": category or "Validation",
        "message": message,
        "suggestion": suggestion,
        "source": source,
        "target": target,
        "rule_id": rule_id,
    }


def row_completion_ignored_findings(row: Dict[str, Any]) -> List[Dict[str, Any]]:
    if not isinstance(row, dict):
        return []
    raw_findings: Any = None
    for key in COMPLETION_IGNORED_FINDINGS_KEYS:
        value = row.get(key)
        if isinstance(value, list):
            raw_findings = value
            break
    if raw_findings is None:
        validation_meta = row.get("completion_validation") or row.get("completionValidation")
        if isinstance(validation_meta, dict):
            for key in ("ignored_findings", "ignoredFindings", "findings"):
                if isinstance(validation_meta.get(key), list):
                    raw_findings = validation_meta.get(key)
                    break
    if not isinstance(raw_findings, list):
        return []
    return [
        normalize_completion_validation_finding(item, row=row, editor_type=safe_text(row.get("editor_type")), row_index=idx + 1)
        for idx, item in enumerate(raw_findings)
    ]


def store_ignored_completion_findings(
    row: Dict[str, Any],
    findings: List[Dict[str, Any]],
    editor_type: str = "",
) -> None:
    try:
        row_index = int(row.get("id") or 0)
    except Exception:
        row_index = 0
    normalized = [
        normalize_completion_validation_finding(item, row=row, editor_type=editor_type, row_index=row_index)
        for item in findings or []
    ]
    if not normalized:
        row.pop("ignored_validation_findings", None)
        row.pop("ignoredValidationFindings", None)
        row.pop("completion_validation", None)
        row.pop("completionValidation", None)
        return
    ignored_at = now_stamp()
    ignored_by = current_editor_identity()
    for item in normalized:
        item["ignored_at"] = ignored_at
        item["ignored_by"] = ignored_by
    row["ignored_validation_findings"] = normalized
    row["ignoredValidationFindings"] = normalized
    row["completion_validation"] = {
        "status": "ignored",
        "ignored_at": ignored_at,
        "ignored_by": ignored_by,
        "editor": safe_text(editor_type) or safe_text(row.get("editor_type")) or "editor",
        "ignored_findings": normalized,
    }
    row["completionValidation"] = {
        "status": "ignored",
        "ignoredAt": ignored_at,
        "ignoredBy": ignored_by,
        "editor": safe_text(editor_type) or safe_text(row.get("editor_type")) or "editor",
        "ignoredFindings": normalized,
    }


def is_completed_with_warnings(row: Dict[str, Any]) -> bool:
    return safe_text(row.get("status")).strip().lower() == COMPLETED_WITH_WARNINGS_STATUS.lower() or bool(row_completion_ignored_findings(row))


def is_segment_confirmed(row: Dict[str, Any]) -> bool:
    raw = row.get("confirmed", row.get("segment_confirmed", ""))
    if isinstance(raw, bool):
        return raw
    if safe_text(raw).strip().lower() in {"1", "true", "yes", "y", "done", "confirmed", "approved", COMPLETED_WITH_WARNINGS_STATUS.lower()}:
        return True
    return safe_text(row.get("status", "")).strip().lower() in COMPLETION_STATUS_VALUES


def set_segment_confirmed(
    row: Dict[str, Any],
    confirmed: bool,
    target: str = "",
    ignored_findings: Optional[List[Dict[str, Any]]] = None,
    editor_type: str = "",
) -> None:
    row["confirmed"] = bool(confirmed)
    row["segment_confirmed"] = bool(confirmed)
    if confirmed:
        if ignored_findings is not None:
            store_ignored_completion_findings(row, ignored_findings, editor_type=editor_type)
        row["status"] = COMPLETED_WITH_WARNINGS_STATUS if row_completion_ignored_findings(row) else "Approved"
        row["confirmed_by"] = current_editor_identity()
        row["confirmed_at"] = now_stamp()
        if target:
            row["target"] = target
            row["translation"] = target
    else:
        row.pop("confirmed_by", None)
        row.pop("confirmed_at", None)
        store_ignored_completion_findings(row, [], editor_type=editor_type)
        if safe_text(row.get("status", "")).strip().lower() in {"approved", COMPLETED_WITH_WARNINGS_STATUS.lower()}:
            row["status"] = "Needs Review" if safe_text(target or row.get("target", "")).strip() else "Untranslated"


def _completion_time_seconds(value: Any) -> Optional[float]:
    if isinstance(value, (int, float)):
        return float(value)
    raw = safe_text(value).strip()
    if not raw:
        return None
    if re.fullmatch(r"\d+(?:\.\d+)?", raw):
        return float(raw)
    if re.fullmatch(r"\d{1,2}:\d{2}(?::\d{2})?(?:[\.,]\d+)?", raw):
        return parse_timecode(raw)
    return None


def segment_completion_validation_findings(
    row: Dict[str, Any],
    editor_type: str = "translation",
    all_rows: Optional[List[Dict[str, Any]]] = None,
    row_index: int = 0,
    target_language: str = "",
    domain: str = "",
    rules: Optional[Dict[str, Any]] = None,
) -> List[Dict[str, Any]]:
    if not isinstance(row, dict):
        return []
    if is_segment_confirmed(row) and is_completed_with_warnings(row):
        return []

    editor_key = safe_text(editor_type).strip().lower()
    row_number = row_index
    if not row_number:
        raw_id = safe_text(row.get("id"))
        row_number = int(raw_id) if raw_id.isdigit() else 1
    candidate = dict(row)
    candidate.setdefault("id", row_number)
    candidate.setdefault("location", f"Segment {row_number}")
    candidate["target"] = safe_text(candidate.get("target") or candidate.get("translation") or "")
    candidate["translation"] = candidate["target"]
    candidate["source"] = safe_text(candidate.get("source") or candidate.get("text") or "")

    findings: List[Dict[str, Any]] = []
    if editor_key in {"translation", "cat", "human_review", "review"}:
        findings.extend(delivery_quality_findings([candidate], target_language or "Target", domain or "Human Review", rules))
    else:
        start_value = _completion_time_seconds(candidate.get("start"))
        end_value = _completion_time_seconds(candidate.get("end"))
        text_value = candidate["target"] or (candidate["source"] if editor_key == "transcription" else "")
        if start_value is None or end_value is None:
            findings.append(qa_manual_finding(candidate, "Major", "Timing", "Start or end time is not valid.", "Use a valid timecode before completing this row."))
        elif end_value <= start_value:
            findings.append(qa_manual_finding(candidate, "Major", "Timing", "End time must be after start time.", "Move the end time after the start time."))
        if start_value is not None and all_rows and row_number > 1:
            previous = all_rows[row_number - 2] if row_number - 2 < len(all_rows) else {}
            previous_end = _completion_time_seconds(previous.get("end")) if isinstance(previous, dict) else None
            if previous_end is not None and start_value < previous_end:
                findings.append(qa_manual_finding(candidate, "Major", "Timing", "Segment overlaps the previous segment.", "Adjust the start or previous end time."))
        if not text_value.strip():
            label = "Transcript text is blank." if editor_key == "transcription" else "Target subtitle text is blank."
            findings.append(qa_manual_finding(candidate, "Major", "Completeness", label, "Add the missing text before completing this row."))
        if editor_key != "transcription" and start_value is not None and end_value is not None and end_value > start_value:
            duration = max(0.1, end_value - start_value)
            cps = round(len(text_value) / duration)
            if cps > 20:
                findings.append(qa_manual_finding(candidate, "Review", "Readability", f"Reading speed is {cps} CPS.", "Shorten the subtitle or adjust timing."))
            if len(text_value) > 84:
                findings.append(qa_manual_finding(candidate, "Review", "Subtitle Length", "Target text is long for a two-line subtitle.", "Split or shorten the subtitle."))

    if isinstance(row.get("qa_findings"), list):
        findings.extend(item for item in row.get("qa_findings", []) if isinstance(item, dict))
    return [
        normalize_completion_validation_finding(item, row=candidate, editor_type=editor_key or "editor", row_index=row_number)
        for item in dedupe_qa_findings(findings)
    ]


def render_completion_validation_popover(
    row: Dict[str, Any],
    findings: List[Dict[str, Any]],
    key_prefix: str,
    target: str = "",
    editor_type: str = "translation",
) -> bool:
    if not findings:
        return False
    popover_factory = getattr(st, "popover", None)
    if callable(popover_factory):
        warning_container = popover_factory("Completion warnings", use_container_width=True)
    else:
        warning_container = st.expander("Completion warnings", expanded=True)
    with warning_container:
        st.caption("Resolve these findings or explicitly ignore them before marking this row complete.")
        for finding in findings[:8]:
            severity = safe_text(finding.get("severity") or "Review")
            message = safe_text(finding.get("message") or "Review this segment.")
            suggestion = safe_text(finding.get("suggestion"))
            st.markdown(f"- **{escape(severity)}**: {escape(message)}" + (f" _{escape(suggestion)}_" if suggestion else ""))
        col_return, col_ignore, col_cancel = st.columns(3)
        if col_return.button("Return to segment", key=f"{key_prefix}_validation_return", use_container_width=True):
            st.session_state.pop(f"{key_prefix}_completion_validation_findings", None)
            return False
        if col_ignore.button("Ignore and mark complete", key=f"{key_prefix}_validation_ignore", use_container_width=True):
            set_segment_confirmed(row, True, target, ignored_findings=findings, editor_type=editor_type)
            st.session_state.pop(f"{key_prefix}_completion_validation_findings", None)
            return True
        if col_cancel.button("Cancel", key=f"{key_prefix}_validation_cancel", use_container_width=True):
            st.session_state.pop(f"{key_prefix}_completion_validation_findings", None)
            return False
    return False


def render_segment_confirmation_checkbox(
    row: Dict[str, Any],
    key_prefix: str,
    target: str = "",
    editor_type: str = "translation",
    all_rows: Optional[List[Dict[str, Any]]] = None,
    row_index: int = 0,
    target_language: str = "",
    domain: str = "",
    rules: Optional[Dict[str, Any]] = None,
) -> bool:
    before = is_segment_confirmed(row)
    checkbox_key = f"{key_prefix}_segment_completed"
    pending_key = f"{key_prefix}_completion_validation_findings"
    confirmed = st.checkbox(
        "Segment completed",
        value=before,
        key=checkbox_key,
        help="Tick this after translation or editing is complete. Unticked segments remain pending.",
    )
    if confirmed != before:
        if confirmed:
            candidate = dict(row)
            candidate["target"] = target or safe_text(candidate.get("target") or candidate.get("translation"))
            findings = segment_completion_validation_findings(
                candidate,
                editor_type=editor_type,
                all_rows=all_rows,
                row_index=row_index,
                target_language=target_language,
                domain=domain,
                rules=rules,
            )
            if findings:
                st.session_state[pending_key] = findings
                st.session_state[checkbox_key] = False
            else:
                set_segment_confirmed(row, True, target, editor_type=editor_type)
                return True
        else:
            set_segment_confirmed(row, False, target, editor_type=editor_type)
            st.session_state.pop(pending_key, None)
            return True
    pending_findings = st.session_state.get(pending_key)
    if isinstance(pending_findings, list) and render_completion_validation_popover(row, pending_findings, key_prefix, target, editor_type):
        st.session_state[checkbox_key] = True
        return True
    return False


def unconfirmed_segment_count(rows: List[Dict[str, Any]]) -> int:
    return sum(1 for row in rows if not is_segment_confirmed(row))


def all_segments_confirmed(rows: List[Dict[str, Any]]) -> bool:
    return bool(rows) and unconfirmed_segment_count(rows) == 0


def apply_validated_completion_flags(
    rows: List[Dict[str, Any]],
    editor_type: str = "translation",
    target_language: str = "",
    domain: str = "",
    rules: Optional[Dict[str, Any]] = None,
) -> int:
    blocked = 0
    for idx, row in enumerate(rows or []):
        if not isinstance(row, dict):
            continue
        target_value = safe_text(row.get("target") or row.get("translation") or "")
        requested_complete = bool(row.get("confirmed") or row.get("done") or is_completed_with_warnings(row))
        if requested_complete:
            findings = segment_completion_validation_findings(
                row,
                editor_type=editor_type,
                all_rows=rows,
                row_index=idx + 1,
                target_language=target_language,
                domain=domain,
                rules=rules,
            )
            if findings:
                set_segment_confirmed(row, False, target_value, editor_type=editor_type)
                row["done"] = False
                blocked += 1
                continue
            set_segment_confirmed(row, True, target_value, editor_type=editor_type)
        else:
            set_segment_confirmed(row, False, target_value, editor_type=editor_type)
            row["done"] = False
    return blocked


def compute_review_completion(rows: List[Dict[str, Any]]) -> Dict[str, int]:
    total = len(rows)
    translated = sum(1 for r in rows if safe_text(r.get("target", "")).strip())
    approved = sum(1 for r in rows if is_segment_confirmed(r))
    needs_review = sum(1 for r in rows if not is_segment_confirmed(r) or not safe_text(r.get("target", "")).strip())
    return {"total": total, "translated": translated, "approved": approved, "needs_review": needs_review}


def compute_matches(source: str, source_language: str = "", target_language: str = "", project_id: str = "") -> Dict[str, List[Dict[str, Any]]]:
    source_l = source.lower()
    tm_hits: List[Dict[str, Any]] = translation_memory_matches(source, source_language, target_language, limit=8)
    seen_tm_hits: Set[Tuple[str, str]] = {
        (safe_text(item.get("source")).lower(), safe_text(item.get("target")).lower())
        for item in tm_hits
    }
    for item in st.session_state.tm:
        if item.get("source", "").lower() == source_l:
            key = (safe_text(item.get("source")).lower(), safe_text(item.get("target")).lower())
            if key not in seen_tm_hits:
                seen_tm_hits.add(key)
                tm_hits.append({"type": "TM 100%", "source": item.get("source",""), "target": item.get("target","")})
        elif source_l and item.get("source", "").lower() in source_l:
            key = (safe_text(item.get("source")).lower(), safe_text(item.get("target")).lower())
            if key not in seen_tm_hits:
                seen_tm_hits.add(key)
                tm_hits.append({"type": "TM fuzzy", "source": item.get("source",""), "target": item.get("target","")})

    gloss_hits: List[Dict[str, Any]] = []
    for item in st.session_state.glossary:
        if item.get("source","").lower() in source_l:
            gloss_hits.append(item)

    dnt_hits: List[Dict[str, Any]] = [{"term": term} for term in st.session_state.dnt if term.lower() in source_l]
    external = external_language_resource_lookup(source, source_language, target_language, project_id)
    for item in external.get("tm", []):
        score = safe_text(item.get("match_score"))
        tm_hits.append(
            {
                "type": f"{safe_text(item.get('provider') or 'External TM')} {score + '%' if score else ''}".strip(),
                "source": safe_text(item.get("source_text")),
                "target": safe_text(item.get("target_text")),
                "provider": safe_text(item.get("provider")),
                "resource_name": safe_text(item.get("resource_name")),
                "cached": bool(item.get("cached")),
            }
        )
    for item in external.get("glossary", []):
        gloss_hits.append(
            {
                "source": safe_text(item.get("source_term")),
                "target": safe_text(item.get("target_term")),
                "notes": " · ".join(part for part in [safe_text(item.get("provider")), safe_text(item.get("resource_name")), safe_text(item.get("definition"))] if part),
                "provider": safe_text(item.get("provider")),
            }
        )
    for item in external.get("dnt", []):
        dnt_hits.append(
            {
                "term": safe_text(item.get("term")),
                "provider": safe_text(item.get("provider")),
                "instruction": safe_text(item.get("instruction")),
            }
        )
    return {
        "tm": tm_hits[:8],
        "glossary": gloss_hits[:12],
        "dnt": dnt_hits[:12],
        "connections": external.get("connections", []),
        "errors": external.get("errors", []),
    }


def editor_predictive_suggestions(source: str, target: str, matches: Dict[str, List[Dict[str, str]]], limit: int = 5) -> List[Dict[str, str]]:
    """Return lightweight CAT suggestions from TM, glossary, DNT, and tokens."""
    source = safe_text(source)
    target = safe_text(target)
    suggestions: List[Dict[str, str]] = []
    seen: set = set()

    def push(kind: str, text: str, reason: str) -> None:
        cleaned = repair_localization_translation(source, safe_text(text))
        if not cleaned:
            return
        key = cleaned.lower()
        if key in seen:
            return
        seen.add(key)
        suggestions.append({"type": kind, "text": cleaned, "reason": reason})

    for item in matches.get("tm", [])[:3]:
        push(item.get("type", "TM"), item.get("target", ""), "Translation memory suggestion")
    if target:
        for item in matches.get("glossary", [])[:5]:
            src = safe_text(item.get("source"))
            tgt = safe_text(item.get("target"))
            if src and tgt and src.lower() in source.lower() and tgt.lower() not in target.lower():
                push("Glossary", target + (" " if target and not target.endswith(" ") else "") + tgt, f"Missing glossary target for {src}")
    for token in extract_protected_tokens(source)[:5]:
        if token and token not in target:
            push("Protected token", (target + " " + token).strip(), f"Preserve {token}")
    for item in matches.get("dnt", [])[:5]:
        term = safe_text(item.get("term"))
        if term and term not in target:
            push("DNT", (target + " " + term).strip(), f"Keep do-not-translate term {term}")
    if not suggestions and target:
        repaired = repair_localization_translation(source, target)
        if repaired and repaired != target:
            push("Repaired Suggestion", repaired, "Protected tokens were repaired from the source")
    return suggestions[:limit]


def extract_protected_tokens(text: str) -> List[str]:
    tokens = LOCALIZATION_PROTECTED_RE.findall(safe_text(text))
    return list(dict.fromkeys(safe_text(token) for token in tokens if safe_text(token)))


def highlight_protected_tokens_html(text: str) -> str:
    value = safe_text(text)
    if not value:
        return ""
    parts: List[str] = []
    last = 0
    for match in LOCALIZATION_PROTECTED_RE.finditer(value):
        parts.append(escape(value[last:match.start()]))
        token = match.group(0)
        parts.append(f'<span class="es-token-protected">{escape(token)}</span>')
        last = match.end()
    parts.append(escape(value[last:]))
    return "".join(parts)


def apply_editor_find_replace(rows: List[Dict[str, Any]], find_text: str, replace_text: str, scope: str = "Target", use_regex: bool = False, case_sensitive: bool = False) -> Tuple[List[Dict[str, Any]], int, str]:
    """Bulk find/replace for editor rows. Returns updated rows, count, error."""
    find_text = safe_text(find_text)
    replace_text = safe_text(replace_text)
    if not find_text:
        return rows, 0, "Enter text or a regex pattern to find."
    updated = [dict(row) for row in rows]
    fields = ["target"] if scope == "Target" else ["source"] if scope == "Source" else ["source", "target"]
    count = 0
    flags = 0 if case_sensitive else re.IGNORECASE
    try:
        pattern = re.compile(find_text if use_regex else re.escape(find_text), flags=flags)
    except re.error as exc:
        return rows, 0, f"Invalid regex: {exc}"
    for row in updated:
        for field in fields:
            value = safe_text(row.get(field, ""))
            new_value, replacements = pattern.subn(replace_text, value)
            if replacements:
                row[field] = repair_localization_translation(row.get("source", ""), new_value) if field == "target" else new_value
                if field == "target":
                    row["translation"] = row[field]
                    if safe_text(row.get("status")) in {"Approved", "100%", "101%"}:
                        row["status"] = "Needs Review"
                count += replacements
    return updated, count, ""


def row_comments(row: Dict[str, Any]) -> List[Dict[str, str]]:
    raw = row.get("comments_json") or row.get("comments") or []
    if isinstance(raw, str):
        try:
            raw = json.loads(raw)
        except Exception:
            raw = []
    if not isinstance(raw, list):
        return []
    comments: List[Dict[str, str]] = []
    for item in raw:
        if isinstance(item, dict):
            comments.append({
                "author": safe_text(item.get("author") or item.get("user") or "Reviewer"),
                "body": safe_text(item.get("body") or item.get("comment") or ""),
                "mentions": safe_text(item.get("mentions") or ""),
                "created_at": safe_text(item.get("created_at") or item.get("time") or ""),
            })
    return [item for item in comments if item.get("body")]


def add_row_comment(row: Dict[str, Any], body: str) -> None:
    body = safe_text(body)
    if not body:
        return
    mentions = ", ".join(sorted(set(re.findall(r"@([A-Za-z0-9_.-]+)", body))))
    comments = row_comments(row)
    comments.append({
        "author": safe_text((current_user() or {}).get("email", "reviewer@cognisweep.local")),
        "body": body,
        "mentions": mentions,
        "created_at": now_stamp(),
    })
    row["comments"] = comments
    row["comments_json"] = json.dumps(comments, ensure_ascii=False)


def current_editor_identity() -> str:
    user = current_user() or {}
    return safe_text(user.get("email") or user.get("name") or "local_reviewer@cognisweep.local")


def render_row_lock_controls(row: Dict[str, Any], key_prefix: str) -> bool:
    owner = safe_text(row.get("locked_by"))
    locked_at = safe_text(row.get("locked_at"))
    current = current_editor_identity()
    changed = False
    if owner:
        st.caption(f"Locked by {owner}" + (f" at {format_local_time(locked_at)}" if locked_at else ""))
        label = "Release lock" if owner == current else "Take over lock"
        if st.button(label, key=f"{key_prefix}_unlock", use_container_width=True):
            if owner == current:
                row.pop("locked_by", None)
                row.pop("locked_at", None)
            else:
                row["locked_by"] = current
                row["locked_at"] = now_stamp()
            changed = True
    else:
        st.caption("No active row lock.")
        if st.button("Lock selected row", key=f"{key_prefix}_lock", use_container_width=True):
            row["locked_by"] = current
            row["locked_at"] = now_stamp()
            changed = True
    return changed


def install_editor_keyboard_shortcut_listener() -> None:
    components.html(
        """
        <script>
        (function() {
          const root = window.parent || window;
          const doc = root.document;
          const installKey = "__errorsweepShortcutDoneV4";
          if (root[installKey]) return;
          root[installKey] = true;

          function buttonByText(text) {
            const wanted = text.trim().toLowerCase();
            return Array.from(doc.querySelectorAll("button")).find((button) => {
              return (button.innerText || "").replace(/\\s+/g, " ").trim().toLowerCase() === wanted;
            });
          }

          function focusedRowCheckbox() {
            let active = doc.activeElement;
            if (!active || !["TEXTAREA", "INPUT"].includes(active.tagName)) return null;
            let row = active.closest('div[data-testid="stHorizontalBlock"]');
            while (row) {
              const checkbox = row.querySelector('div[data-testid="stCheckbox"] input[type="checkbox"]');
              if (checkbox) return checkbox;
              const parent = row.parentElement;
              row = parent ? parent.closest('div[data-testid="stHorizontalBlock"]') : null;
            }
            return null;
          }

          function approveFocusedSegment() {
            const checkbox = focusedRowCheckbox();
            if (checkbox && !checkbox.checked) {
              const label = checkbox.closest("label");
              (label || checkbox).click();
              return true;
            }
            const completeButton = buttonByText("Complete");
            if (completeButton) {
              completeButton.click();
              return true;
            }
            return false;
          }

          doc.addEventListener("keydown", function(e) {
            const key = (e.key || "").toLowerCase();
            if (e.ctrlKey && !e.shiftKey && !e.altKey && key === "s") {
              e.preventDefault();
              e.stopPropagation();
              const saveButton = buttonByText("Save file");
              if (saveButton) saveButton.click();
              return;
            }
            if (e.ctrlKey && !e.shiftKey && !e.altKey && e.key === "Enter") {
              e.preventDefault();
              e.stopPropagation();
              approveFocusedSegment();
              return;
            }
            if (e.altKey && !e.ctrlKey && !e.shiftKey && key === "n") {
              e.preventDefault();
              e.stopPropagation();
              const nextButton = buttonByText("Next pending");
              if (nextButton) nextButton.click();
              return;
            }
            if (e.altKey && !e.ctrlKey && !e.shiftKey && key === "p") {
              e.preventDefault();
              e.stopPropagation();
              const prevButton = buttonByText("Prev pending");
              if (prevButton) prevButton.click();
              return;
            }
            if (e.altKey && !e.ctrlKey && !e.shiftKey && key === "1") {
              e.preventDefault();
              e.stopPropagation();
              const suggestionButton = buttonByText("Use suggestion");
              if (suggestionButton) suggestionButton.click();
              return;
            }
            if (e.altKey && !e.ctrlKey && !e.shiftKey && key === "q") {
              e.preventDefault();
              e.stopPropagation();
              const qaButton = Array.from(doc.querySelectorAll("button")).find((button) => /^(E\\d+|W\\d+|OK|PII)$/i.test((button.innerText || "").trim()));
              if (qaButton) qaButton.click();
              return;
            }
            const combo = (e.ctrlKey ? "Ctrl+" : "") + (e.shiftKey ? "Shift+" : "") + (e.altKey ? "Alt+" : "") + e.key;
            if (["Alt+1", "Ctrl+Shift+T"].includes(combo)) {
              const note = doc.getElementById("errorsweep-shortcut-note");
              if (note) note.textContent = combo + " captured.";
            }
          }, true);
        })();
        </script>
        <div id="errorsweep-shortcut-note" style="display:none;">Shortcut listener active.</div>
        """,
        height=0,
    )


def render_keyboard_shortcuts_hint(key_prefix: str) -> None:
    shortcuts = [
        ("Ctrl+S", "Save file"),
        ("Ctrl+Enter", "Complete selected row"),
        ("Alt+N", "Next pending segment"),
        ("Alt+P", "Previous pending segment"),
        ("Alt+1", "Use top TM suggestion"),
        ("Alt+Q", "Open QA details"),
    ]
    html = "".join(
        f'<div class="es-cat-mini-row"><b>{escape(combo)}</b><br><span class="es-small">{escape(desc)}</span></div>'
        for combo, desc in shortcuts
    )
    st.markdown(html, unsafe_allow_html=True)
    install_editor_keyboard_shortcut_listener()


def render_contextual_copilot(source: str, target: str, matches: Dict[str, List[Dict[str, str]]], key_prefix: str) -> None:
    question = st.text_input("Ask copilot", placeholder="Ask about tone, date format, terminology, or why QA flagged this row", key=f"{key_prefix}_copilot_q")
    if st.button("Analyze row", key=f"{key_prefix}_copilot_btn", use_container_width=True):
        hints = []
        if matches.get("glossary"):
            hints.append("Glossary: " + "; ".join(f"{safe_text(g.get('source'))} -> {safe_text(g.get('target'))}" for g in matches["glossary"][:4]))
        if matches.get("dnt"):
            hints.append("DNT: " + ", ".join(safe_text(d.get("term")) for d in matches["dnt"][:6]))
        tokens = extract_protected_tokens(source)
        if tokens:
            hints.append("Protected tokens: " + ", ".join(tokens[:6]))
        if not safe_text(target):
            hints.append("Target is empty; route to MT/BYO AI or human translation.")
        elif len(safe_text(target)) < max(4, len(safe_text(source)) * 0.25):
            hints.append("Target is much shorter than source; check for dropped meaning.")
        if not hints:
            hints.append("No obvious deterministic issue found. Review style, locale, and client rules.")
        if question:
            hints.insert(0, f"Question: {question}")
        st.info("\n".join(f"- {hint}" for hint in hints))


def render_row_comments(row: Dict[str, Any], key_prefix: str) -> bool:
    comments = row_comments(row)
    if comments:
        for comment in comments[-5:]:
            mention_text = f" Mentions: {comment['mentions']}" if comment.get("mentions") else ""
            st.markdown(
                f'<div class="es-cat-mini-row"><b>{escape(comment["author"])}</b><br>{escape(comment["body"])}<br><span class="es-small">{escape(format_local_time(comment.get("created_at")))}{escape(mention_text)}</span></div>',
                unsafe_allow_html=True,
            )
    else:
        st.markdown('<div class="es-cat-assist-empty">No comments yet.</div>', unsafe_allow_html=True)
    new_comment = st.text_area("Add comment", height=74, placeholder="Ask @reviewer or add context for this segment", key=f"{key_prefix}_comment")
    if st.button("Add comment", key=f"{key_prefix}_add_comment", use_container_width=True, disabled=not safe_text(new_comment)):
        add_row_comment(row, new_comment)
        return True
    return False


def render_interactive_media_timeline(rows: List[Dict[str, Any]], current_idx: int = 0, key: str = "timeline") -> None:
    if not rows:
        return
    total = max(float(safe_text(row.get("end")) or 0) for row in rows)
    total = max(total, 1.0)
    blocks = []
    for idx, row in enumerate(rows[:160]):
        start = float(row.get("start") or 0)
        end = float(row.get("end") or start + 0.1)
        left = max(0, min(100, start / total * 100))
        width = max(1.2, min(100 - left, (end - start) / total * 100))
        active = idx == current_idx
        color = "#00d985" if active else "#38bdf8" if safe_text(row.get("status")) == "Approved" else "#8b5cf6"
        blocks.append(
            f'<div title="Segment {idx + 1}: {escape(format_time(start))} - {escape(format_time(end))}" '
            f'style="position:absolute;left:{left:.2f}%;width:{width:.2f}%;top:{18 + (idx % 4) * 18}px;height:12px;border-radius:8px;background:{color};box-shadow:0 0 18px rgba(56,189,248,.35);"></div>'
        )
    components.html(
        f"""
        <div style="height:108px;background:#080b14;border:1px solid rgba(148,163,184,.25);border-radius:12px;padding:10px;color:#dbeafe;font-family:Inter,Arial,sans-serif;">
          <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:8px;"><b>Timeline</b><span>{escape(format_time(total))}</span></div>
          <div style="position:relative;height:82px;background:linear-gradient(90deg,rgba(14,165,233,.08),rgba(139,92,246,.10));border-radius:10px;overflow:hidden;">{''.join(blocks)}</div>
        </div>
        """,
        height=126,
    )


def media_gap_label(value: Optional[float]) -> str:
    if value is None:
        return "-"
    if value < 0:
        return f"{abs(value):.1f}s overlap"
    return f"{value:.1f}s"


def clear_media_timing_widget_state(idx: int) -> None:
    for prefix in ["focus_start", "focus_end"]:
        st.session_state.pop(f"{prefix}_{idx}", None)


def render_media_timing_adjuster(rows: List[Dict[str, Any]], idx: int, key_prefix: str) -> None:
    if not rows or idx < 0 or idx >= len(rows):
        return

    stats = media_timing_summary(rows, idx)
    m1, m2, m3, m4 = st.columns(4)
    m1.metric("Duration", f"{stats['duration']:.1f}s")
    m2.metric("CPS", stats["cps"])
    m3.metric("Prev gap", media_gap_label(stats.get("previous_gap")))
    m4.metric("Next gap", media_gap_label(stats.get("next_gap")))

    step = st.number_input(
        "Timing step",
        min_value=0.1,
        max_value=10.0,
        value=0.5,
        step=0.1,
        format="%.1f",
        key=f"{key_prefix}_step",
    )
    duration_target = st.number_input(
        "Set duration",
        min_value=0.1,
        max_value=600.0,
        value=max(0.1, float(stats["duration"])),
        step=0.1,
        format="%.1f",
        key=f"{key_prefix}_duration",
    )

    def apply_timing_action(action: str, amount: float = 0.0) -> None:
        updated = adjust_media_segment_timing(rows, idx, action, amount)
        rows[:] = updated
        st.session_state.subtitle_segments = updated
        clear_media_timing_widget_state(idx)
        st.rerun()

    move_a, move_b, start_a, start_b, end_a, end_b = st.columns(6)
    if move_a.button("Move -", key=f"{key_prefix}_move_back", use_container_width=True):
        apply_timing_action("move", -float(step))
    if move_b.button("Move +", key=f"{key_prefix}_move_forward", use_container_width=True):
        apply_timing_action("move", float(step))
    if start_a.button("Start -", key=f"{key_prefix}_start_back", use_container_width=True):
        apply_timing_action("trim_start", -float(step))
    if start_b.button("Start +", key=f"{key_prefix}_start_forward", use_container_width=True):
        apply_timing_action("trim_start", float(step))
    if end_a.button("End -", key=f"{key_prefix}_end_back", use_container_width=True):
        apply_timing_action("trim_end", -float(step))
    if end_b.button("End +", key=f"{key_prefix}_end_forward", use_container_width=True):
        apply_timing_action("trim_end", float(step))

    snap_a, snap_b, duration_col = st.columns(3)
    if snap_a.button("Snap prev", key=f"{key_prefix}_snap_prev", use_container_width=True, disabled=idx == 0):
        apply_timing_action("snap_start_previous")
    if snap_b.button("Snap next", key=f"{key_prefix}_snap_next", use_container_width=True, disabled=idx >= len(rows) - 1):
        apply_timing_action("snap_end_next")
    if duration_col.button("Apply duration", key=f"{key_prefix}_apply_duration", use_container_width=True):
        apply_timing_action("set_duration", float(duration_target))


def openai_client() -> Optional[OpenAI]:
    key = secret("OPENAI_API_KEY")
    if not key:
        return None
    return OpenAI(api_key=key)


def current_ai_route_label() -> str:
    """Small safe label for UI. Do not expose provider names, URLs, or tokens."""
    if st.session_state.get("byo_openai_api_key"):
        provider = safe_text(st.session_state.get("byo_ai_provider", "Custom API"))
        model = safe_text(st.session_state.get("byo_openai_model", ""))
        return f"BYO {provider} active" + (f" ({model})" if model else "")
    return "Manual Human Review - add a user AI API key for draft translations"


def user_ai_api_key_available() -> bool:
    return bool(str(st.session_state.get("byo_openai_api_key", "") or "").strip())


def manual_review_mode_active() -> bool:
    """No AI/MT draft route is active; prepare blank rows for human translation."""
    return not user_ai_api_key_available()


def render_no_ai_key_editor_notice(workflow_label: str = "this workflow") -> None:
    st.info(
        f"No AI API key is active for {workflow_label}, so CogniSweep will not generate AI translations. "
        "The editor will still open for manual translation/post-editing, and connected TM, glossary, and DNT resources remain available."
    )


def log_ai_usage_event(usage: Dict[str, Any], purpose: str, segment_count: int = 0) -> None:
    """Log AI/translation usage in session and, when configured, Supabase.

    Persists BYO/platform AI events for owner reporting.
    """
    st.session_state.setdefault("ai_usage_events", [])
    user = current_user() or {}
    record = {
        "time": now_stamp() if "now_stamp" in globals() else datetime.now().strftime("%Y-%m-%d %H:%M"),
        "user_email": user.get("email", ""),
        "workspace": user.get("workspace", "Demo Workspace"),
        "purpose": purpose,
        "provider": usage.get("provider", usage.get("engine", "unknown")),
        "model": usage.get("model", usage.get("engine", "")),
        "managed": usage.get("managed", False),
        "billable": usage.get("billable", False),
        "usage_kind": usage.get("usage_kind", "ai_route"),
        "input_tokens": usage.get("input_tokens", 0),
        "output_tokens": usage.get("output_tokens", 0),
        "total_tokens": usage.get("total_tokens", 0),
        "characters": usage.get("characters", 0),
        "requests": usage.get("requests", 0),
        "success": usage.get("success", False),
        "error": usage.get("error", ""),
        "segments": segment_count,
    }
    st.session_state.ai_usage_events.insert(0, record)
    trim_session_list("ai_usage_events")

    if log_persistent_usage_event is not None:
        try:
            log_persistent_usage_event(
                record,
                purpose=purpose,
                segment_count=segment_count,
                user=user,
                metadata={
                    "app_version": APP_VERSION,
                    "billable": record.get("billable", False),
                    "usage_kind": record.get("usage_kind", "ai_route"),
                },
            )
        except Exception as exc:
            LOGGER.error("Unable to persist usage event: %s", exc)


def repair_localization_translation(source: str, translation: str) -> str:
    """Restore non-translatable localization tokens after MT/AI output.

    MT engines may alter protection markers by case (PH000Token) or drop visual
    prefixes. This final pass is source-driven and conservative: it only restores
    placeholders, tags, URLs/emails, emoji/icon prefixes, and wrapper brackets.
    """
    source = safe_text(source)
    out = safe_text(translation)
    if not source:
        return out

    out = re.sub(r"^\s*[ÂÃ]\s+", "", out).strip()

    protected = LOCALIZATION_PROTECTED_RE.findall(source)
    for idx, token in enumerate(protected):
        marker_re = re.compile(
            rf"(?i)[_\s]*(?:P\s*H\s*{idx:03d}\s*T\s*O\s*K\s*E\s*N|E\s*S\s*P\s*H\s*{idx}|Z\s*X\s*P\s*H\s*{idx}\s*Z\s*X|ZXPH\s*{idx}\s*ZX)[_\s]*"
        )
        out = marker_re.sub(token, out)
        if token and token not in out:
            out = f"{out.rstrip()} {token}".strip()

    prefix_match = LOCALIZATION_VISUAL_PREFIX_RE.match(source)
    if prefix_match:
        prefix = prefix_match.group(1)
        if prefix.strip() and not out.startswith(prefix.strip()):
            out = prefix + out.lstrip()

    for symbol in LOCALIZATION_EMOJI_RE.findall(source):
        if symbol and symbol not in out:
            out = f"{symbol} {out}".strip()

    src = source.strip()
    stripped = out.strip()
    if src.startswith("[") and src.endswith("]") and stripped and not (stripped.startswith("[") and stripped.endswith("]")):
        out = f"[{stripped.strip('[] ')}]"

    return out.strip()


def repair_translation_batch(sources: List[str], translations: List[str]) -> List[str]:
    repaired = []
    for idx, source in enumerate(sources):
        translation = translations[idx] if idx < len(translations) else ""
        repaired.append(repair_localization_translation(source, translation))
    return repaired


def call_main_api_translate(texts: List[str], target_language: str, domain: str, rules: Optional[Dict[str, Any]] = None) -> List[str]:
    """Translate through the v30 two-phase backend.

    User has BYO key:
        Use the selected OpenAI-compatible provider/base URL/model from Account.

    User has no key:
        Return blank Human Review rows for manual translation.
    """
    if not texts:
        return []
    if not feature_flag("main_api_translation"):
        st.warning("Translation routing is disabled by Platform Settings. Rows were sent to Human Review without MT.")
        return ["" for _ in texts]

    user_key = str(st.session_state.get("byo_openai_api_key", "") or "").strip()
    rules_text = rules_summary_for_ai(rules)

    # ----------------------------------------------------------
    # BYO KEY PATH - user can provide OpenAI or any OpenAI-compatible API route.
    # ----------------------------------------------------------
    if user_key:
        if ai_json_items is None or select_ai_route is None:
            st.error("BYO-key AI router file is missing. Add managed_ai_router.py beside app.py.")
            return ["" for _ in texts]

        try:
            route = select_ai_route(user_openai_key=user_key, purpose="translate")
        except Exception as exc:
            st.error(f"User AI route is not configured: {exc}")
            return ["" for _ in texts]

        system_prompt = f"""
You are CogniSweep AI, a professional localization translator.
Return JSON only. Do not use markdown.

Task:
Translate source strings into {target_language} for a {domain} localization project.

Hard rules:
1. Preserve placeholders exactly: {{{{email}}}}, {{{{password}}}}, %s, %d, <tags>, URLs, emails.
2. Preserve numbers, units, emoji/icons, bullets, and product names.
3. Obey uploaded rules ZIP and saved Memory & Rules. Preserve DNT/client locked terms if they appear.
4. Square bracket UI labels may be localized inside brackets, but keep the bracket structure.
5. Do not leave translations blank.
6. Return a JSON object with key "items".

Client rules:
{rules_text or "No uploaded or saved client rules were provided."}

Output shape:
{{
  "items": [
    {{"index": 0, "translation": "translated text"}}
  ]
}}
"""
        payload = {
            "target_language": target_language,
            "domain": domain,
            "rules_summary": rules_text,
            "texts": [{"index": i, "source": text} for i, text in enumerate(texts)],
        }

        items, usage = ai_json_items(
            system_prompt=system_prompt,
            user_prompt=json.dumps(payload, ensure_ascii=False),
            route=route,
            temperature=0.0,
            max_tokens=4500,
        )
        log_ai_usage_event(usage, "translate", len(texts))

        result = [""] * len(texts)
        for item in items:
            try:
                idx = int(item.get("index", 0))
            except Exception as exc:
                LOGGER.debug("Skipping malformed translation item index: %s", exc)
                continue
            if 0 <= idx < len(result):
                result[idx] = safe_text(item.get("translation", ""))

        if not any(result) and usage.get("error"):
            st.error(f"Translation service error: {usage.get('error')}")
        return repair_translation_batch(texts, result)

    # ----------------------------------------------------------
    # NO USER KEY PATH: prepare manual Human Review rows.
    # ----------------------------------------------------------
    return ["" for _ in texts]



def generate_transcription_rows_from_video(video_file, locale: str = "en-US", prompt: str = "") -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    """Generate transcript rows from uploaded video/audio.

    v32 policy:
    - Auto transcription is available only when the user provides a BYO OpenAI-compatible API key.
    - Translation providers are not used for transcription.
    - If no user API key is available, return blank starter rows for manual human editing.
    """
    if video_file is None:
        return default_subtitle_segments(10, transcription=True), {"success": False, "error": "No video uploaded."}

    user_key = str(st.session_state.get("byo_openai_api_key", "") or "").strip()
    if not user_key:
        return default_subtitle_segments(10, transcription=True), {
            "success": False,
            "provider": "manual_transcription",
            "engine": "manual_editor",
            "error": "No user API key available. Blank rows were created for manual transcription.",
        }

    if transcribe_media_file_to_rows is None:
        return default_subtitle_segments(10, transcription=True), {"success": False, "error": "speech_transcription.py is missing."}

    media_record = save_media_preview_file(f"transcribe_{uuid.uuid4().hex}", video_file)
    media_path = safe_text(media_record.get("media_preview_path"))
    if not media_path:
        return default_subtitle_segments(10, transcription=True), {
            "success": False,
            "provider": "manual_transcription",
            "engine": "manual_editor",
            "error": "Unable to save media file for transcription.",
        }

    rows, usage = transcribe_media_file_to_rows(
        media_path=media_path,
        filename=getattr(video_file, "name", "video.mp4"),
        mime_type=getattr(video_file, "type", "video/mp4") or "video/mp4",
        user_openai_key=user_key,
        locale=locale,
        prompt=prompt,
    )
    st.session_state.setdefault("ai_usage_events", [])
    user = current_user() or {}
    st.session_state.ai_usage_events.insert(0, {
        "time": now_stamp(),
        "user_email": user.get("email", ""),
        "workspace": user.get("workspace", "Demo Workspace"),
        "purpose": "transcription",
        "provider": usage.get("provider", "user_speech"),
        "model": usage.get("engine", "speech"),
        "managed": False,
        "billable": False,
        "usage_kind": "ai_route",
        "input_tokens": 0,
        "output_tokens": 0,
        "total_tokens": 0,
        "characters": sum(len(safe_text(row.get("source", ""))) for row in rows),
        "success": usage.get("success", False),
        "error": usage.get("error", ""),
        "segments": len(rows),
    })
    trim_session_list("ai_usage_events")
    return rows, usage


def translate_subtitle_sources(rows: List[Dict[str, Any]], target_language: str, domain: str = "Subtitling", rules: Optional[Dict[str, Any]] = None) -> Tuple[List[Dict[str, Any]], int]:
    """Translate source rows into target subtitle rows when a user AI key is active."""
    source_texts = [safe_text(r.get("source", "")) for r in rows]
    translations = call_main_api_translate(source_texts, target_language, domain, rules=rules)
    missing = 0
    for row, trans in zip(rows, translations):
        row["target"] = safe_text(trans)
        if row["target"]:
            row["status"] = "MT"
            row["match"] = "MT"
        else:
            row["status"] = "Needs Review"
            row["match"] = "Untranslated"
            missing += 1
    return rows, missing

def call_main_api_qa(rows: List[Dict[str, Any]], domain: str, strictness: str = "Standard", rules: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    """Optional Managed AI QA route. Deterministic checks still run first elsewhere."""
    if not rows:
        return []
    if ai_json_items is None or select_ai_route is None:
        return []
    try:
        route = select_ai_route(
            user_openai_key=st.session_state.get("byo_openai_api_key", ""),
            purpose="qa",
        )
    except Exception as exc:
        LOGGER.warning("Unable to select QA AI route: %s", exc)
        return []

    rules_text = rules_summary_for_ai(rules)
    system_prompt = f"""
You are CogniSweep AI, a conservative localization QA reviewer.
Return JSON only. Do not invent errors.
Flag only real issues supported by source/target evidence.
DNT/placeholder/number damage is severe. Empty target is Critical.
Apply uploaded rules ZIP and saved Memory & Rules when judging glossary, DNT, style, and client instructions.

Client rules:
{rules_text or "No uploaded or saved client rules were provided."}

Output shape:
{{"items":[{{"id":1,"issue":"short issue","severity":"Minor|Major|Critical","suggestion":"fix","reason":"why"}}]}}
"""
    payload = {
        "domain": domain,
        "strictness": strictness,
        "rules_summary": rules_text,
        "segments": [
            {"id": r.get("id"), "source": r.get("source", ""), "target": r.get("target", "")}
            for r in rows[:80]
        ],
    }
    items, usage = ai_json_items(
        system_prompt=system_prompt,
        user_prompt=json.dumps(payload, ensure_ascii=False),
        route=route,
        temperature=0.0,
        max_tokens=3000,
    )
    log_ai_usage_event(usage, "qa", len(rows[:80]))
    return items

def auto_detect_domain(text_sample: str) -> str:
    t = text_sample.lower()
    if any(x in t for x in ["button", "dashboard", "settings", "login", "password", "screen", "menu", "tooltip"]):
        return "Software UI"
    if any(x in t for x in ["subtitle", "-->", "caption", "dialogue", "scene"]):
        return "Subtitling"
    if any(x in t for x in ["invoice", "payment", "bank", "account", "revenue"]):
        return "Finance"
    if any(x in t for x in ["agreement", "clause", "contract", "legal"]):
        return "Legal"
    if any(x in t for x in ["course", "lesson", "quiz", "module"]):
        return "E-learning"
    if any(x in t for x in ["campaign", "brand", "copy", "ad", "landing page"]):
        return "Marketing"
    return "General"


def detect_sensitive_text(text: str) -> List[str]:
    value = safe_text(text)
    if not value:
        return []
    hits = []
    if re.search(r"[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}", value):
        hits.append("email")
    if re.search(r"\b(?:\+?\d[\d .()-]{7,}\d)\b", value):
        hits.append("phone/number")
    if re.search(r"\b(?:api[_-]?key|secret|token|password|passwd|pwd)\b\s*[:=]", value, re.I):
        hits.append("credential-like text")
    if not hits and SENSITIVE_TEXT_RE.search(value):
        hits.append("sensitive pattern")
    return hits


def sensitive_rows_summary(rows: List[Dict[str, Any]], limit: int = 8) -> Dict[str, Any]:
    matches = []
    for idx, row in enumerate(rows or []):
        joined = " ".join([safe_text(row.get("source", "")), safe_text(row.get("target", ""))])
        kinds = detect_sensitive_text(joined)
        if kinds:
            matches.append({"row": idx + 1, "kinds": sorted(set(kinds))})
        if len(matches) >= limit:
            break
    return {"count": len(matches), "matches": matches}


def render_privacy_route_notice(context: str = "translation") -> None:
    if st.session_state.get("byo_openai_api_key"):
        st.warning(f"{context}: BYO external AI key is active. Confirm client approval before sending confidential or NDA text.")
    else:
        st.info(f"{context}: no user AI key is active, so CogniSweep will prepare manual Human Review rows.")


def run_global_qa_for_row(row: Dict[str, Any], target_language: str, domain: str, rules: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    if deterministic_checks_v2 is None:
        return []
    segment = {
        "id": row.get("id", ""),
        "location": row.get("location", f"Segment {row.get('id', '')}"),
        "source": row.get("source", ""),
        "translation": row.get("target", row.get("translation", "")),
        "mode": domain,
    }
    try:
        return deterministic_checks_v2(
            segment,
            rules=rules or {},
            target_language=target_language,
            domain=domain,
            enable_language_tool=False,
            language_tool_mode="local",
        )
    except Exception as exc:
        LOGGER.warning("Global QA failed for row %s: %s", row.get("id", ""), exc)
        return []


def summarize_qa_findings(findings: List[Dict[str, Any]]) -> str:
    if not findings:
        return ""
    labels = [qa_finding_label(finding) for finding in findings[:4]]
    return ", ".join(label for label in labels if label)


def qa_finding_label(finding: Any) -> str:
    if isinstance(finding, dict):
        severity = safe_text(finding.get("Severity") or finding.get("severity") or "Review").title()
        kind = safe_text(
            finding.get("Error Type")
            or finding.get("error_type")
            or finding.get("Check")
            or finding.get("Issue")
            or finding.get("issue")
            or "QA"
        )
        return f"{severity}: {kind}"
    return safe_text(finding)


def readable_qa_findings(value: Any) -> str:
    if not value:
        return ""
    if isinstance(value, list):
        return ", ".join(label for label in (qa_finding_label(item) for item in value[:6]) if label)
    if isinstance(value, dict):
        return qa_finding_label(value)
    return safe_text(value)


def rows_for_display(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    display_rows: List[Dict[str, Any]] = []
    for row in rows or []:
        item = dict(row)
        if "qa_findings" in item:
            item["qa_findings"] = readable_qa_findings(item.get("qa_findings"))
        if "qa_summary" in item:
            item["qa_summary"] = readable_qa_findings(item.get("qa_summary")) or safe_text(item.get("qa_summary"))
        if "issues" in item:
            item["issues"] = readable_qa_findings(item.get("issues")) or safe_text(item.get("issues"))
        display_rows.append(item)
    return display_rows


def qa_severity_rank(severity: str) -> int:
    order = {"Critical": 4, "Major": 3, "Minor": 2, "Review": 1, "Info": 0, "Pass": -1}
    return order.get(safe_text(severity).title(), 1)


def qa_overall_status(findings: List[Dict[str, Any]]) -> str:
    if not findings:
        return "Pass"
    max_rank = max(qa_severity_rank(f.get("Severity", "Review")) for f in findings)
    if max_rank >= 4:
        return "Critical"
    if max_rank >= 3:
        return "Major"
    return "Needs Review"


def dedupe_qa_findings(findings: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    unique: List[Dict[str, Any]] = []
    seen = set()
    for finding in findings or []:
        key = (
            safe_text(finding.get("Location") or finding.get("Segment ID")),
            safe_text(finding.get("Rule ID")),
            safe_text(finding.get("Error Type")),
            safe_text(finding.get("Wrong Part") or finding.get("Explanation")),
        )
        if key in seen:
            continue
        seen.add(key)
        unique.append(finding)
    return unique


def delivery_quality_findings(
    rows: List[Dict[str, Any]],
    target_language: str,
    domain: str,
    rules: Optional[Dict[str, Any]] = None,
) -> List[Dict[str, Any]]:
    """Pre-delivery gate for objective localization integrity checks.

    This deliberately duplicates a few core checks outside the AI path so that
    exports still catch placeholders, emoji, DNT, and ZWNJ issues when no API key
    is configured.
    """
    all_findings: List[Dict[str, Any]] = []
    rules = rules or workspace_rules()
    dnt_terms = [safe_text(item.get("term")) for item in rules.get("dnt", []) if safe_text(item.get("term"))]
    zwnj = "\u200c"

    for idx, original in enumerate(rows or [], start=1):
        row = dict(original or {})
        row.setdefault("id", idx)
        row.setdefault("location", f"Segment {idx}")
        row["target"] = safe_text(row.get("target", row.get("translation", "")))
        row["source"] = safe_text(row.get("source", ""))
        row_findings: List[Dict[str, Any]] = []

        if not row["target"].strip():
            row_findings.append(qa_manual_finding(row, "Major", "Completeness", "Target translation is blank.", "Add the missing translation."))

        protected = LOCALIZATION_PROTECTED_RE.findall(row["source"])
        for token in protected:
            if token and token not in row["target"]:
                row_findings.append(qa_manual_finding(row, "Major", "Protected Token", f"Missing protected token {token}", f"Keep {token} unchanged in the target."))

        for symbol in LOCALIZATION_EMOJI_RE.findall(row["source"]):
            if symbol and symbol not in row["target"]:
                row_findings.append(qa_manual_finding(row, "Major", "Formatting", f"Missing source emoji/icon {symbol}", "Keep source emoji/icon characters unless client rules say to remove them."))

        for term in dnt_terms:
            if term and term.lower() in row["source"].lower() and term not in row["target"]:
                row_findings.append(qa_manual_finding(row, "Major", "DNT", f"DNT term changed or missing: {term}", f"Keep {term} unchanged."))

        source_zwnj = row["source"].count(zwnj)
        target_zwnj = row["target"].count(zwnj)
        if source_zwnj and target_zwnj < source_zwnj:
            row_findings.append(qa_manual_finding(row, "Major", "ZWNJ", "Zero Width Non-Joiner is missing from target.", "Preserve ZWNJ characters where the source requires them."))
        if target_zwnj and re.search(rf"(^|[\s\.,;:!?]){zwnj}|{zwnj}($|[\s\.,;:!?])", row["target"]):
            row_findings.append(qa_manual_finding(row, "Major", "ZWNJ", "Zero Width Non-Joiner is placed next to whitespace, punctuation, or a boundary.", "Keep ZWNJ only between characters that must not join."))

        row_findings.extend(run_global_qa_for_row(row, target_language=target_language, domain=domain, rules=rules))
        for finding in row_findings:
            finding.setdefault("Location", row.get("location", f"Segment {idx}"))
            finding.setdefault("Segment ID", row.get("id", idx))
        all_findings.extend(row_findings)

    return dedupe_qa_findings(all_findings)


def delivery_gate_summary(rows: List[Dict[str, Any]], findings: List[Dict[str, Any]]) -> Dict[str, Any]:
    status_by_location: Dict[str, List[Dict[str, Any]]] = {}
    for finding in findings or []:
        location = safe_text(finding.get("Location") or finding.get("Segment ID"))
        if location:
            status_by_location.setdefault(location, []).append(finding)
    gate_rows = []
    for idx, row in enumerate(rows or [], start=1):
        location = safe_text(row.get("location") or f"Segment {row.get('id', idx)}")
        row_findings = status_by_location.get(location, [])
        gate_rows.append({
            **row,
            "id": row.get("id", idx),
            "status": qa_overall_status(row_findings),
            "issues": summarize_qa_findings(row_findings),
            "match": row.get("match", ""),
        })
    _, _, summary = professional_qa_rows(gate_rows, findings)
    blocking = [f for f in findings if qa_severity_rank(f.get("Severity", "Review")) >= 3]
    summary["blocking_findings"] = len(blocking)
    summary["ready"] = summary["result"] == "PASS" and not blocking
    return summary


def render_delivery_gate(
    rows: List[Dict[str, Any]],
    findings: List[Dict[str, Any]],
    title: str = "Delivery readiness",
    render: bool = True,
) -> Dict[str, Any]:
    summary = delivery_gate_summary(rows, findings)
    if not render:
        return summary
    st.markdown(f"### {title}")
    metrics([
        ("Gate", "PASS" if summary["ready"] else "FAIL", f"{summary['qa_score']}%"),
        ("Blocking", summary["blocking_findings"], "Critical/Major"),
        ("Findings", summary["total_findings"], "total"),
        ("Threshold", "95%", "minimum pass"),
    ])
    if summary["ready"]:
        st.success("Delivery gate passed. Objective localization checks did not find blocking issues.")
    else:
        st.error("Delivery gate failed. Fix Critical/Major issues or keep the file in Human Review before delivery.")
        preview = [f for f in findings if qa_severity_rank(f.get("Severity", "Review")) >= 3][:12]
        if preview:
            cols = ["Location", "Source Text", "Translation", "Error Type", "Severity", "Wrong Part", "Suggestion", "Rule ID"]
            st.dataframe(pd.DataFrame(preview)[[c for c in cols if c in pd.DataFrame(preview).columns]], use_container_width=True, hide_index=True)
    return summary


def qa_manual_finding(row: Dict[str, Any], severity: str, category: str, issue: str, suggestion: str = "") -> Dict[str, Any]:
    return {
        "Sheet": "",
        "Location": safe_text(row.get("location") or f"Segment {row.get('id', '')}"),
        "Mode": "Manual QA",
        "Source Text": safe_text(row.get("source", "")),
        "Translation": safe_text(row.get("target", row.get("translation", ""))),
        "Error Type": category,
        "Severity": severity,
        "Wrong Part": issue,
        "Suggestion": suggestion,
        "Explanation": issue,
        "Check Source": "CogniSweep QA",
        "Rule Source": "Built-in QA",
        "Confidence": "High",
        "Rule ID": f"manual.{re.sub(r'[^a-z0-9]+', '_', category.lower()).strip('_')}",
        "Autofix Possible": "No",
        "Priority": 90 if severity == "Critical" else 70 if severity == "Major" else 50,
    }


def professional_qa_rows(segment_rows: List[Dict[str, Any]], detailed_findings: List[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, Any]]:
    finding_rows: List[Dict[str, Any]] = []
    severity_counts = {"Critical": 0, "Major": 0, "Minor": 0, "Review": 0}
    for idx, finding in enumerate(detailed_findings, start=1):
        severity = safe_text(finding.get("Severity") or "Review").title()
        if severity not in severity_counts:
            severity = "Review"
        severity_counts[severity] += 1
        finding_rows.append({
            "Finding ID": idx,
            "Segment ID": safe_text(finding.get("Segment ID") or finding.get("Location") or ""),
            "Source Text": safe_text(finding.get("Source Text") or ""),
            "Target Text": safe_text(finding.get("Translation") or ""),
            "Suggested Target": safe_text(finding.get("Suggestion") or ""),
            "Error Category": safe_text(finding.get("Error Type") or "QA"),
            "Severity": severity,
            "Issue": safe_text(finding.get("Wrong Part") or finding.get("Explanation") or ""),
            "Explanation": safe_text(finding.get("Explanation") or ""),
            "Check": safe_text(finding.get("Rule Source") or finding.get("Check Source") or "Rule Engine"),
            "Confidence": safe_text(finding.get("Confidence") or ""),
            "Rule ID": safe_text(finding.get("Rule ID") or ""),
        })

    segment_overview = []
    failed_segments = 0
    for row in segment_rows:
        status = safe_text(row.get("status", "Pass"))
        if status != "Pass":
            failed_segments += 1
        segment_overview.append({
            "Segment ID": row.get("id", ""),
            "Status": status,
            "Source Text": row.get("source", ""),
            "Target Text": row.get("target", ""),
            "Issue Summary": row.get("issues", ""),
            "Match": row.get("match", ""),
        })

    total_segments = len(segment_rows)
    pass_segments = max(0, total_segments - failed_segments)
    qa_score = round((pass_segments / total_segments) * 100, 2) if total_segments else 100.0
    summary = {
        "total_segments": total_segments,
        "pass_segments": pass_segments,
        "review_segments": failed_segments,
        "total_findings": len(finding_rows),
        "qa_score": qa_score,
        "result": "PASS" if qa_score >= 95 and severity_counts["Critical"] == 0 else "FAIL",
        "severity_counts": severity_counts,
    }
    return finding_rows, segment_overview, summary


def create_qa_excel_report(segment_rows: List[Dict[str, Any]], detailed_findings: List[Dict[str, Any]]) -> bytes:
    finding_rows, segment_overview, summary = professional_qa_rows(segment_rows, detailed_findings)
    wb = Workbook()
    ws_summary = wb.active
    ws_summary.title = "Summary"
    ws_findings = wb.create_sheet("QA Findings")
    ws_segments = wb.create_sheet("Segment Overview")
    ws_instructions = wb.create_sheet("Review Notes")

    dark = "1F2937"
    blue = "D9EAF7"
    green = "D9EAD3"
    yellow = "FFF2CC"
    red = "F4CCCC"
    orange = "FCE4D6"
    border = Side(style="thin", color="A6A6A6")

    ws_summary.merge_cells("A1:D1")
    ws_summary["A1"] = "CogniSweep QA Report"
    ws_summary["A1"].font = Font(bold=True, size=16, color="FFFFFF")
    ws_summary["A1"].fill = PatternFill("solid", fgColor=dark)
    ws_summary["A1"].alignment = Alignment(horizontal="center")
    summary_rows = [
        ("Generated", format_local_time(now_stamp())),
        ("Result", summary["result"]),
        ("QA Score", summary["qa_score"]),
        ("Total Segments", summary["total_segments"]),
        ("Passed Segments", summary["pass_segments"]),
        ("Segments Needing Review", summary["review_segments"]),
        ("Total Findings", summary["total_findings"]),
        ("Critical", summary["severity_counts"]["Critical"]),
        ("Major", summary["severity_counts"]["Major"]),
        ("Minor", summary["severity_counts"]["Minor"]),
        ("Review", summary["severity_counts"]["Review"]),
    ]
    for idx, (label, value) in enumerate(summary_rows, start=3):
        ws_summary.cell(idx, 1, label)
        ws_summary.cell(idx, 2, value)
        ws_summary.cell(idx, 1).font = Font(bold=True)
        ws_summary.cell(idx, 1).fill = PatternFill("solid", fgColor=blue)
        if label == "Result":
            ws_summary.cell(idx, 2).fill = PatternFill("solid", fgColor=green if value == "PASS" else red)
            ws_summary.cell(idx, 2).font = Font(bold=True)
    ws_summary["D3"] = "Pass rule"
    ws_summary["E3"] = "PASS requires QA score >= 95 and zero Critical findings."
    ws_summary["D3"].font = Font(bold=True)
    ws_summary["D3"].fill = PatternFill("solid", fgColor=blue)
    apply_widths(ws_summary, {"A": 28, "B": 20, "D": 18, "E": 62})

    finding_headers = [
        "Finding ID", "Segment ID", "Source Text", "Target Text", "Suggested Target",
        "Error Category", "Severity", "Issue", "Explanation", "Check", "Confidence", "Rule ID",
    ]
    for col_idx, header in enumerate(finding_headers, start=1):
        cell = ws_findings.cell(1, col_idx, header)
        cell.font = Font(bold=True)
        cell.fill = PatternFill("solid", fgColor=blue)
    for row_idx, row in enumerate(finding_rows, start=2):
        for col_idx, header in enumerate(finding_headers, start=1):
            cell = ws_findings.cell(row_idx, col_idx, row.get(header, ""))
            if header == "Severity":
                color = red if row.get(header) == "Critical" else orange if row.get(header) == "Major" else yellow if row.get(header) == "Minor" else blue
                cell.fill = PatternFill("solid", fgColor=color)
                cell.font = Font(bold=True)
    apply_widths(ws_findings, {"A": 12, "B": 18, "C": 48, "D": 48, "E": 42, "F": 20, "G": 14, "H": 34, "I": 42, "J": 18, "K": 16, "L": 24})
    ws_findings.freeze_panes = "A2"

    segment_headers = ["Segment ID", "Status", "Source Text", "Target Text", "Issue Summary", "Match"]
    for col_idx, header in enumerate(segment_headers, start=1):
        cell = ws_segments.cell(1, col_idx, header)
        cell.font = Font(bold=True)
        cell.fill = PatternFill("solid", fgColor=blue)
    for row_idx, row in enumerate(segment_overview, start=2):
        for col_idx, header in enumerate(segment_headers, start=1):
            cell = ws_segments.cell(row_idx, col_idx, row.get(header, ""))
            if header == "Status":
                cell.fill = PatternFill("solid", fgColor=green if row.get(header) == "Pass" else yellow)
    apply_widths(ws_segments, {"A": 12, "B": 18, "C": 52, "D": 52, "E": 46, "F": 16})
    ws_segments.freeze_panes = "A2"

    notes = [
        ("Purpose", "Use this workbook as the client-facing QA handoff. The Findings sheet contains one issue per row."),
        ("Severity", "Critical and Major issues should be reviewed first. Minor issues are lower-risk language or formatting corrections."),
        ("Status", "Segment Overview shows all uploaded segments, including clean pass rows."),
        ("Threshold", "PASS requires QA score >= 95 and zero Critical findings."),
    ]
    ws_instructions["A1"] = "Review Notes"
    ws_instructions["A1"].font = Font(bold=True, size=14)
    for idx, (label, text) in enumerate(notes, start=3):
        ws_instructions.cell(idx, 1, label)
        ws_instructions.cell(idx, 2, text)
        ws_instructions.cell(idx, 1).font = Font(bold=True)
        ws_instructions.cell(idx, 1).fill = PatternFill("solid", fgColor=blue)
    apply_widths(ws_instructions, {"A": 18, "B": 90})

    for sheet in wb.worksheets:
        style_sheet_base(sheet)
        for row in sheet.iter_rows():
            for cell in row:
                cell.border = Border(left=border, right=border, top=border, bottom=border)
                cell.alignment = Alignment(vertical="top", wrap_text=True)

    bio = io.BytesIO()
    wb.save(bio)
    bio.seek(0)
    return bio.getvalue()


def validate_timing_rows(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    issues = []
    previous_end = None
    for idx, row in enumerate(rows or []):
        start = float(row.get("start", 0) or 0)
        end = float(row.get("end", 0) or 0)
        if end <= start:
            issues.append({"row": idx + 1, "issue": "End time must be after start time."})
        if previous_end is not None and start < previous_end:
            issues.append({"row": idx + 1, "issue": "Segment overlaps the previous segment."})
        previous_end = max(previous_end or 0, end)
    return issues


